window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c20-exam"] = window.COURSE_LANG["c20-exam"] || {};
window.COURSE_LANG["c20-exam"]["es"] = [
  {"id":1,"q":"Un aire acondicionado proporciona 36,000 BTU/h de enfriamiento y consume 3,000 watts. ¿Cuál es su EER?","opts":["6.0","12.0","9.0","18.0"],"re":"EER = capacidad de enfriamiento (BTU/h) ÷ potencia de entrada (watts) = 36,000 ÷ 3,000 = 12.0. El EER califica la eficiencia en estado estable a una condición fija (95°F exterior)."},
  {"id":2,"q":"Una tonelada de refrigeración equivale a cuántos BTU/h?","opts":["15,000","6,000","10,000","12,000"],"re":"Una tonelada de refrigeración = 12,000 BTU/h — el calor necesario para derretir una tonelada de hielo en 24 horas (288,000 BTU ÷ 24 h)."},
  {"id":3,"q":"Una regla general común para el flujo de aire de enfriamiento residencial es aproximadamente cuántos CFM por tonelada?","opts":["200 CFM","400 CFM","100 CFM","800 CFM"],"re":"Alrededor de 400 CFM por tonelada (rango 350–450) es el flujo de aire de diseño residencial estándar — más bajo (~350) para climas húmedos, más alto (~450) para climas secos."},
  {"id":4,"q":"¿Qué fórmula calcula el calor sensible de una corriente de aire?","opts":["Qs = 500 × GPM × ΔT","Qs = 1.08 × CFM × ΔT","Qs = 4.5 × CFM × Δh","Qs = 0.68 × CFM × Δgrains"],"re":"Calor sensible: Qs = 1.08 × CFM × ΔT(°F). El factor 1.08 combina la densidad del aire y el calor específico en condiciones estándar. 0.68 = latente (granos), 4.5 = total (entalpía), 500 = agua."},
  {"id":5,"q":"El calor total (sensible + latente) de una corriente de aire se obtiene usando cuál factor?","opts":["4.5","0.68","1.08","60"],"re":"Calor total Qt = 4.5 × CFM × Δh (entalpía, BTU/lb). 1.08 = sensible, 0.68 = latente (granos de humedad)."},
  {"id":6,"q":"¿Para qué se usa el Manual J de ACCA?","opts":["Carga comercial","Selección del modelo de equipo","Dimensionamiento de ductos","Carga residencial de calefacción y enfriamiento"],"re":"El Manual J = Cálculo de Carga Residencial — determina la carga de calefacción/enfriamiento del edificio (BTU/h). Manual D = diseño de ductos, Manual S = selección de equipo, Manual N = carga comercial."},
  {"id":7,"q":"¿Qué manual de ACCA cubre el diseño del sistema de ductos residencial?","opts":["Manual D","Manual S","Manual P","Manual J"],"re":"Manual D = Sistemas de Ductos Residenciales. Dimensiona los ductos usando la presión estática disponible y la tasa de fricción resultante."},
  {"id":8,"q":"Después de calcular la carga, ¿qué manual de ACCA guía la selección correcta del equipo?","opts":["Manual S","Manual D","Manual J","Manual N"],"re":"Manual S = Selección de Equipo Residencial — ajusta la capacidad del equipo a la carga del Manual J para que el sistema no quede sobredimensionado."},
  {"id":9,"q":"¿En qué se diferencia el SEER del EER?","opts":["El SEER mide el flujo de aire","El SEER se aplica solo a bombas de calor","El SEER se mide solo a plena carga","El SEER es un promedio estacional sobre un rango de condiciones"],"re":"El SEER (Seasonal Energy Efficiency Ratio) promedia la eficiencia a lo largo de una temporada de enfriamiento y temperaturas exteriores variables; el EER es una calificación única en estado estable a 95°F. El SEER es más alto que el EER para la misma unidad."},
  {"id":10,"q":"El coeficiente de rendimiento (COP) de una bomba de calor se define como:","opts":["BTU ÷ tonelada","Calor de salida ÷ trabajo de entrada","CFM ÷ watts","Trabajo de entrada ÷ calor de salida"],"re":"COP = calor útil de salida ÷ energía de entrada (mismas unidades). Un COP de 3 significa 3 unidades de calor por unidad de electricidad. COP ≈ EER ÷ 3.412."},
  {"id":11,"q":"En una carta psicrométrica, la humedad en el aire en relación con el máximo que puede contener a esa temperatura se llama:","opts":["Temperatura de bulbo húmedo","Entalpía","Punto de rocío","Humedad relativa"],"re":"Humedad relativa (HR) = humedad real ÷ máximo que el aire puede contener a esa temperatura de bulbo seco, como porcentaje."},
  {"id":12,"q":"La temperatura a la cual el vapor de agua en el aire comienza a condensarse es el:","opts":["Temperatura de bulbo seco","Temperatura de bulbo húmedo","Temperatura de diseño","Punto de rocío"],"re":"El punto de rocío es donde el aire se satura (100% HR) y la humedad se condensa. Las superficies del serpentín por debajo del punto de rocío producen condensado (deshumidificación)."},
  {"id":13,"q":"Un psicrómetro de honda se usa para medir:","opts":["Presión del refrigerante","Velocidad del flujo de aire","Temperaturas de bulbo húmedo y bulbo seco","Presión estática"],"re":"Un psicrómetro de honda lee el bulbo seco y el bulbo húmedo; la depresión del bulbo húmedo da la HR y el punto de rocío en la carta psicrométrica."},
  {"id":14,"q":"Las condiciones de diseño exterior para los cálculos de carga normalmente se basan en:","opts":["Un valor de 110°F obligatorio por código","El día más caluroso registrado","La temperatura promedio anual","Los valores de diseño del 1% y 99% de ASHRAE/ACCA"],"re":"El Manual J usa condiciones de diseño estadísticas de ASHRAE (p. ej., 1% verano, 99% invierno) para que el equipo se dimensione para extremos típicos, no extremos récord — evitando el sobredimensionamiento."},
  {"id":15,"q":"Un manejador de aire residencial normalmente está clasificado para una presión estática externa total (TESP) de aproximadamente:","opts":["5.0 in. w.c.","0.5 in. w.c.","0.05 in. w.c.","15 in. w.c."],"re":"La mayoría de los manejadores de aire/calefactores residenciales están clasificados cerca de 0.5 in. w.c. de TESP. Una presión estática medida por encima de esto indica ductos restrictivos, un filtro sucio o retornos subdimensionados."},
  {"id":16,"q":"En el método de diseño de ductos de fricción igual, la tasa de fricción se expresa en:","opts":["BTU por hora","CFM por tonelada","Pulgadas de columna de agua por 100 ft","Grados por pie"],"re":"La tasa de fricción se expresa en pulgadas de columna de agua por 100 ft de ducto. El Manual D la deriva de la presión estática disponible y la longitud efectiva total."},
  {"id":17,"q":"La velocidad del aire recomendada en los troncales de suministro principales residenciales es generalmente:","opts":["700–900 fpm","2,000–2,500 fpm","100–300 fpm","4,000+ fpm"],"re":"Los troncales de suministro residenciales funcionan aproximadamente entre 700–900 fpm (las ramas más bajas) para limitar el ruido y la fricción; los sistemas comerciales usan velocidades más altas."},
  {"id":18,"q":"Para estimar el tonelaje nominal a partir del flujo de aire de diseño, se divide el CFM entre aproximadamente:","opts":["400","12,000","200","100"],"re":"A ~400 CFM/tonelada, el tonelaje ≈ CFM ÷ 400 (p. ej., 1,600 CFM ÷ 400 ≈ 4 toneladas). Esto se basa en el flujo de aire; la capacidad real proviene de una carga del Manual J."},
  {"id":19,"q":"La carga de enfriamiento de verano en un edificio se ve más afectada por:","opts":["El color de la pintura del calefactor","Solo la longitud del ducto","Solo el área del piso","Ventanas/ganancia solar, aislamiento e infiltración"],"re":"La carga de enfriamiento es impulsada por la ganancia solar a través de los vidrios, la conducción a través de paredes/techo/aislamiento, la infiltración y las ganancias internas (personas, electrodomésticos) — todo en el Manual J."},
  {"id":20,"q":"La infiltración de aire en un edificio comúnmente se expresa como:","opts":["Cambios de aire por hora (ACH)","BTU por tonelada","Micrones","Presión estática"],"re":"La infiltración/ventilación a menudo se da en ACH (cambios de aire por hora) o CFM. Las casas más herméticas tienen menor ACH y una menor carga de infiltración."},
  {"id":21,"q":"Una rejilla de aire de retorno subdimensionada probablemente causará:","opts":["Menor consumo de amperios","Aumento del SEER","Baja presión de descarga","Alta presión estática y reducción del flujo de aire"],"re":"Los retornos subdimensionados elevan la presión estática, ahogan el soplador, reducen el flujo de aire (CFM) y pueden congelar el serpentín y aumentar el uso de energía."},
  {"id":22,"q":"Un aire acondicionado nominal de 4 toneladas tiene una capacidad de enfriamiento clasificada de:","opts":["24,000 BTU/h","36,000 BTU/h","60,000 BTU/h","48,000 BTU/h"],"re":"4 toneladas × 12,000 BTU/h = 48,000 BTU/h de capacidad de enfriamiento nominal."},
  {"id":23,"q":"Un presupuesto de trabajo completo debe incluir material, mano de obra, gastos generales y:","opts":["Ganancia (margen)","Solo el impuesto sobre las ventas","Solo refrigerante","La factura de servicios públicos del cliente"],"re":"Un presupuesto completo cubre material, mano de obra, equipo, gastos generales, permisos y un margen de ganancia. Omitir los gastos generales/ganancia conduce a pérdidas."},
  {"id":24,"q":"El sobredimensionamiento de un aire acondicionado más comúnmente resulta en:","opts":["Mayor SEER","Ciclos cortos y mal control de humedad","Menor costo de instalación","Mejor deshumidificación"],"re":"Una unidad sobredimensionada hace ciclos cortos: alcanza el punto de ajuste antes de remover suficiente humedad, dejando el espacio frío y húmedo. El dimensionamiento según Manual J/S evita esto."},
  {"id":25,"q":"En una carta psicrométrica, las líneas de entalpía constante corren casi paralelas a las líneas de:","opts":["Temperatura de bulbo seco constante","Humedad relativa constante","Punto de rocío constante","Temperatura de bulbo húmedo constante"],"re":"Las líneas de entalpía constante siguen de cerca las líneas de bulbo húmedo constante, razón por la cual el bulbo húmedo es un buen índice del contenido total de calor."},
  {"id":26,"q":"Unir tubería de cobre para refrigerante en un sistema de alta presión normalmente se hace mediante:","opts":["Solo accesorios de compresión","Soldadura blanda por debajo de 840°F","Soldadura fuerte por encima de 840°F","Pegamento"],"re":"Las uniones de refrigerante se sueldan con soldadura fuerte con material de aporte que funde por encima de 840°F (a menudo ~1,150°F) para resistir bajo alta presión. La soldadura blanda (<840°F) es demasiado débil para las líneas de refrigerante."},
  {"id":27,"q":"¿Por qué se hace fluir nitrógeno seco a través de la tubería al hacer soldadura fuerte en las líneas de refrigerante?","opts":["Para agregar carga","Para detectar fugas","Para prevenir la oxidación/escamas internas","Para enfriar la unión"],"re":"Hacer fluir nitrógeno purga el oxígeno para que no se forme óxido de cobre (escama negra) dentro de la tubería. La escama puede obstruir los dispositivos de medición y contaminar el sistema."},
  {"id":28,"q":"Un vacío profundo en un sistema de refrigerante normalmente se logra hasta aproximadamente:","opts":["0 psig","500 micrones","28 in. Hg","5 psig"],"re":"El objetivo es ~500 micrones (y que el sistema lo mantenga) para remover la humedad y los no condensables. Un medidor de micrones — no un manómetro compuesto — confirma el nivel."},
  {"id":29,"q":"La humedad que queda en un sistema de refrigerante puede combinarse con el refrigerante y el aceite para formar:","opts":["Ácidos y lodos","Solo vapor de agua puro","Nitrógeno","Capacidad adicional"],"re":"La humedad reacciona con el refrigerante y el aceite para formar ácidos que corroen los componentes y dañan el compresor — por eso son importantes la evacuación y un filtro deshidratador."},
  {"id":30,"q":"En un sistema dividido, la línea de refrigerante de mayor diámetro y aislada es la:","opts":["Línea de líquido","Bypass de gas caliente","Línea de succión (vapor)","Línea de drenaje"],"re":"La línea de succión transporta vapor frío de baja presión al compresor; es más grande y está aislada para prevenir la ganancia de calor y el sudor. La línea de líquido es más pequeña y sin aislamiento."},
  {"id":31,"q":"Un drenaje de condensado de un serpentín de enfriamiento debe incluir un:","opts":["Sifón en P (P-trap)","Válvula de alivio","Válvula de retención","Interruptor de presión"],"re":"Un sifón en P (P-trap) impide que la presión del soplador succione aire hacia adentro o lo empuje hacia afuera a través del drenaje, permite que el condensado fluya y bloquea olores/derivación de aire."},
  {"id":32,"q":"La pendiente mínima para una línea de drenaje de condensado horizontal es generalmente:","opts":["Cuesta arriba","1 in. por pie","No se necesita pendiente","1/8 in. por pie"],"re":"Al menos 1/8 in. por pie (alrededor del 1%) hacia el drenaje para que el condensado fluya por gravedad y no se acumule, lo que causa desbordamiento y crecimiento microbiano."},
  {"id":33,"q":"El desconectador eléctrico para una unidad condensadora exterior debe ubicarse:","opts":["En cualquier lugar conveniente","A la vista de la unidad","En el ático","Solo en el medidor"],"re":"El NEC requiere un medio de desconexión a la vista y de fácil acceso para el equipo, de modo que un técnico pueda bloquearlo antes de dar servicio."},
  {"id":34,"q":"En la placa de datos de una unidad condensadora, MOCP se refiere a la:","opts":["Capacidad de aceite del motor","Protección máxima contra sobrecorriente (interruptor/fusible)","Ampacidad mínima del circuito","Presión máxima de operación"],"re":"MOCP = Protección Máxima contra Sobrecorriente — el interruptor/fusible más grande permitido. La MCA (Ampacidad Mínima del Circuito) establece el tamaño mínimo del cable. Ambos deben respetarse."},
  {"id":35,"q":"Una válvula de expansión termostática (TXV) controla el flujo de refrigerante para mantener constante:","opts":["La presión de descarga","El subenfriamiento","La temperatura del condensador","El sobrecalentamiento del evaporador"],"re":"Una TXV modula para mantener un sobrecalentamiento del evaporador relativamente constante a través de las cargas, alimentando el serpentín eficientemente. Un orificio fijo no se ajusta."},
  {"id":36,"q":"Un filtro deshidratador normalmente se instala en la:","opts":["Línea de drenaje de condensado","Línea de succión cerca del compresor","Línea de descarga","Línea de líquido antes del dispositivo de medición"],"re":"El filtro deshidratador de la línea de líquido remueve la humedad y los desechos y protege el dispositivo de medición. La flecha en el deshidratador debe apuntar en la dirección del flujo."},
  {"id":37,"q":"Un sistema con una TXV se carga con mayor precisión usando el:","opts":["Estimación del peso de la caja","Método de sobrecalentamiento","Método de subenfriamiento","Solo la vista"],"re":"Los sistemas con TXV se cargan por subenfriamiento (línea de líquido), ya que la TXV ya controla el sobrecalentamiento. Los sistemas de orificio fijo (pistón) usan el método de sobrecalentamiento."},
  {"id":38,"q":"El sobrecalentamiento es el número de grados que un vapor de refrigerante se calienta:","opts":["Por encima de su temperatura de saturación (ebullición)","Por debajo del punto de rocío","Por encima del ambiente","Por debajo de su temperatura de condensación"],"re":"Sobrecalentamiento = temperatura del vapor − temperatura de saturación a esa presión. Confirma que todo el líquido se ha evaporado antes del compresor, protegiéndolo del golpe de líquido."},
  {"id":39,"q":"El subenfriamiento es el número de grados que el refrigerante líquido se enfría:","opts":["Por encima del ambiente","Por encima de su temperatura de saturación","Por debajo de su temperatura de condensación (saturación)","Por debajo de la temperatura del evaporador"],"re":"Subenfriamiento = temperatura de saturación − temperatura del líquido en el condensador/línea de líquido. Un subenfriamiento adecuado asegura que líquido sólido alimente el dispositivo de medición."},
  {"id":40,"q":"El instrumento correcto para verificar un vacío profundo es un:","opts":["Medidor de micrones (vacío)","Amperímetro de gancho","Manómetro","Manómetro compuesto"],"re":"Un medidor de micrones lee el rango de vacío profundo con precisión; un manómetro compuesto estándar no puede distinguir 1,000 de 25,000 micrones."},
  {"id":41,"q":"La presión de gas del múltiple (salida) típica para un calefactor de gas natural es de aproximadamente:","opts":["11 in. w.c.","1 psi","3.5 in. w.c.","25 in. w.c."],"re":"Los calefactores de gas natural funcionan a ~3.5 in. w.c. de presión del múltiple; el LP (propano) funciona a ~10–11 in. w.c. Siempre ajuste según la placa de clasificación con un manómetro."},
  {"id":42,"q":"Los calefactores que queman combustible instalados en un espacio confinado requieren:","opts":["Ningún aire especial","Aire adecuado de combustión y ventilación","Solo aire de retorno","Un filtro más grande"],"re":"Los artefactos de combustión necesitan suficiente aire de combustión/ventilación según el Código Mecánico; muy poco aire causa combustión incompleta, CO y retroceso de tiro."},
  {"id":43,"q":"Un calefactor estándar de eficiencia media que usa un ducto de ventilación Tipo B se clasifica como:","opts":["Categoría III","Categoría I","Categoría IV","Categoría II"],"re":"Los artefactos de Categoría I ventilan con tiro natural (no positivo, no condensante) hacia un ducto B. La Categoría IV (condensante, 90%+) usa ventilación sellada de PVC."},
  {"id":44,"q":"Según el Título 24 de California, los ductos recién instalados en espacios no acondicionados deben aislarse al menos a:","opts":["R-4","R-6 / R-8 (depende del clima)","R-2","Sin aislamiento"],"re":"El Título 24 normalmente requiere aislamiento de ductos de R-6 a R-8 según la zona climática, además del sellado/prueba de fugas de ductos en la mayoría de las alteraciones."},
  {"id":45,"q":"El material preferido para sellar permanentemente las uniones de ductos es:","opts":["Mástique (con malla en los espacios)","Pintura en aerosol","Solo sellador (caulk)","Cinta de ducto (gris) con respaldo de tela"],"re":"El mástique para ductos (con malla de fibra de vidrio en los espacios más grandes) da un sello duradero y aceptado por el código. La cinta de ducto de tela estándar se seca y falla; las cintas UL-181 se permiten donde estén certificadas."},
  {"id":46,"q":"El ducto flexible debe soportarse a intervalos que no excedan aproximadamente:","opts":["4 ft","1 ft","12 ft","No se necesita soporte"],"re":"El ducto flexible normalmente se soporta a intervalos de hasta ~4 ft con una flecha máxima cercana a 1/2 in. por pie de espaciamiento, usando correas anchas para evitar el pellizco y la restricción del flujo de aire."},
  {"id":47,"q":"Antes de abrir un sistema de refrigerante sellado para reparación, el técnico primero debe:","opts":["Cortar la línea para abrirla","Agregar refrigerante","Recuperar el refrigerante según EPA 608","Hacer funcionar el compresor"],"re":"La Sección 608 de la EPA requiere recuperar el refrigerante en equipo aprobado antes de abrir el sistema; ventilarlo a la atmósfera es ilegal."},
  {"id":48,"q":"Un diferencial de temperatura de enfriamiento normal (aire de retorno menos suministro) es de aproximadamente:","opts":["2–5°F","50°F+","14–22°F","30–40°F"],"re":"Un sistema correctamente cargado con el flujo de aire correcto muestra una caída de aproximadamente 14–22°F a través del evaporador. Fuera de este rango apunta a problemas de flujo de aire o de carga."},
  {"id":49,"q":"En un termostato típico de bajo voltaje, la terminal 'Y' controla el:","opts":["Solo el ventilador","Común","Calefacción","Contactor de enfriamiento (compresor)"],"re":"Y = llamada de enfriamiento (energiza el contactor del compresor). G = ventilador, W = calefacción, R = energía de 24V, C = común. El cableado correcto es esencial."},
  {"id":50,"q":"Una unidad condensadora debe colocarse sobre una base nivelada principalmente para:","opts":["Aumentar el SEER","Mejorar la apariencia","Asegurar el retorno y drenaje correcto del aceite del compresor","Reducir el tamaño del cable"],"re":"Una unidad nivelada asegura el retorno correcto del aceite al compresor y el drenaje adecuado del agua; una base desnivelada causa migración del aceite y falla prematura del compresor."},
  {"id":51,"q":"Al hacer soldadura fuerte con plata cerca de una válvula de servicio, el técnico debe:","opts":["Omitir el nitrógeno","Soldar con la válvula completamente abierta y sin protección","Proteger/enfriar la válvula y mantener el nitrógeno fluyendo","Solo hacer pump down"],"re":"Las válvulas sensibles al calor deben protegerse (trapo húmedo/disipador de calor) con nitrógeno fluyendo para prevenir daños en los sellos y oxidación interna."},
  {"id":52,"q":"El aislamiento de la línea de succión se instala para:","opts":["Solo reducir el ruido","Prevenir la ganancia de calor y el sudor en la línea fría","Aumentar la presión de descarga","Solo bloquear la luz solar"],"re":"Aislar la línea de succión fría previene la ganancia de calor (pérdida de eficiencia) y la condensación que gotea y causa daños."},
  {"id":53,"q":"Para ducto de lámina metálica, un número de calibre más bajo significa que el metal es:","opts":["Siempre galvanizado","El mismo espesor","Más grueso","Más delgado"],"re":"Calibre más bajo = lámina metálica más gruesa. Los ductos más grandes necesitan metal más pesado (calibre más bajo) y refuerzo según SMACNA."},
  {"id":54,"q":"Durante el arranque, verificar el flujo de aire correcto antes de revisar la carga es importante porque:","opts":["Ahorra refrigerante","La carga no importa","Las lecturas del refrigerante solo son válidas con el flujo de aire correcto","El flujo de aire no tiene efecto"],"re":"Las presiones, el sobrecalentamiento y el subenfriamiento solo tienen sentido con el flujo de aire adecuado. Confirme primero el flujo de aire/diferencial de temperatura, luego evalúe y ajuste la carga."},
  {"id":55,"q":"Un serpentín del evaporador congelado es causado más comúnmente por:","opts":["Bajo flujo de aire o baja carga de refrigerante","Solo alta presión de descarga","Un filtro demasiado limpio","Ductos sobredimensionados"],"re":"El flujo de aire restringido (filtro/serpentín sucio, problema del soplador) o la carga baja hacen que la temperatura del serpentín caiga por debajo del punto de congelación, congelándolo. Diagnostique primero el flujo de aire, luego la carga."},
  {"id":56,"q":"Una carga baja de refrigerante típicamente produce:","opts":["Alta presión de descarga","Alta succión y bajo sobrecalentamiento","Baja presión de succión y alto sobrecalentamiento","Alto subenfriamiento"],"re":"La carga insuficiente ahoga el evaporador: baja succión, alto sobrecalentamiento, bajo subenfriamiento. Confirme, agregue carga por peso correctamente y encuentre la fuga."},
  {"id":57,"q":"Un sistema sobrecargado muestra más a menudo:","opts":["Bajo subenfriamiento","Baja presión de descarga","Alta presión de descarga y alto subenfriamiento","Alto sobrecalentamiento"],"re":"La sobrecarga acumula líquido en el condensador: alta presión de descarga y alto subenfriamiento, bajo sobrecalentamiento. Recupere refrigerante para corregir la carga."},
  {"id":58,"q":"Un serpentín del condensador exterior sucio o bloqueado causará:","opts":["Alta presión de descarga","Baja presión de descarga","Bajo consumo de amperios","Un condensador congelado"],"re":"El mal rechazo de calor del condensador eleva la presión de descarga y los amperios del compresor, reduce la capacidad y puede dispararse por alta presión. Limpie el serpentín."},
  {"id":59,"q":"Un capacitor de marcha fallado (abierto) en un compresor monofásico típicamente causará que:","opts":["No se vea afectado","Tenga un SEER más alto","Funcione más rápido","Zumbe, consuma altos amperios y no arranque"],"re":"Un capacitor de marcha/arranque fallado impide el torque de arranque: el motor zumba, consume amperios de rotor bloqueado y puede dispararse. Pruebe los microfaradios contra la clasificación."},
  {"id":60,"q":"Un contactor en un condensador de aire acondicionado funciona para:","opts":["Drenar el condensado","Conmutar el voltaje de línea al compresor y al ventilador","Medir el refrigerante","Filtrar el aire"],"re":"El contactor es un interruptor operado eléctricamente que se cierra ante una llamada de 24V para enviar voltaje de línea al compresor y al ventilador del condensador. Los contactos picados causan fallas."},
  {"id":61,"q":"En una bomba de calor, una válvula reversora atascada causará:","opts":["Mayor eficiencia","Operación correcta","Condensado congelado","Falla para cambiar entre calefacción y enfriamiento, o derivación de presión"],"re":"Una válvula reversora (de 4 vías) atascada atrapa un modo o deriva los lados de alta/baja (las presiones se igualan). Revise el solenoide y el diferencial de temperatura a través de los puertos de la válvula."},
  {"id":62,"q":"El propósito del ciclo de descongelamiento de una bomba de calor es:","opts":["Enfriar la casa","Derretir la escarcha del serpentín exterior en modo de calefacción","Cargar el sistema","Limpiar el filtro"],"re":"En calefacción, el serpentín exterior acumula escarcha; el descongelamiento invierte brevemente el ciclo (y puede energizar el calor auxiliar) para derretir el hielo, luego regresa a calefacción."},
  {"id":63,"q":"Una gran caída de temperatura a través de un filtro deshidratador de la línea de líquido usualmente indica:","opts":["Sobrecarga","Operación normal","Bajo flujo de aire","Una restricción (deshidratador obstruido)"],"re":"Una caída de temperatura/sudor notable a través del deshidratador indica una restricción. Un deshidratador/dispositivo de medición restringido ahoga el evaporador (baja succión, alto sobrecalentamiento)."},
  {"id":64,"q":"Los gases no condensables (aire) en un sistema de refrigerante causan:","opts":["Baja presión de descarga","Más subenfriamiento","Bajo sobrecalentamiento","Presión de descarga anormalmente alta"],"re":"El aire/no condensables elevan la presión de descarga por encima del valor de saturación normal para la temperatura. Recupere, evacúe a un vacío profundo y recargue."},
  {"id":65,"q":"Un calefactor de gas que enciende pero se apaga después de unos segundos lo más probable tiene un defectuoso:","opts":["Sensor de llama/termopar que no detecta llama","Bomba de condensado","Filtro de aire","Rotor del soplador"],"re":"Si el sensor de llama/termopar no detecta la llama, el control cierra la válvula de gas como medida de seguridad. Limpie o reemplace el sensor y verifique la señal en microamperios y la conexión a tierra."},
  {"id":66,"q":"Un encendedor de superficie caliente (HSI) que está agrietado o abierto resultará en:","opts":["Sin encendido (sin calor)","Calefacción continua","Solo enfriamiento","Alta presión de descarga"],"re":"Un HSI agrietado/abierto no brillará, por lo que el encendido falla — sin calor. Revise la resistencia y busque grietas visibles; manipúlelo sin tocar el elemento."},
  {"id":67,"q":"Un interruptor de rollout o de límite alto de un calefactor que se dispara repetidamente indica:","opts":["Operación normal","Sobrecalentamiento por chimenea bloqueada o bajo flujo de aire","Un condensador sucio","Solo baja presión de gas"],"re":"Los disparos del límite/rollout indican sobrecalentamiento por flujo de aire restringido (filtro/serpentín/soplador sucio) o una chimenea bloqueada/problema del intercambiador de calor. Encuentre la causa raíz — no solo reinicie."},
  {"id":68,"q":"Si el inductor de un calefactor funciona pero el interruptor de presión no cierra, revise si hay:","opts":["Bajo refrigerante","Un evaporador sucio","Una chimenea/condensado bloqueado o una manguera agrietada hacia el interruptor","Ventanas abiertas"],"re":"El interruptor de presión verifica el tiro del inductor. La falla para cerrar a menudo es una ventilación/condensado bloqueado, una manguera de detección tapada o agrietada, o un inductor débil — verifique antes de reemplazar el interruptor."},
  {"id":69,"q":"¿Qué ventaja ofrece un motor de soplador ECM sobre un motor PSC estándar?","opts":["Velocidad variable y control de flujo de aire constante","Menor eficiencia","Sin electrónica","Mayor consumo de amperios"],"re":"Los motores ECM (conmutados electrónicamente) varían la velocidad para mantener el flujo de aire objetivo frente a la presión estática cambiante, mejorando el confort y la eficiencia en comparación con los motores PSC de velocidad fija."},
  {"id":70,"q":"El mejor primer paso para confirmar una sospecha de fuga de refrigerante es:","opts":["Agregar refrigerante y esperar","Usar un detector electrónico de fugas, burbujas o tinte UV","Reemplazar el compresor","Ignorarlo"],"re":"Localice la fuga con un detector electrónico, burbujas de jabón o tinte UV antes de reparar. La EPA requiere reparar fugas significativas en lugar de rellenar repetidamente."},
  {"id":71,"q":"Un amperaje del compresor medido muy por encima de la RLA clasificada indica:","opts":["Un problema como alta presión de descarga, bajo voltaje o un problema mecánico","Operación correcta","Un filtro de aire sobredimensionado","Carga ligera normal"],"re":"Los amperios por encima de la RLA (Rated Load Amps) apuntan a alta presión de descarga, un condensador restringido, bajo voltaje o un compresor en falla. Investigue antes de que se sobrecaliente."},
  {"id":72,"q":"Un sistema con alto sobrecalentamiento y baja presión de succión lo más probable tiene:","opts":["Una sobrecarga","Demasiado flujo de aire","Una carga insuficiente o una restricción","Un condensador sucio"],"re":"Alto sobrecalentamiento + baja succión = un evaporador ahogado, por carga insuficiente o una restricción en la línea de líquido/dispositivo de medición. Revise el subenfriamiento para distinguir entre los dos."},
  {"id":73,"q":"Un interruptor de flotador (de seguridad) de condensado está diseñado para:","opts":["Aumentar el flujo de aire","Apagar el sistema si la bandeja de drenaje se desborda","Aumentar la carga","Descongelar el serpentín"],"re":"Un interruptor de flotador interrumpe la llamada de enfriamiento cuando el condensado se acumula, previniendo daños por agua. Un flotador disparado apunta a un drenaje o sifón obstruido."},
  {"id":74,"q":"En clima frío, una bomba de calor depende del calor suplementario (auxiliar) porque:","opts":["La válvula reversora falla","Funciona en enfriamiento","La capacidad y el COP disminuyen a medida que baja la temperatura exterior","El compresor se detiene"],"re":"A medida que baja la temperatura exterior, la capacidad y el COP de una bomba de calor disminuyen, por lo que el calor auxiliar/de respaldo eléctrico o de gas la complementa para satisfacer la carga."},
  {"id":75,"q":"Un bajo flujo de aire interior durante el enfriamiento típicamente causará:","opts":["Ningún efecto en el serpentín","Alto subenfriamiento","Alta presión de succión","Baja presión de succión y posible congelamiento del serpentín"],"re":"El flujo de aire reducido disminuye la carga del evaporador, bajando la presión de succión y la temperatura del serpentín — llevando al congelamiento. Revise el filtro, el serpentín, la velocidad del soplador y los ductos."},
  {"id":76,"q":"El mantenimiento de rutina que más mejora la eficiencia del condensador es:","opts":["Quitar el filtro","Agregar refrigerante en cada visita","Aumentar la velocidad del ventilador","Limpiar el serpentín exterior y despejar los desechos"],"re":"Un serpentín del condensador limpio rechaza el calor adecuadamente, bajando la presión de descarga y el consumo de amperios. La limpieza del serpentín y el espacio libre alrededor de la unidad son elementos clave de mantenimiento."},
  {"id":77,"q":"El intervalo recomendado para inspeccionar/reemplazar un filtro de aire estándar de 1 pulgada es aproximadamente:","opts":["Cada 5 años","Nunca","Solo cuando se desintegra","Cada 1–3 meses"],"re":"Los filtros estándar de 1 pulgada se revisan mensualmente y se reemplazan cada 1–3 meses (antes con mascotas/polvo). Los filtros obstruidos restringen el flujo de aire y congelan los serpentines."},
  {"id":78,"q":"Un compresor con 'ciclos cortos' (encendido/apagado frecuente) puede ser causado por:","opts":["Flujo de aire adecuado","Un filtro limpio","Dimensionamiento correcto","Equipo sobredimensionado, carga baja o un problema de control/presión"],"re":"Los ciclos cortos provienen del sobredimensionamiento, problemas de carga, serpentines sucios que disparan los dispositivos de seguridad o controles defectuosos. Diagnostique la causa raíz para proteger el compresor."},
  {"id":79,"q":"Los procedimientos de bloqueo/etiquetado (LOTO) se requieren para:","opts":["Probar capacitores","Prevenir la energización accidental del equipo durante el servicio","Acelerar el trabajo","Mejorar la eficiencia"],"re":"El LOTO de Cal/OSHA (Título 8) requiere desenergizar y bloquear/etiquetar las fuentes de energía antes del servicio, de modo que el equipo no pueda arrancar inesperadamente y lesionar al trabajador."},
  {"id":80,"q":"Antes de trabajar dentro de un condensador desconectado, un técnico aún debe:","opts":["Agregar refrigerante","Hacer funcionar el ventilador","Asumir que es seguro","Descargar el capacitor y verificar voltaje cero"],"re":"Los capacitores almacenan una carga letal después de quitar la energía. Descárguelos de forma segura y verifique la ausencia de voltaje con un medidor antes de tocar las terminales."},
  {"id":81,"q":"La protección ocular apropiada al hacer soldadura fuerte es:","opts":["Gafas de soldadura fuerte con tinte","Sin protección","Solo lentes de sol","Una mascarilla contra polvo"],"re":"La soldadura fuerte produce luz y calor intensos; las gafas de soldadura fuerte con tinte (además de guantes y ventilación) protegen los ojos del resplandor y las chispas."},
  {"id":82,"q":"El refrigerante que se fuga en un espacio confinado y sin ventilación es peligroso principalmente porque puede:","opts":["Aumentar la humedad","Desplazar el oxígeno y causar asfixia","Aumentar la presión exterior","Mejorar la calidad del aire"],"re":"La mayoría de los refrigerantes son más pesados que el aire y pueden desplazar el oxígeno en espacios bajos/confinados, causando asfixia. Asegure la ventilación y siga la SDS."},
  {"id":83,"q":"Los refrigerantes A2L como el R-32 y el R-454B se clasifican como:","opts":["Ligeramente inflamables, menor toxicidad","No inflamables","Explosivos como el propano","Altamente tóxicos"],"re":"Los refrigerantes A2L son ligeramente inflamables (baja inflamabilidad) y de baja toxicidad. Siga las certificaciones del equipo, la detección/mitigación de fugas y no use llamas abiertas durante el servicio."},
  {"id":84,"q":"La forma correcta de confirmar que un circuito está desenergizado antes del servicio es:","opts":["Usar un medidor con clasificación adecuada (probar-conocido-probar)","Tocar los cables","Escuchar el zumbido","Preguntar a un compañero de trabajo"],"re":"Verifique voltaje cero con un medidor con clasificación adecuada usando el método de probar-conocido-vivo-probar. Nunca confíe solo en la etiqueta de un interruptor antes de contactar los conductores."},
  {"id":85,"q":"Las herramientas eléctricas portátiles usadas al aire libre o en áreas húmedas deben protegerse con un:","opts":["GFCI","Solo un transformador","Regleta supresora","Un fusible más grande"],"re":"Un GFCI (interruptor de circuito por falla a tierra) se dispara ante pequeñas corrientes de falla a tierra, previniendo la electrocución en condiciones húmedas/exteriores — requerido por Cal/OSHA y el NEC."},
  {"id":86,"q":"Una escalera recta (de extensión) debe colocarse con una relación base-a-altura de aproximadamente:","opts":["1:1","1:4","1:20","1:10"],"re":"La regla 4-a-1: coloque la base 1 ft hacia afuera por cada 4 ft de altura de trabajo. Use la clasificación de servicio adecuada y asegure/amarre la escalera."},
  {"id":87,"q":"Los cilindros de gas comprimido (refrigerante o nitrógeno) deben:","opts":["Asegurarse en posición vertical y mantenerse alejados de fuentes de calor","Acostarse de lado cerca del calor","Dejarse sin tapa al moverlos","Llenarse al 100%"],"re":"Los cilindros se aseguran en posición vertical con la tapa puesta al moverlos, se mantienen por debajo de ~125°F y nunca se sobrellenan (refrigerante ≤80%) para prevenir la ruptura."},
  {"id":88,"q":"Un cilindro de nitrógeno presurizado siempre debe usarse con un:","opts":["Soplete","Regulador de presión","Sin regulador","Bomba de vacío"],"re":"El nitrógeno se almacena a muy alta presión; un regulador lo reduce a una presión de trabajo segura. Nunca pruebe la presión de un sistema por encima de su presión de prueba clasificada."},
  {"id":89,"q":"Ventilar refrigerante CFC/HCFC/HFC a la atmósfera durante el servicio es:","opts":["Requerido","Solo ilegal en interiores","Permitido en pequeñas cantidades","Prohibido bajo la Clean Air Act (EPA 608)"],"re":"La Sección 608 de la EPA prohíbe ventilar refrigerantes a sabiendas. Los técnicos deben recuperar el refrigerante con equipo certificado y poseer la certificación EPA 608."},
  {"id":90,"q":"El monóxido de carbono (CO) de la combustión incompleta es peligroso porque es:","opts":["Inofensivo al aire libre","Visible y con olor","Incoloro, inodoro y tóxico","Más pesado que el refrigerante"],"re":"El CO es incoloro e inodoro y se une a la hemoglobina, causando intoxicación. El aire de combustión adecuado, la ventilación y un detector de CO son esenciales; investigue cualquier derrame."},
  {"id":91,"q":"Una Hoja de Datos de Seguridad (SDS) proporciona información sobre:","opts":["El SEER del equipo","El dimensionamiento de ductos","Los peligros, manejo y primeros auxilios de un químico","Los términos de la garantía"],"re":"Bajo HazCom, una SDS enumera los peligros de un producto, el manejo seguro, el PPE, los primeros auxilios y las medidas de emergencia. Debe estar accesible para los trabajadores en el trabajo."},
  {"id":92,"q":"El estándar de Prevención de Enfermedades por Calor de Cal/OSHA requiere que los empleadores proporcionen:","opts":["Solo pago de horas extra","Refrigerante adicional","Agua, sombra, descanso y capacitación","Nada al aire libre"],"re":"El estándar de Prevención de Enfermedades por Calor de Cal/OSHA (Título 8 §3395) requiere agua potable, sombra para descansar, pausas de descanso, capacitación y aclimatación para el trabajo al aire libre."},
  {"id":93,"q":"La clase correcta de extintor de incendios para un incendio eléctrico energizado es:","opts":["Clase A","Clase D","Clase C","Clase B"],"re":"Los extintores Clase C están clasificados para equipo eléctrico energizado (agente no conductor). Clase A = combustibles ordinarios, B = líquidos inflamables, D = metales."},
  {"id":94,"q":"Antes de perturbar un aislamiento sospechoso de tubería o ducto viejo que pueda contener asbesto, el técnico debe:","opts":["Aspirarlo con una aspiradora de taller","Quemarlo","Detenerse y hacer que personal calificado lo pruebe/maneje","Cortarlo libremente"],"re":"Perturbar el asbesto libera fibras peligrosas. Los materiales sospechosos deben probarse y manejarse según las regulaciones por personal capacitado/certificado — no por trabajadores sin capacitación."},
  {"id":95,"q":"Al entrar a un espacio confinado como un sótano de poca altura o un tanque, lo primero que se debe probar es:","opts":["El nivel de oxígeno y una atmósfera peligrosa/tóxica","La señal de Wi-Fi","El ruido","El color de la pintura"],"re":"Los espacios confinados requieren prueba atmosférica (oxígeno, inflamables, tóxicos) y un permiso/procedimiento antes de entrar, ya que la deficiencia de oxígeno o los gases tóxicos pueden ser fatales."},
  {"id":96,"q":"El PPE adecuado al manipular refrigerante líquido incluye:","opts":["Pantalones cortos","Zapatos abiertos en la punta","Sin guantes","Lentes de seguridad y guantes para prevenir congelación/lesión ocular"],"re":"El refrigerante líquido puede causar congelación y lesión ocular. Use lentes de seguridad y guantes y trabaje en un área ventilada según la SDS."},
  {"id":97,"q":"Las consideraciones de protección contra caídas bajo Cal/OSHA aplican al trabajar:","opts":["En alturas elevadas y bordes de techo según los umbrales de Cal/OSHA","Solo en escaleras","Solo por encima de 50 ft","Nunca en trabajos residenciales"],"re":"Cal/OSHA requiere protección contra caídas a alturas definidas (p. ej., bordes de techo, plataformas elevadas). Use barandillas, sistemas personales de detención de caídas u otros métodos aprobados según el Título 8."},
  {"id":98,"q":"Cortar o esmerilar materiales que producen polvo de sílice requiere:","opts":["Solo guantes","Más refrigerante","Controles de polvo y protección respiratoria","Sin precauciones"],"re":"La sílice cristalina respirable es un riesgo grave para la salud; Cal/OSHA requiere controles de agua/polvo y protección respiratoria al cortar concreto, mampostería, etc."},
  {"id":99,"q":"Al dar servicio a equipo en la azotea, el técnico debe estar más consciente de:","opts":["La clasificación SEER","La pintura","El tamaño del filtro","Los bordes del techo, tragaluces y peligros de caída/calor"],"re":"El trabajo en azoteas agrega peligros de caída (bordes, tragaluces), exposición al calor y peligros eléctricos/de refrigerante. Planifique el acceso, la protección contra caídas y las medidas contra enfermedades por calor."},
  {"id":100,"q":"La primera acción si el refrigerante líquido entra en contacto con la piel (congelación) es:","opts":["Aplicar calor directo","Ignorarlo","Frotar vigorosamente","Enjuagar con abundante agua tibia y buscar atención médica"],"re":"Para la congelación por refrigerante, enjuague con abundante agua tibia (no caliente), no frote, proteja el área y obtenga atención médica según la SDS."},
  {"id":101,"q":"En una carta psicrométrica, las líneas de temperatura de bulbo húmedo se utilizan principalmente para determinar:","opts":["La velocidad del aire","El contenido total de calor (entalpía)","El tamaño del ducto","La carga de refrigerante"],"re":"La temperatura de bulbo húmedo se relaciona directamente con la entalpía (calor total). Las líneas de bulbo húmedo constante corren casi paralelas a las líneas de entalpía en la carta psicrométrica."},
  {"id":102,"q":"La relación de calor sensible (SHR) de una carga de enfriamiento es la relación entre:","opts":["Calor total y sensible","Calor latente y total","Calor sensible y total","Flujo de aire y carga"],"re":"SHR = calor sensible ÷ calor total (sensible + latente). Un SHR más bajo significa que se requiere mayor remoción de humedad del equipo."},
  {"id":103,"q":"El Manual D de ACCA se utiliza para:","opts":["Calcular la carga térmica","Diseñar y dimensionar el sistema de ductos","Seleccionar el termostato","Dimensionar el equipo"],"re":"El Manual D es la norma de diseño de ductos residenciales: dimensiona los ductos según la presión estática disponible (tasa de fricción) y el flujo de aire requerido."},
  {"id":104,"q":"En el Manual D, la tasa de fricción se determina a partir de la presión estática disponible y de:","opts":["La pendiente del techo","La longitud equivalente total del tramo más largo","El número de rejillas","El tipo de refrigerante"],"re":"Tasa de fricción = (presión estática disponible × 100) ÷ longitud efectiva total del tramo de suministro y retorno más largo, incluyendo las longitudes equivalentes de los accesorios."},
  {"id":105,"q":"El Manual S de ACCA se utiliza para:","opts":["Diseñar la ventilación","Calcular la pérdida de calor","Seleccionar el equipo para que coincida con la carga del Manual J","Dimensionar los ductos"],"re":"El Manual S selecciona el equipo de modo que su capacidad sensible y latente (en condiciones de diseño) coincida con la carga del Manual J, limitando el sobredimensionamiento."},
  {"id":106,"q":"Según el Manual S, el equipo de enfriamiento generalmente no debe sobredimensionarse más allá de aproximadamente qué porcentaje de la carga de enfriamiento de diseño?","opts":["115% (15% por encima) para AC","200%","15% por encima","Sin límite"],"re":"El Manual S normalmente limita el dimensionamiento del AC a aproximadamente 115% de la carga sensible de diseño (y hasta ~125% para bombas de calor en algunos casos) para mantener la deshumidificación y la eficiencia."},
  {"id":107,"q":"Un objetivo común de flujo de aire de diseño residencial para un sistema de enfriamiento es de aproximadamente:","opts":["50 CFM por tonelada","400 CFM por tonelada","100 CFM por tonelada","1200 CFM por tonelada"],"re":"El flujo de aire de diseño estándar para enfriamiento de confort es de aproximadamente 400 CFM por tonelada (rango de 350–450 CFM/tonelada), ajustado según la humedad del clima."},
  {"id":108,"q":"En climas desérticos secos, el flujo de aire de diseño suele elevarse hacia 450 CFM/tonelada, mientras que en climas húmedos puede reducirse hacia 350 CFM/tonelada con el fin de:","opts":["Reducir el SEER","Aumentar el ruido","Reducir el calibre del cable","Equilibrar la remoción sensible y latente"],"re":"Un mayor flujo de aire aumenta la capacidad sensible (climas secos); un menor flujo de aire incrementa la remoción latente (humedad) necesaria en climas húmedos."},
  {"id":109,"q":"La 'diferencia de temperatura de diseño' en un cálculo de carga de calefacción es la diferencia entre:","opts":["Bulbo húmedo y seco","Dos habitaciones adyacentes","Aire de suministro y retorno","Temperatura interior de diseño y temperatura exterior de diseño"],"re":"ΔT de diseño de calefacción = temperatura interior de diseño menos la temperatura exterior de diseño de invierno al 99% para la localidad (de las tablas del Manual J / datos de ASHRAE)."},
  {"id":110,"q":"La carga de calor latente en un edificio proviene principalmente de:","opts":["La iluminación","Fuentes de humedad (personas, cocina, infiltración)","La luz solar a través de las ventanas","La conducción por las paredes"],"re":"La carga latente es humedad: ocupantes, cocina, duchas, plantas y aire de infiltración/ventilación húmedo. La radiación solar, la conducción y la iluminación son cargas sensibles."},
  {"id":111,"q":"Al leer una carta psicrométrica, la temperatura de punto de rocío se encuentra siguiendo una línea horizontal hacia la curva de saturación desde:","opts":["El eje de bulbo seco","La escala de entalpía","La razón de humedad (contenido de humedad)","La escala de CFM"],"re":"El punto de rocío corresponde a la razón de humedad: muévase horizontalmente (contenido de humedad constante) a la izquierda hasta la curva de saturación del 100% para leer la temperatura de punto de rocío."},
  {"id":112,"q":"Un ductulador es una herramienta que se usa para relacionar el tamaño del ducto, el flujo de aire, la pérdida por fricción y:","opts":["La velocidad del aire","El voltaje","La presión del refrigerante","La temperatura de la llama"],"re":"Un ductulador (regla de cálculo redonda/rectangular) relaciona el CFM, la tasa de fricción por cada 100 ft, la dimensión del ducto y la velocidad para el dimensionamiento de ductos."},
  {"id":113,"q":"La infiltración en un cálculo de carga se refiere a:","opts":["La fuga de aire no intencional a través de la envolvente del edificio","El aceite en el compresor","El agua en el ducto","La fuga de refrigerante"],"re":"La infiltración es aire exterior no controlado que se filtra por grietas, huecos y aberturas, agregando carga tanto sensible como latente."},
  {"id":114,"q":"El diseño del Manual J utiliza las temperaturas exteriores de diseño al 1% para enfriamiento y al 99% para calefacción, lo que significa que el equipo se dimensiona para:","opts":["Condiciones estacionales típicas cercanas a los extremos","Solo la temperatura interior","Los extremos récord absolutos","La temperatura promedio anual"],"re":"Los valores de 1%/99% se exceden solo ~1% del tiempo, por lo que dimensionar para los verdaderos extremos récord sobredimensionaría el sistema la mayor parte del año."},
  {"id":115,"q":"La ganancia/pérdida de calor del ducto en un ático no acondicionado se reduce principalmente mediante:","opts":["Mayor voltaje","Sellado y aislamiento de los ductos","Rejillas más grandes","Más refrigerante"],"re":"Sellar las fugas (con mástique) y aislar los ductos (por ejemplo, R-8) reduce las pérdidas por conducción y fuga a través de espacios no acondicionados calientes/fríos."},
  {"id":116,"q":"Para la ventilación residencial, la Norma 62.2 de ASHRAE especifica una cantidad mínima de:","opts":["Ventilación mecánica de aire fresco según el área de piso y los ocupantes","Aceite del compresor","Refrigerante por tonelada","Aislamiento de ductos"],"re":"ASHRAE 62.2 establece una tasa de ventilación mecánica para toda la vivienda a partir del área de piso y el número de dormitorios/ocupantes para garantizar la calidad del aire interior."},
  {"id":117,"q":"La clasificación de presión estática externa (ESP) de un ventilador representa la presión estática que puede vencer a través de:","opts":["El sistema de ductos, el serpentín y el filtro en conjunto","Las líneas de refrigerante","El compresor","Solo el filtro"],"re":"La ESP es la presión estática total contra la que el ventilador debe trabajar: ductos de suministro, ductos de retorno, serpentín, filtro y rejillas, al flujo de aire nominal."},
  {"id":118,"q":"Al estimar un trabajo, la diferencia entre costos 'directos' e 'indirectos' (overhead) es que los costos indirectos incluyen:","opts":["Costos no atados a un trabajo específico (oficina, seguros, camiones)","Solo el refrigerante","Materiales instalados en el trabajo","Solo las tarifas de permisos"],"re":"Los costos directos son específicos del trabajo (material, mano de obra en ese trabajo); los costos indirectos son gastos continuos del negocio repartidos entre todos los trabajos (renta, seguros, vehículos, administración)."},
  {"id":119,"q":"El calor suplementario (auxiliar) de una bomba de calor debe dimensionarse para cubrir:","opts":["La carga de calefacción no cubierta por la bomba de calor por debajo del punto de equilibrio","Solo la pérdida del ducto","La carga de enfriamiento","Solo la carga latente"],"re":"Por debajo del punto de equilibrio, la bomba de calor no puede satisfacer toda la carga de calefacción, por lo que el calor auxiliar (a menudo resistencias eléctricas) cubre el déficit hasta la temperatura de diseño."},
  {"id":120,"q":"El 'punto de equilibrio' de una bomba de calor es la temperatura exterior a la cual:","opts":["La salida de la bomba de calor iguala exactamente la pérdida de calor del edificio","Comienza el descongelamiento","Falla el compresor","El SEER es más alto"],"re":"En el punto de equilibrio, la capacidad decreciente de la bomba de calor iguala la pérdida de calor creciente del edificio; por debajo de él, se necesita calor suplementario."},
  {"id":121,"q":"Para convertir el calor sensible removido en el CFM requerido, la fórmula estándar utiliza la constante 1.08 con:","opts":["El voltaje","El ΔT y el CFM","Solo el bulbo húmedo","El subenfriamiento del refrigerante"],"re":"Calor sensible (BTU/h) = 1.08 × CFM × ΔT (diferencia de temperatura de bulbo seco) en condiciones de aire estándar."},
  {"id":122,"q":"En un cálculo de carga, las ventanas orientadas al norte generalmente aportan ___ ganancia de calor solar que las ventanas orientadas al oeste.","opts":["Menos","No existe ganancia por ventana","Más","Idéntica"],"re":"El vidrio orientado al oeste recibe el intenso sol de la tarde en ángulo bajo (hora pico de enfriamiento), por lo que gana mucho más calor solar que el vidrio orientado al norte."},
  {"id":123,"q":"Un 'conteo manual' (takeoff) durante la estimación se refiere a:","opts":["Bombear el refrigerante","Retirar el equipo antiguo","Cerrar el gas","Contar/enumerar todos los materiales y cantidades a partir de los planos"],"re":"Un conteo (takeoff) consiste en detallar cada accesorio, longitud de ducto/tubería, rejilla y unidad de los planos para elaborar una lista de materiales y una propuesta precisas."},
  {"id":124,"q":"Al seleccionar un horno (furnace), la capacidad de salida (no la de entrada) debe igualarse a la carga de calefacción porque la salida refleja:","opts":["El SEER","El calor realmente entregado después de la eficiencia de combustión (AFUE)","El tamaño de la línea de gas","El tamaño del filtro"],"re":"Entrada × AFUE = salida (calor entregado). La carga de pérdida de calor del edificio debe cubrirse con los BTU/h de salida, no con la clasificación de entrada, que es mayor."},
  {"id":125,"q":"Una jurisdicción requiere un permiso para el reemplazo (changeout) de un sistema HVAC principalmente para asegurar:","opts":["Menor costo de refrigerante","Mayor ganancia del contratista","El cumplimiento del código y la inspección de la instalación","Una instalación más rápida"],"re":"Los permisos activan la inspección para que el trabajo cumpla con los códigos mecánicos, eléctricos y de energía, protegiendo la seguridad y el valor de la propiedad."},
  {"id":126,"q":"Al soldar con bronce (brazing) juntas de cobre a cobre de refrigeración, se prefiere una aleación BCuP (cobre-fósforo) porque:","opts":["No se puede usar en refrigeración","Requiere fundente sobre el cobre","Se funde a temperatura ambiente","Es autofundente en juntas de cobre a cobre"],"re":"Las aleaciones BCuP son autofundentes en juntas de cobre a cobre debido al fósforo; aún se requiere fundente al soldar cobre con latón o acero."},
  {"id":127,"q":"Hacer fluir nitrógeno seco a través de la tubería mientras se suelda con bronce previene:","opts":["El sobrecalentamiento alto","El sobrecalentamiento del soplete","La pérdida de refrigerante","La formación de escamas de óxido de cobre dentro de la tubería"],"re":"Sin una purga inerte de nitrógeno, el interior de la tubería se oxida, formando escamas de óxido de cobre que pueden obstruir los dispositivos de medición y contaminar el sistema."},
  {"id":128,"q":"Una presión típica de purga de nitrógeno de bajo flujo durante la soldadura con bronce es de aproximadamente:","opts":["0 psig","500 psig","150 psig","2–3 psig (un flujo suave)"],"re":"Solo se necesita un flujo suave de nitrógeno (unos pocos psig) para desplazar el oxígeno; una presión alta expulsaría la soldadura fundida fuera de la junta."},
  {"id":129,"q":"Antes de cargar un sistema nuevo, se realiza un vacío profundo para eliminar la humedad y:","opts":["Aumentar la presión de descarga","Evaporar y evacuar los no condensables y el vapor de agua","Aumentar el sobrecalentamiento","Agregar refrigerante"],"re":"Un vacío profundo (por ejemplo, ≤500 micrones) reduce el punto de ebullición del agua para que la humedad atrapada se vaporice y se evacúe junto con el aire/no condensables."},
  {"id":130,"q":"Se considera que un sistema está correctamente evacuado cuando un vacuómetro de micrones se mantiene por debajo de 500 micrones y:","opts":["Se mantiene estable (pasa la prueba de decaimiento) tras aislar la bomba","Muestra alto sobrecalentamiento","Sube rápidamente al cerrar la válvula","Marca 0 psig"],"re":"Después de aislar la bomba de vacío, el nivel de micrones debe mantenerse (un aumento lento y pequeño que se estabiliza); un aumento rápido indica humedad remanente o una fuga."},
  {"id":131,"q":"La tubería de refrigerante de la línea de succión que sube verticalmente puede requerir una trampa P (P-trap) o un dimensionamiento adecuado para asegurar:","opts":["Menor voltaje","Descongelamiento más rápido","El retorno de aceite al compresor","Mayor subenfriamiento"],"re":"El aceite viaja con el refrigerante; en montantes verticales largos, la velocidad correcta (y trampas donde sea necesario) mantiene el aceite en movimiento de regreso al compresor en lugar de acumularse."},
  {"id":132,"q":"Las líneas de succión de refrigerante deben aislarse principalmente para:","opts":["Prevenir la ganancia de calor y la condensación/sudoración superficial","Aumentar la presión","Solo reducir el ruido","Acelerar la soldadura con bronce"],"re":"Aislar la línea de succión fría previene la ganancia de calor que reduce la capacidad y evita la condensación que puede gotear y causar daños por agua."},
  {"id":133,"q":"Una línea de drenaje de condensado de un serpentín de enfriamiento normalmente requiere:","opts":["Pendiente hacia arriba","Presurización","Una trampa y una pendiente descendente adecuada","Ninguna pendiente"],"re":"Una trampa contrarresta la presión negativa del ventilador para que el condensado drene libremente; la línea debe tener pendiente descendente (por ejemplo, 1/8 in por pie) hacia el drenaje."},
  {"id":134,"q":"Se instala un interruptor o bandeja de condensado secundario (de derrame) para:","opts":["Reducir la presión de descarga","Aumentar el refrigerante","Aumentar el flujo de aire","Apagar el sistema o captar el agua si el drenaje primario se obstruye"],"re":"Los códigos exigen protección contra derrames (interruptor de flotador y/o bandeja secundaria) para prevenir daños por agua cuando el drenaje de condensado primario se obstruye."},
  {"id":135,"q":"La amperidad mínima de circuito (MCA) en la placa de datos de una unidad se utiliza para dimensionar:","opts":["El ducto","Los conductores del circuito derivado (cable)","El filtro","La carga de refrigerante"],"re":"La MCA le indica al instalador la amperidad mínima del cable requerida; la MOP/MOCP indica la máxima protección contra sobrecorriente (tamaño de interruptor/fusible)."},
  {"id":136,"q":"El valor MOP (máxima protección contra sobrecorriente) en la placa de datos establece:","opts":["El tipo de refrigerante","El calibre del ducto","El mayor tamaño permitido de interruptor/fusible","El color del cable"],"re":"La MOP (también llamada MOCP) es el mayor interruptor o fusible permitido para proteger el equipo; no se puede exceder aunque se use un cable más grande."},
  {"id":137,"q":"En el cableado estándar de termostatos de bajo voltaje, la terminal 'C' proporciona:","opts":["El lado común (de retorno) del transformador de 24 V","La señal del ventilador","La llamada de enfriamiento","La llamada de calefacción"],"re":"R es la fase viva de 24 V, C es el retorno común; juntas alimentan el termostato. Y=enfriamiento, G=ventilador, W=calefacción, O/B=válvula reversora."},
  {"id":138,"q":"En un termostato de bomba de calor, la terminal 'O' energiza la válvula reversora en:","opts":["Modo de enfriamiento","Modo de calefacción","Calor de emergencia","Solo en descongelamiento"],"re":"La mayoría de las bombas de calor energizan la válvula reversora con 'O' en enfriamiento. (Algunos sistemas más antiguos usan 'B' para energizarla en calefacción)."},
  {"id":139,"q":"Un transformador de control de 24 V clasificado en VA se selecciona de modo que su capacidad en VA:","opts":["Iguale el voltaje de línea","Sea siempre 5 VA","Coincida con el SEER","Cumpla o supere la carga de control total conectada"],"re":"Los VA del transformador deben suministrar el consumo combinado de la bobina del contactor, los relés y los accesorios; un subdimensionamiento causa caída de voltaje y vibración (chatter)."},
  {"id":140,"q":"Las normas SMACNA para ductos de lámina metálica especifican el calibre mínimo del metal principalmente según:","opts":["El color de la pintura","La marca del termostato","El tamaño del ducto y la clase de presión de operación","El tipo de refrigerante"],"re":"Los ductos más grandes y las clases de presión estática más altas requieren metal más grueso (de menor calibre) y más refuerzo, según las normas SMACNA de construcción de ductos HVAC."},
  {"id":141,"q":"Las costuras y juntas de los ductos se sellan mejor con:","opts":["Cinta de tela estándar ('duct tape')","Aceite de refrigerante","Mástique UL-181 o cinta de aluminio aprobada","Solo silicón sellador"],"re":"La cinta de tela falla con el tiempo; los códigos exigen mástique o cinta de aluminio listada UL-181 en las costuras para limitar las fugas."},
  {"id":142,"q":"Un horno de gas requiere aire de combustión. Un horno de tiro atmosférico en un espacio confinado necesita:","opts":["Dos aberturas (alta y baja) para el aire de combustión/ventilación","Más refrigerante","Ninguna abertura de aire","Solo un ventilador de extracción"],"re":"Los espacios confinados necesitan dos aberturas permanentes (una cerca de la parte superior, otra cerca de la inferior) dimensionadas según el código para suministrar aire de combustión y dilución."},
  {"id":143,"q":"Un horno de gas Categoría IV (condensante de alta eficiencia) se ventila con:","opts":["Solo chimenea de mampostería","Sin ventilación","Plástico sellado (PVC/CPVC) porque los gases de combustión son fríos y de presión positiva","Tubo metálico de pared sencilla"],"re":"Los hornos condensantes (Cat IV) producen gases de combustión fríos, de presión positiva y cargados de humedad, ventilados a través de plástico sellado con un drenaje de condensado."},
  {"id":144,"q":"Durante el arranque, medir la presión estática externa total (TESP) verifica:","opts":["La presión del gas","La carga de refrigerante","El color de la llama","El rendimiento del flujo de aire/ducto frente a la tabla del ventilador"],"re":"Comparar la TESP medida con la tabla de rendimiento del ventilador confirma si el sistema está moviendo el flujo de aire de diseño; una TESP alta indica restricción."},
  {"id":145,"q":"La presión del múltiple de gas (manifold) en un horno residencial típico de gas natural se ajusta cerca de:","opts":["25 in WC","3.5 in WC","11 in WC","0.5 in WC"],"re":"Los hornos de gas natural comúnmente operan con aproximadamente 3.5 in WC de presión de múltiple (el propano LP cerca de 10–11 in WC); siempre verifique con la placa de clasificación y un manómetro."},
  {"id":146,"q":"Después de instalar un condensador nuevo, el técnico verifica la carga en un sistema de orificio fijo (pistón) principalmente mediante:","opts":["El voltaje","El subenfriamiento","El tamaño del ducto","El sobrecalentamiento (con una carta de carga)"],"re":"Los sistemas de orificio fijo/pistón se cargan por sobrecalentamiento (usando una carta objetivo con bulbo húmedo interior y bulbo seco exterior); los sistemas con TXV usan subenfriamiento."},
  {"id":147,"q":"Un sistema equipado con TXV se carga a un objetivo de:","opts":["Valor de sobrecalentamiento","Valor de voltaje","Valor de subenfriamiento","Valor de CFM"],"re":"Dado que una TXV mantiene automáticamente el sobrecalentamiento del evaporador, la carga correcta se verifica en el condensador mediante el subenfriamiento según la especificación del fabricante."},
  {"id":148,"q":"El dimensionamiento del juego de líneas (line-set) importa porque una línea de succión sobredimensionada puede causar:","opts":["Demasiado subenfriamiento","Voltaje alto","Baja velocidad del refrigerante y mal retorno de aceite","Exceso de flujo de aire"],"re":"Si la velocidad de succión es demasiado baja (línea demasiado grande o tramo demasiado largo sin el dimensionamiento adecuado), el aceite no retornará al compresor, arriesgando una falla de lubricación."},
  {"id":149,"q":"Un medio de desconexión (desconexión de servicio) debe instalarse:","opts":["A la vista de la unidad exterior","Solo en el ático","Dentro del compresor","En el termostato"],"re":"El código eléctrico exige una desconexión a la vista y de fácil acceso de la unidad exterior para que pueda desenergizarse de forma segura para su mantenimiento."},
  {"id":150,"q":"Al conectar ducto flexible, este debe:","opts":["Dejarse desconectado","Comprimirse y doblarse para ahorrar espacio","Tensarse y apoyarse para evitar combaduras y restricciones","Llenarse con refrigerante"],"re":"El ducto flexible debe estirarse bien tenso y apoyarse a intervalos; las combaduras, dobleces y compresiones aumentan drásticamente la presión estática y reducen el flujo de aire."},
  {"id":151,"q":"El propósito de que la profundidad de una trampa P/trampa de condensado sea adecuada es:","opts":["Aumentar el flujo de aire","Reducir la presión del gas","Agregar refrigerante","Prevenir el paso de aire o el burbujeo que bloquea el drenaje"],"re":"En serpentines de tiro inducido (draw-through), la presión negativa del ventilador puede retener agua en la línea; una trampa correctamente dimensionada sella contra ella para que el condensado drene."},
  {"id":152,"q":"Antes de abrir un sistema para reemplazar un componente, el refrigerante debe ser:","opts":["Recuperado en un cilindro de recuperación aprobado","Quemado","Ventilado a la atmósfera","Mezclado con nitrógeno"],"re":"La Sección 608 de la EPA prohíbe la ventilación; el refrigerante debe recuperarse con equipo certificado en un cilindro de recuperación aprobado por el DOT."},
  {"id":153,"q":"Un juego de líneas nuevo se somete a una prueba de presión para detectar fugas antes de la evacuación usando:","opts":["Agua","Propano","Oxígeno puro","Nitrógeno seco (a menudo con una traza de refrigerante para un detector)"],"re":"El nitrógeno seco se usa para la prueba de presión/fugas porque es inerte y seco; el oxígeno es peligroso (combustión) y nunca debe usarse."},
  {"id":154,"q":"La puesta en marcha (commissioning) de una bomba de calor incluye verificar la operación de descongelamiento, lo cual se confirma mejor mediante:","opts":["La lectura de la marca del termostato","Iniciar/observar un ciclo de descongelamiento y el cambio de la válvula reversora","Revisar el filtro","Medir el SEER"],"re":"Durante el descongelamiento la unidad se invierte a enfriamiento, el ventilador exterior se detiene y el serpentín elimina el hielo; observar este ciclo confirma que la tarjeta de descongelamiento y la válvula reversora funcionan."},
  {"id":155,"q":"Un sobrecalentamiento alto junto con un subenfriamiento bajo indica con mayor frecuencia que el sistema está:","opts":["Con carga insuficiente (bajo de refrigerante)","Con flujo de aire demasiado alto","Sobrecargado","Con voltaje demasiado alto"],"re":"Una carga baja deja al evaporador hambriento (sobrecalentamiento alto) y deja poco líquido en el condensador (subenfriamiento bajo): la firma clásica de carga insuficiente."},
  {"id":156,"q":"Un sobrecalentamiento bajo con un subenfriamiento alto indica con mayor frecuencia:","opts":["Contactor abierto","Sobrecarga (demasiado refrigerante)","Filtro sucio","Carga insuficiente"],"re":"El exceso de carga inunda el condensador (subenfriamiento alto) y puede inundar el evaporador (sobrecalentamiento bajo): la firma de sobrecarga."},
  {"id":157,"q":"Una TXV que está 'cazando' (señal del bulbo inestable) típicamente causa:","opts":["Sobrecalentamiento que oscila hacia arriba y hacia abajo de forma errática","Voltaje alto","Sobrecalentamiento estable","Ningún efecto sobre el sobrecalentamiento"],"re":"Una TXV que caza sobrealimenta y subalimenta el evaporador, haciendo que el sobrecalentamiento oscile; las causas incluyen un bulbo sensor suelto/mal aislado o un tamaño de válvula incorrecto."},
  {"id":158,"q":"Un compresor que zumba y se dispara por sobrecarga pero no arranca, con los devanados leyendo bien, a menudo tiene un/una:","opts":["Termostato","Capacitor de arranque/marcha","Válvula reversora","Filtro deshidratador"],"re":"Un capacitor débil o fallado le quita al motor el par de arranque; el compresor consume amperaje de rotor bloqueado y se dispara. Verifique los microfaradios del capacitor antes de condenar el compresor."},
  {"id":159,"q":"Un capacitor de marcha se prueba mediante:","opts":["La revisión del refrigerante","La lectura solo del voltaje","Su olor","La medición de su capacitancia (µF) frente al valor nominal"],"re":"Con el capacitor descargado y desconectado, un medidor en capacitancia compara los µF reales con el valor nominal; los capacitores fuera de tolerancia o abultados deben reemplazarse."},
  {"id":160,"q":"Los puntos del contactor picados y quemados se atienden mejor:","opts":["Limándolos hasta alisarlos","Aumentando el flujo de aire","Reemplazando el contactor","Agregando refrigerante"],"re":"Limar los contactos elimina el recubrimiento y empeora el arqueo; un contactor picado debe reemplazarse para asegurar una conmutación confiable y de baja resistencia."},
  {"id":161,"q":"Para diagnosticar una sospecha de motor de compresor a tierra, el técnico mide la resistencia desde las terminales C, S y R hacia:","opts":["El termostato","Tierra/chasis (cualquier continuidad a tierra indica un devanado a tierra)","El refrigerante","El ducto"],"re":"Los devanados Común-Arranque-Marcha deben leer continuidad y aproximadamente C-R + C-S = S-R; cualquier continuidad de devanado a tierra significa un compresor a tierra (en corto con la carcasa) que debe reemplazarse."},
  {"id":162,"q":"Una presión de descarga (head) anormalmente alta es causada comúnmente por:","opts":["Serpentín limpio","Un serpentín de condensador sucio, sobrecarga o no condensables","Solo baja temperatura ambiente","Bajo refrigerante"],"re":"El rechazo de calor restringido del condensador (serpentín sucio, ventilador fallado, sobrecarga, o aire/no condensables en el sistema) eleva la presión de descarga."},
  {"id":163,"q":"Un horno de gas enciende y luego se apaga después de unos segundos (falla de 'comprobación de llama'). La causa más probable es un/una:","opts":["Sensor de llama sucio o fallado","Bajo refrigerante","Ducto sobredimensionado","Mala clasificación SEER"],"re":"Si el sensor de llama no puede comprobar la llama (sucio, agrietado o desalineado), el control cierra la válvula de gas por seguridad: la llama enciende y luego se apaga."},
  {"id":164,"q":"La señal del sensor de llama (rectificación de llama) se mide en:","opts":["Micrones","Libras","Voltios CA","Microamperios (µA) CC"],"re":"Un sensor de llama limpio deja pasar una pequeña corriente CC (microamperios) por rectificación; una lectura baja de microamperios indica un sensor sucio o una llama débil."},
  {"id":165,"q":"Un horno que cicla de forma corta por el interruptor de límite alto usualmente tiene:","opts":["Un filtro limpio","Flujo de aire insuficiente (sobrecalentamiento del intercambiador de calor)","Solo baja presión de gas","Demasiado flujo de aire"],"re":"El flujo de aire restringido (filtro/serpentín sucio, ductos bloqueados, ventilador débil) deja que el intercambiador de calor se sobrecaliente, disparando el límite y ciclando de forma corta el quemador."},
  {"id":166,"q":"Un intercambiador de calor agrietado es una preocupación de seguridad porque puede:","opts":["Aumentar el flujo de aire","Ahorrar gas","Permitir que los productos de combustión (CO) se mezclen con el aire de suministro","Reducir el SEER"],"re":"Una grieta puede filtrar monóxido de carbono y gases de combustión hacia el flujo de aire acondicionado: un peligro mortal que requiere apagar el equipo hasta repararlo/reemplazarlo."},
  {"id":167,"q":"Una bomba de calor que sopla aire frío en modo de calefacción y nunca se calienta puede tener una:","opts":["SEER alta","Válvula reversora atascada (todavía en enfriamiento)","Drenaje de condensado obstruido","Solo un filtro sucio"],"re":"Si la válvula reversora no logra cambiar (o falla su solenoide/cableado), la unidad permanece en enfriamiento durante una llamada de calor, entregando aire frío."},
  {"id":168,"q":"En modo de calefacción, el serpentín exterior de una bomba de calor actúa como el:","opts":["Condensador","Filtro","Dispositivo de medición","Evaporador (absorbiendo calor del aire exterior)"],"re":"En calefacción el flujo de refrigerante se invierte: el serpentín exterior absorbe calor (evaporador) y el serpentín interior lo rechaza (condensador)."},
  {"id":169,"q":"Un compresor que consume amperaje de rotor bloqueado (LRA) de forma continua:","opts":["Funcionará eficientemente","Se sobrecalentará y disparará su sobrecarga/interruptor","Mejorará el subenfriamiento","Reducirá la presión de descarga"],"re":"Un LRA continuo significa que el rotor no está girando (agarrotado, sin par de arranque, bajo voltaje); el motor se sobrecalienta y la sobrecarga o el interruptor se disparan."},
  {"id":170,"q":"Una restricción de refrigerante (por ejemplo, un filtro deshidratador obstruido) típicamente muestra:","opts":["Una caída de temperatura y escarcha en la restricción con baja presión de evaporador","Presiones iguales","Subenfriamiento alto en todas partes","Ningún síntoma"],"re":"La restricción de flujo causa una caída de presión/temperatura a través de la obstrucción (a menudo escarcha ahí), dejando hambriento al evaporador y reduciendo su presión."},
  {"id":171,"q":"Para encontrar una fuga pequeña de refrigerante, el método más preciso entre estos es:","opts":["Adivinar","Un detector electrónico de fugas o tinte UV, confirmado con burbujas","Agregar más carga","Solo escuchar"],"re":"Los detectores electrónicos y el tinte UV (más burbujas de jabón para confirmar) localizan con precisión las fugas pequeñas; una prueba de presión estática con nitrógeno confirma la hermeticidad."},
  {"id":172,"q":"Un motor de ventilador que funciona pero mueve poco aire, con alta presión estática, sugiere:","opts":["SEER alta","Fuga de refrigerante","Baja presión de gas","Una restricción de ducto/serpentín/filtro o una rueda de ventilador que patina/falla"],"re":"Una presión estática alta con bajo flujo de aire apunta a una restricción (filtro/serpentín sucio, ductos subdimensionados o bloqueados) o a una rueda de ventilador/banda degradada."},
  {"id":173,"q":"El mantenimiento rutinario para conservar la capacidad y la eficiencia incluye:","opts":["Limpiar serpentines, reemplazar filtros y verificar el flujo de aire/carga","Agregar refrigerante en cada visita","Deshabilitar las seguridades","Retirar la desconexión"],"re":"Serpentines y filtros limpios, flujo de aire verificado, carga correcta, conexiones eléctricas apretadas y drenajes de condensado despejados mantienen el sistema eficiente y confiable."},
  {"id":174,"q":"Agregar refrigerante a un sistema sin encontrar la fuga es:","opts":["Requerido por la EPA","Inadecuado: la fuga debe encontrarse y repararse (y ventilar es ilegal)","Más rápido y recomendado","La mejor práctica"],"re":"'Rellenar' un sistema con fuga desperdicia refrigerante, daña el medio ambiente y viola las buenas prácticas/reglas de la EPA: localice y repare la fuga."},
  {"id":175,"q":"Un capacitor debe descargarse antes de probarlo/manipularlo porque:","opts":["Siempre es seguro","Contiene refrigerante","Puede almacenar una carga eléctrica peligrosa incluso con la energía apagada","Contiene gas"],"re":"Los capacitores de marcha/arranque almacenan energía; tocar las terminales puede provocar una descarga. Descárguelo a través de una resistencia adecuada antes de manipularlo."},
  {"id":176,"q":"Una baja presión de succión con sobrecalentamiento de normal a alto en enfriamiento a menudo apunta a:","opts":["Solo condensador sucio","Sobrecarga","Voltaje alto","Carga baja o línea de líquido restringida / bajo flujo de aire"],"re":"Un evaporador hambriento por carga baja, una restricción en la línea de líquido o bajo flujo de aire interior reduce la presión de succión y aumenta el sobrecalentamiento."},
  {"id":177,"q":"Una bobina de contactor que no acciona, con 24 V presentes en la bobina, indica:","opts":["Bobina en buen estado","Fuga de refrigerante","Filtro sucio","Una bobina abierta (quemada): reemplace el contactor"],"re":"Si el voltaje de control nominal está presente pero el contactor no se energiza, la bobina está abierta/fallada y el contactor debe reemplazarse."},
  {"id":178,"q":"Un serpentín de evaporador que está limpio pero el sistema aún se congela, con la carga correcta, sugiere revisar el/la:","opts":["Válvula de gas","Válvula reversora","Flujo de aire interior (velocidad del ventilador, restricción de ductos)","Sensor de llama"],"re":"Con buena carga y un serpentín limpio, el congelamiento persistente usualmente se debe a bajo flujo de aire: derivación/velocidad incorrecta del ventilador, retorno restringido o ductos bloqueados."},
  {"id":179,"q":"Bajo la Sección 608 de la EPA, ventilar intencionalmente la mayoría de los refrigerantes durante el servicio está:","opts":["Prohibido","Permitido solo en interiores","Permitido si es poco","Requerido"],"re":"Ventilar CFC, HCFC, HFC y sus sustitutos es ilegal; el refrigerante debe recuperarse. Solo se toleran las liberaciones mínimas (de minimis) durante la recuperación/recirculación normal."},
  {"id":180,"q":"La certificación 'Tipo II' de la Sección 608 de la EPA cubre a los técnicos que trabajan en:","opts":["Solo AC automotriz","Electrodomésticos pequeños","Solo disposición","Aparatos de alta presión (por ejemplo, AC tipo split, bombas de calor)"],"re":"Tipo I = electrodomésticos pequeños; Tipo II = sistemas de alta presión; Tipo III = baja presión; Universal = todos. La mayoría del trabajo de campo de HVAC requiere Tipo II o Universal."},
  {"id":181,"q":"Un cilindro de refrigerante desechable (no recargable) nunca debe:","opts":["Mantenerse por debajo de 125°F","Almacenarse en posición vertical","Reciclarse cuando esté vacío","Recargarse"],"re":"Recargar un cilindro desechable del DOT es ilegal y peligroso (riesgo de sobrepresión/ruptura); recupere únicamente en cilindros de recuperación recargables clasificados por el DOT."},
  {"id":182,"q":"Un cilindro de recuperación debe llenarse a no más del ___ de su capacidad para permitir la expansión del líquido:","opts":["80%","50%","100%","95%"],"re":"La regla de llenado del 80% deja espacio de vapor para la expansión térmica del refrigerante líquido, previniendo la sobrepresión hidrostática a medida que sube la temperatura."},
  {"id":183,"q":"Los cilindros de refrigerante deben almacenarse:","opts":["Cerca de una llama abierta","En un área fresca y ventilada, lejos del calor, asegurados en posición vertical","En un techo caliente en verano","Junto a un horno"],"re":"El calor eleva peligrosamente la presión del cilindro; almacénelos en un lugar fresco y bien ventilado, asegurados contra caídas y lejos de fuentes de ignición."},
  {"id":184,"q":"Los refrigerantes A2L (por ejemplo, R-32, R-454B) se diferencian de los HFC más antiguos en que son:","opts":["Inertes como el nitrógeno","Ligeramente inflamables, lo que requiere detección de fugas y límites de carga","No tóxicos y no inflamables","Más pesados que el mercurio"],"re":"Los refrigerantes A2L tienen menor GWP pero son ligeramente inflamables; los equipos usan detección de fugas, enclavamientos de ventilación y límites de carga según el código (UL 60335-2-40)."},
  {"id":185,"q":"Antes de trabajar dentro de un panel eléctrico del equipo, el técnico debe:","opts":["Bloquear y etiquetar (LOTO) la desconexión y verificar voltaje cero","Aumentar el tamaño del interruptor","Agregar refrigerante","Abrir la válvula de gas"],"re":"El LOTO desenergiza el circuito, bloquea la desconexión, la etiqueta, y un medidor verifica voltaje cero antes de trabajar, previniendo la electrocución por un arranque inesperado."},
  {"id":186,"q":"Una fuga de refrigerante en un espacio bajo y mal ventilado (sótano o foso) es peligrosa principalmente porque la mayoría de los vapores de refrigerante son:","opts":["Seguros para respirar","Inflamables como la gasolina","Más pesados que el aire y se acumulan abajo, desplazando el oxígeno","Más ligeros que el aire y se elevan hacia afuera"],"re":"La mayoría de los vapores de refrigerante son más densos que el aire, por lo que se acumulan en áreas bajas y pueden desplazar el oxígeno, causando asfixia. Ventile los espacios bajos y monitoree el oxígeno antes de entrar."},
  {"id":187,"q":"La protección contra caídas generalmente se requiere en un techo o superficie de trabajo elevada en construcción cuando se trabaja a alturas superiores a:","opts":["2 pies","20 pies","6 pies (umbral general de construcción)","Sin requisito"],"re":"La protección contra caídas de OSHA en construcción generalmente se activa a los 6 pies; Cal/OSHA y el tipo de trabajo pueden imponer requisitos adicionales: use barandales, PFAS o cubiertas."},
  {"id":188,"q":"Al entrar a un ático o bóveda que pueda tener una atmósfera peligrosa, el técnico debe tratarlo como un/una:","opts":["Almacenamiento de refrigerante","Sala de descanso","Habitación normal","Posible espacio confinado que requiere evaluación/permiso"],"re":"Los espacios con entrada/salida limitada y una atmósfera potencialmente peligrosa son espacios confinados; evalúe, ventile, pruebe el aire y siga los procedimientos de permiso."},
  {"id":189,"q":"Un extintor de incendios Clase C está clasificado para incendios que involucran:","opts":["Metales combustibles","Madera y papel","Aceites de cocina","Equipo eléctrico energizado"],"re":"Clase A = combustibles ordinarios, B = líquidos inflamables, C = eléctrico energizado, D = metales, K = medios de cocina. Use Clase C (o ABC) cerca de equipo eléctrico vivo."},
  {"id":190,"q":"El nitrógeno utilizado para pruebas de presión es peligroso en un espacio confinado principalmente porque puede:","opts":["Incendiarse","Congelar las tuberías","Explotar","Desplazar el oxígeno y causar asfixia"],"re":"El nitrógeno es inerte pero desplaza el oxígeno; una fuga en un espacio cerrado puede reducir el O₂ a niveles asfixiantes sin advertencia. Ventile y monitoree."},
  {"id":191,"q":"Siempre debe usarse un regulador en un cilindro de nitrógeno porque la presión del cilindro puede exceder:","opts":["2000 psig (muy por encima de la presión de prueba del sistema)","14 psig","50 psig","100 psig"],"re":"Los cilindros de nitrógeno llenos contienen ~2000+ psig; sin un regulador, esa presión puede romper líneas/componentes. Ajuste el regulador a la presión de prueba requerida."},
  {"id":192,"q":"El monóxido de carbono (CO) es peligroso porque:","opts":["Solo afecta al equipo","Es más pesado que el refrigerante","Tiene un olor fuerte","Es incoloro e inodoro y se une a la hemoglobina, bloqueando el oxígeno"],"re":"El CO es un gas inodoro e incoloro que se une a la hemoglobina con mucha más facilidad que el oxígeno, causando envenenamiento; las verificaciones de seguridad de combustión y las alarmas de CO son esenciales."},
  {"id":193,"q":"Al soldar con bronce, se necesita protección ocular (lentes con tono) porque la llama produce:","opts":["Electricidad estática","Luz brillante y el trabajo involucra metal caliente/salpicaduras de fundente","Frío","Refrigerante"],"re":"Las llamas de soldadura con bronce son intensas; los lentes de seguridad con tono protegen contra el deslumbramiento, los rayos UV/IR y las salpicaduras de fundente/metal, mientras que los guantes protegen de las quemaduras."},
  {"id":194,"q":"Una prueba de 'despresurización en el peor de los casos' en un aparato de combustión verifica:","opts":["El derrame de gases de combustión/contratiro cuando los ventiladores de extracción despresurizan el espacio","El SEER","Las fugas de refrigerante","El tamaño del ducto"],"re":"Hacer funcionar los ventiladores de extracción puede despresurizar una casa y causar que un aparato atmosférico genere contratiro de CO al interior; la prueba verifica la ventilación segura en el peor de los casos."},
  {"id":195,"q":"El equipo de protección personal (PPE) para trabajo eléctrico cerca de partes vivas incluye:","opts":["Nada","Solo un casco","Guantes/herramientas aislados y protección con clasificación de arco apropiada","Gafas para refrigerante"],"re":"El trabajo eléctrico vivo requiere herramientas/guantes aislados, protección ocular y PPE con clasificación de arco acorde al peligro; desenergizar primero siempre es preferible."},
  {"id":196,"q":"Un receptáculo GFCI protege al trabajador al:","opts":["Aumentar el amperaje","Dispararse rápidamente cuando detecta una fuga de corriente a tierra","Agregar refrigerante","Aumentar el voltaje"],"re":"Un GFCI detecta un desequilibrio entre la fase y el neutro (fuga a tierra, por ejemplo, a través de una persona) y se dispara en milisegundos para prevenir la electrocución."},
  {"id":197,"q":"La Hoja de Datos de Seguridad (SDS) de un refrigerante o producto químico proporciona:","opts":["Información de peligros, manejo, primeros auxilios y PPE","El precio","El tamaño del ducto","La clasificación SEER"],"re":"Una SDS enumera los peligros físicos/para la salud, el manejo y almacenamiento seguros, los controles de exposición/PPE, los primeros auxilios y la respuesta ante derrames; debe estar accesible en el trabajo."},
  {"id":198,"q":"Las escaleras utilizadas para acceder a equipos en azoteas deben:","opts":["Estar clasificadas para la carga y colocadas en un ángulo seguro, extendidas por encima del borde del techo","Ser de aluminio cerca de líneas eléctricas","Tener cualquier longitud, apoyadas en cualquier ángulo","Dejarse sin asegurar"],"re":"Use una escalera clasificada para servicio a un ángulo de ~4:1, extendida ~3 ft por encima del punto de apoyo, asegurada; evite escaleras metálicas cerca de líneas eléctricas."},
  {"id":199,"q":"La técnica adecuada de levantamiento para evitar lesiones de espalda al mover equipo es:","opts":["Levantar con las piernas, mantener la carga cerca, evitar girar el torso","Doblarse por la cintura y girar","Usar el movimiento más rápido","Levantar siempre solo"],"re":"Doble las rodillas, mantenga la espalda recta y la carga cerca del cuerpo, y pivotee con los pies en lugar de girar el torso; busque ayuda o use equipo para unidades pesadas."},
  {"id":200,"q":"Antes de reconectar la energía y dejar un trabajo, el técnico debe confirmar que todos los dispositivos de seguridad (límites, interruptores de presión, sensor de llama) estén:","opts":["Retirados","Puenteados para mayor confiabilidad","Pintados","Funcionales y no puenteados/anulados"],"re":"Nunca deje los controles de seguridad puenteados o deshabilitados; verifique que todos los límites, interruptores de presión, interruptores de flotador y la comprobación de llama operen para que el sistema falle de forma segura."},
  {"id":201,"q":"Una tonelada de refrigeración es igual a:","opts":["100,000 BTU/h","1,000 BTU/h","500 watts","12,000 BTU/h"],"re":"Una tonelada de refrigeración = 12,000 BTU/h, la tasa para derretir una tonelada de hielo en 24 horas (288,000 BTU ÷ 24 h)."},
  {"id":202,"q":"El calor latente de vaporización es el calor absorbido cuando una sustancia:","opts":["Pierde presión","Se congela","Aumenta su temperatura","Cambia de líquido a vapor sin cambio de temperatura"],"re":"El calor latente cambia el estado (líquido↔vapor) a temperatura constante; este cambio de fase en el evaporador/condensador es como la refrigeración mueve el calor."},
  {"id":203,"q":"En el ciclo básico de refrigeración, el componente que eleva la presión y la temperatura del refrigerante es el:","opts":["Dispositivo dosificador","Condensador","Compresor","Evaporador"],"re":"El compresor eleva el vapor de baja presión a alta presión/temperatura para que pueda rechazar el calor en el condensador."},
  {"id":204,"q":"El dispositivo dosificador (p. ej., TXV o pistón) en el ciclo:","opts":["Comprime el vapor","Reduce la presión y dosifica el líquido hacia el evaporador","Agrega calor","Almacena aceite"],"re":"El dispositivo dosificador crea la caída de presión entre el lado de alta y el de baja, y controla el flujo de refrigerante líquido hacia el evaporador."},
  {"id":205,"q":"En un sistema de enfriamiento, el evaporador:","opts":["Eleva la presión","Absorbe el calor del aire interior","Almacena líquido","Rechaza el calor al exterior"],"re":"El evaporador absorbe el calor interior a medida que el refrigerante hierve y se convierte en vapor; el condensador rechaza ese calor al exterior."},
  {"id":206,"q":"La relación de compresión de un compresor de refrigeración es la relación entre:","opts":["La presión absoluta de descarga y la presión absoluta de succión","La temperatura de succión y la de descarga","Los CFM y el tonelaje","El voltaje y el amperaje"],"re":"Relación de compresión = presión absoluta de descarga / presión absoluta de succión (psia, no psig). Una relación más alta reduce la eficiencia volumétrica y eleva la temperatura de descarga."},
  {"id":207,"q":"En un sistema de refrigeración, el lado de alta (lado de descarga) incluye los componentes entre:","opts":["Únicamente las dos válvulas de servicio","El termostato y el fusible","La descarga del compresor y el dispositivo dosificador","La entrada del evaporador y la entrada del compresor"],"re":"El lado de alta (descarga) va desde la salida del compresor, a través del condensador, hasta el dispositivo dosificador; el lado de baja (succión) va desde la salida del dispositivo dosificador, a través del evaporador, de vuelta al compresor."},
  {"id":208,"q":"En comparación con el R-22, el R-410A opera a:","opts":["Presiones significativamente más altas","Presiones idénticas","Sin presión","Presiones mucho más bajas"],"re":"El R-410A funciona aproximadamente entre 50 y 70 % más de presión que el R-22, por lo que requiere equipos, manómetros y componentes calificados para la presión más alta."},
  {"id":209,"q":"Una mezcla de refrigerante zeotrópica (p. ej., R-407C) presenta 'deslizamiento de temperatura' (temperature glide), lo que significa que:","opts":["Tiene un solo punto de ebullición","Sus componentes hierven/condensan en un rango de temperaturas","Es un azeótropo","No se puede utilizar"],"re":"Las mezclas zeotrópicas cambian de fase en un rango de temperatura (glide); para evitar el fraccionamiento se cargan como líquido, y el glide se toma en cuenta en el sobrecalentamiento/subenfriamiento."},
  {"id":210,"q":"¿Con cuáles refrigerantes se requiere el aceite POE (polioléster)?","opts":["R-22 (aceite mineral)","HFC como el R-410A","Solo amoníaco","Ningún refrigerante necesita aceite"],"re":"Los sistemas con HFC (R-410A, R-407C) usan aceite POE; el R-22 usaba aceite mineral. El POE es higroscópico, así que manténgalo sellado y evacúe bien."},
  {"id":211,"q":"El valor R del aislamiento es una medida de su:","opts":["Peso","Resistencia térmica (mayor = mejor aislante)","Costo","Color"],"re":"El valor R cuantifica la resistencia al flujo de calor; un valor R más alto significa menor transferencia de calor. El valor U (conductancia total) es su recíproco."},
  {"id":212,"q":"La ley de Ohm establece que el voltaje es igual a:","opts":["Potencia × tiempo","Corriente ÷ resistencia","Resistencia ÷ corriente","Corriente × resistencia (V = I × R)"],"re":"Ley de Ohm: V = I × R. Permite a los técnicos calcular cualquiera de los valores (voltaje, corriente, resistencia) a partir de los otros dos."},
  {"id":213,"q":"Para una carga resistiva, la potencia eléctrica en watts es igual a:","opts":["Volts × amperes","Volts ÷ amperes","Amperes ÷ ohms","Volts × ohms"],"re":"Potencia (W) = volts × amperes (P = V × I) para cargas resistivas; esto se usa para dimensionar circuitos y estimar el consumo de la calefacción eléctrica."},
  {"id":214,"q":"El poder calorífico aproximado del gas natural es de alrededor de:","opts":["100 BTU por pie cúbico","1,000 BTU por pie cúbico","1,000,000 BTU por pie cúbico","10 BTU por pie cúbico"],"re":"El gas natural es de aproximadamente 1,000 BTU por pie cúbico; esto se usa con el flujo de gas medido para hallar la tasa de entrada de un horno (furnace)."},
  {"id":215,"q":"'Cronometrar el medidor de gas' (clocking the gas meter) permite al técnico determinar de un horno (furnace) su:","opts":["Tamaño del ducto","SEER","BTU/h de entrada (tasa de quemado)","Carga de refrigerante"],"re":"Cronometrar el dial del medidor de gas da los pies cúbicos por hora; multiplicado por el poder calorífico (~1,000 BTU/cf) arroja la tasa de quemado de entrada."},
  {"id":216,"q":"El aumento de temperatura a través de un horno (furnace) de gas debe estar dentro del rango:","opts":["Establecido por el termostato","Siempre 20°F","Indicado en la placa de datos del horno (furnace)","Siempre 100°F"],"re":"Cada horno (furnace) indica un rango permitido de aumento de temperatura en su placa de datos; el flujo de aire se ajusta para que el aumento medido (de retorno a suministro) se mantenga dentro de ese rango."},
  {"id":217,"q":"El flujo de aire de un horno (furnace) de gas se puede calcular con la fórmula CFM = BTU/h de salida ÷ (1.08 × ___):","opts":["Aumento de temperatura","Presión estática","Sobrecalentamiento","Voltaje"],"re":"Reordenando Q = 1.08 × CFM × ΔT se obtiene CFM = salida ÷ (1.08 × aumento de temperatura) — una verificación en campo del flujo de aire del soplador en un horno (furnace)."},
  {"id":218,"q":"Según las leyes de los ventiladores (fan laws), el flujo de aire (CFM) varía:","opts":["Nada con las RPM","Inversamente con las RPM","Directamente (linealmente) con las RPM del soplador","Con el cuadrado de las RPM del soplador"],"re":"El CFM es directamente proporcional a las RPM; la presión estática varía con las RPM al cuadrado; la potencia varía con las RPM al cubo."},
  {"id":219,"q":"Según las leyes de los ventiladores (fan laws), la presión estática varía con:","opts":["Las RPM","El cubo de las RPM","La raíz cuadrada de las RPM","El cuadrado de las RPM"],"re":"La presión estática aumenta con el cuadrado de la velocidad, y la potencia requerida con el cubo — por eso pequeños aumentos de velocidad elevan fuertemente la potencia y el ruido."},
  {"id":220,"q":"La velocidad del aire en un ducto es igual al flujo de aire (CFM) dividido entre:","opts":["El voltaje","La longitud del ducto","El área de la sección transversal del ducto (pies cuadrados)","La presión estática"],"re":"Velocidad (fpm) = CFM ÷ área (pies cuadrados). Una velocidad excesiva causa ruido; una muy baja causa una distribución deficiente del aire."},
  {"id":221,"q":"La energía trifásica se usa comúnmente para motores grandes de HVAC porque:","opts":["No requiere protección","Es más barata de instalar en todas partes","Entrega energía más uniforme, lo que permite motores más pequeños y eficientes","Usa un solo cable"],"re":"La energía trifásica entrega potencia más constante, por lo que los motores son más pequeños, funcionan más fríos/eficientemente y arrancan sin componentes de arranque."},
  {"id":222,"q":"Una dimensión de 'redondo equivalente' de un ducto se usa para:","opts":["Convertir un ducto rectangular al tamaño redondo con igual fricción/flujo de aire","Ajustar el termostato","Medir el refrigerante","Dimensionar el interruptor (breaker)"],"re":"Las tablas de fricción se basan en ductos redondos; el valor de redondo equivalente permite dimensionar ductos rectangulares con la misma pérdida por fricción para un flujo de aire dado."},
  {"id":223,"q":"Un sistema de aire de retorno subdimensionado normalmente causará:","opts":["Menor consumo de energía","Alta presión estática y flujo de aire reducido (soplador hambriento)","Mayor capacidad de enfriamiento","Menor presión estática"],"re":"Muy poca área de retorno eleva la presión estática del lado de retorno, dejando hambriento al soplador; el flujo de aire baja, perjudicando la capacidad y arriesgando congelamiento de la bobina o disparos del límite del horno (furnace)."},
  {"id":224,"q":"En la estimación, el 'margen' difiere del 'recargo' (markup) en que el margen es la ganancia expresada como un porcentaje de:","opts":["Solo la mano de obra","El precio de venta","Solo el material","El costo"],"re":"Margen = ganancia ÷ precio de venta; recargo (markup) = ganancia ÷ costo. La misma ganancia en dólares representa un porcentaje de margen menor que el porcentaje de recargo, un error común de fijación de precios."},
  {"id":225,"q":"Una orden de cambio (change order) se usa para:","opts":["Programar una inspección","Pedir refrigerante","Documentar el alcance agregado/modificado y su costo más allá del contrato original","Cancelar la licencia"],"re":"Una orden de cambio por escrito registra el trabajo agregado o modificado después del contrato, con el precio acordado y las firmas — protegiendo a ambas partes."},
  {"id":226,"q":"Una conexión abocardada SAE de 45° se usa para:","opts":["Sellar ductos","Soldar con bronce cobre a acero","Conectar respiraderos de gas","Hacer un sello mecánico, sin empaque, en cobre blando (mini-splits, válvulas)"],"re":"Un abocardado de 45° bien hecho asienta metal contra metal bajo la tuerca de abocardado, dando una conexión de refrigerante reparable sin soldadura de bronce."},
  {"id":227,"q":"Después de cortar tubería de cobre, el técnico debe escariar/desbarbar el extremo para:","opts":["Endurecer el cobre","Agregar fundente","Eliminar las rebabas que causan turbulencia y residuos en el sistema","Aumentar el diámetro"],"re":"Las rebabas restringen el flujo, crean turbulencia y pueden desprenderse y ensuciar los dispositivos dosificadores; escarie el interior y desbarbe antes del ensamblaje."},
  {"id":228,"q":"Entre las aleaciones de soldadura fuerte de plata, las de mayor contenido de plata generalmente:","opts":["No requieren calor","Son más débiles","Fluyen a temperaturas más bajas","No pueden unir cobre"],"re":"Las aleaciones con mayor contenido de plata se funden/fluyen a temperaturas más bajas y mojan bien, útiles en metales distintos; el BCuP de menor contenido de plata es común para cobre con cobre."},
  {"id":229,"q":"La soldadura blanda (p. ej., 95/5) es aceptable para ___ pero NO para uniones de refrigerante:","opts":["Líneas de agua/condensado","Tubería de gas","Cable eléctrico","Líneas de refrigerante de alta presión"],"re":"La soldadura blanda se funde a baja temperatura y carece de la resistencia para las presiones de refrigerante; se usa en líneas de agua/drenaje, mientras que las uniones de refrigerante se sueldan con bronce."},
  {"id":230,"q":"La aleación fundida de soldadura fuerte es atraída hacia una unión correctamente ajustada por:","opts":["La presión del refrigerante","Solo la gravedad","La atracción eléctrica","La acción capilar"],"re":"La acción capilar atrae el material de aporte fundido hacia el espacio pequeño y uniforme entre el tubo y el accesorio, por lo que el huelgo y la limpieza correctos son esenciales."},
  {"id":231,"q":"La ampacidad del cable de cobre (60/75°C) es comúnmente: #14 = 15 A, #12 = 20 A, y #10 = ___:","opts":["10 A","100 A","50 A","30 A"],"re":"Ampacidades comunes de cobre para circuitos ramales: 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — siempre confirme con la tabla del código y las condiciones."},
  {"id":232,"q":"El propósito principal del conductor de puesta a tierra del equipo es:","opts":["Aumentar el voltaje","Proporcionar una trayectoria de falla de baja resistencia para que el interruptor (breaker) se dispare ante una falla a tierra","Mejorar el SEER","Conducir la corriente de carga normal"],"re":"El conductor de tierra le da a la corriente de falla una trayectoria segura de regreso a la fuente, disparando el dispositivo de sobrecorriente y evitando que las cubiertas queden energizadas."},
  {"id":233,"q":"Un kit de arranque rápido (capacitor de arranque con un relé de potencial o PTCR) se agrega para:","opts":["Aumentar el torque de arranque en un compresor de arranque difícil","Retirar refrigerante","Reducir el voltaje","Frenar el compresor"],"re":"Un dispositivo de arranque rápido da torque de arranque adicional (y se desconecta rápidamente tras el arranque) para ayudar a un compresor que tiene dificultad para arrancar, p. ej., bajo alta presión de cabeza."},
  {"id":234,"q":"Un calentador de cárter (crankcase heater) en un compresor se usa para:","opts":["Enfriar el aceite","Aumentar la presión de cabeza","Evitar que el refrigerante migre/condense hacia el aceite del compresor durante el ciclo de apagado","Agregar refrigerante"],"re":"El calentador de cárter mantiene el aceite caliente para que el refrigerante no condense en él durante los ciclos de apagado, evitando la dilución y el dañino golpe de líquido (slugging) en el arranque."},
  {"id":235,"q":"El control de presión de cabeza en baja temperatura ambiente (ciclado del ventilador o inundación del condensador) se usa para que un sistema pueda:","opts":["Calentar más rápido","Ahorrar refrigerante","Enfriar de manera confiable en temperaturas exteriores frías al mantener alta la presión de cabeza","Omitir el dispositivo dosificador"],"re":"En clima frío la presión de cabeza puede caer demasiado para que el dispositivo dosificador alimente correctamente; los controles de baja temperatura ambiente mantienen una presión de cabeza adecuada para el enfriamiento mecánico."},
  {"id":236,"q":"Un secuenciador en un horno (furnace) de calefacción eléctrica se usa para:","opts":["Dosificar el refrigerante","Abrir la válvula de gas","Enfriar la bobina","Escalonar el encendido/apagado de los elementos calefactores para limitar la corriente de irrupción"],"re":"Los secuenciadores energizan las resistencias de calefacción eléctrica por etapas, de modo que no todas tomen la corriente de irrupción a la vez — reduciendo el estrés eléctrico y el parpadeo."},
  {"id":237,"q":"La tubería de gas se dimensiona con base en los CFH requeridos, la longitud de la tubería y:","opts":["El SEER","El calibre del ducto","La caída de presión permitida (según las tablas de dimensionamiento)","El tipo de refrigerante"],"re":"Las tablas de dimensionamiento de tubería usan la demanda (CFH), la longitud más larga y la caída de presión permitida para elegir un diámetro que entregue suficiente gas a todos los aparatos."},
  {"id":238,"q":"Una trampa de sedimentos (drip leg) se instala cerca de la válvula de gas para:","opts":["Ventilar el gas de combustión","Aumentar la presión","Atrapar residuos y humedad antes de que entren a la válvula de gas","Agregar aire"],"re":"La trampa de sedimentos recoge óxido, sarro y condensado para que no lleguen ni ensucien la válvula de gas/orificios."},
  {"id":239,"q":"Una válvula manual de cierre de gas generalmente debe instalarse:","opts":["A menos de 6 pies del aparato y en la misma habitación","Dentro del quemador","En cualquier parte de la casa","Solo en el medidor"],"re":"El código requiere un cierre manual accesible a unos 6 pies del aparato (misma habitación) para que el gas pueda aislarse rápidamente para el servicio."},
  {"id":240,"q":"Un respiradero de gas Tipo B (doble pared) debe mantener su espacio libre indicado a los combustibles, típicamente:","opts":["0 pulgadas","36 pulgadas","12 pulgadas","Alrededor de 1 pulgada"],"re":"El respiradero Tipo B está certificado para un espacio libre de aproximadamente 1 pulgada a los combustibles; los conectores de pared simple requieren espacios libres mucho mayores — siempre siga la certificación."},
  {"id":241,"q":"Un conector de respiradero para un aparato atmosférico debe tener una inclinación:","opts":["Hacia arriba en dirección a la chimenea (p. ej., ≥1/4 pulg por pie)","Perfectamente nivelado","En bucle hacia abajo","Hacia abajo, alejándose de la chimenea"],"re":"Una inclinación hacia arriba en dirección a la chimenea favorece el tiro natural y evita el estancamiento de gases de combustión/condensado que bloquearía la ventilación."},
  {"id":242,"q":"Un cierre Pittsburgh (Pittsburgh lock), las grapas de arrastre (drive cleats) y las grapas en S (S-cleats) se usan todos en:","opts":["Conducto eléctrico","Tubería de refrigerante","Costuras y uniones de ductos de lámina metálica","Ventilación de gas"],"re":"Estas son conexiones de lámina metálica: el cierre Pittsburgh forma una costura longitudinal, mientras que las grapas de arrastre y en S unen secciones de ducto transversalmente."},
  {"id":243,"q":"Un encendedor de superficie caliente (HSI) se verifica mejor midiendo su:","opts":["Solo el voltaje","El flujo de aire","La resistencia (ohms) en frío, comparada con la especificación","La carga de refrigerante"],"re":"Una lectura de resistencia en frío (ohms) fuera del rango del fabricante indica un encendedor agrietado o envejecido; inspeccione visualmente también en busca de grietas."},
  {"id":244,"q":"El análisis de combustión al arranque mide el CO, la temperatura de la chimenea y:","opts":["El voltaje","El oxígeno/CO₂ en el gas de combustión","El tamaño del ducto","El SEER"],"re":"Un analizador de combustión lee el O₂/CO₂, el CO y la temperatura de la chimenea para confirmar una combustión completa, segura y eficiente, y una ventilación adecuada."},
  {"id":245,"q":"Una campana de flujo (balometer) se usa durante el arranque para medir:","opts":["La temperatura de la llama","El flujo de aire (CFM) en una rejilla de suministro o de retorno","La presión de gas","La presión de refrigerante"],"re":"Una campana de flujo captura y lee los CFM entregados en una rejilla de suministro o de retorno, útil para el balanceo de aire y para verificar el flujo de aire de diseño."},
  {"id":246,"q":"Al cargar un mini-split sin ductos, la carga de fábrica normalmente cubre una longitud de línea establecida, y el técnico debe:","opts":["Usar agua","Siempre retirar refrigerante","Omitir la evacuación","Agregar refrigerante por la longitud de línea que exceda la cantidad incluida"],"re":"Los mini-splits vienen precargados para una longitud de línea base (p. ej., 15–25 pies); los juegos de líneas más largos requieren agregar la cantidad por pie indicada en el manual de instalación."},
  {"id":247,"q":"En una evacuación triple, se introduce nitrógeno seco entre los tirones de vacío para:","opts":["Agregar refrigerante","Presurizar para la prueba de fugas","Romper el vacío y ayudar a barrer la humedad restante","Enfriar la bomba"],"re":"Romper el vacío con nitrógeno seco diluye y arrastra la humedad residual; repetir el tirón/barrido alcanza un sistema seco de manera más confiable."},
  {"id":248,"q":"Para una lectura de vacío precisa, el medidor de micrones (micron gauge) debe colocarse:","opts":["En el sistema, lo más lejos posible de la bomba","Dentro del compresor","En la entrada de la bomba de vacío","En la línea de gas"],"re":"Leer en la bomba muestra el vacío de la bomba, no el del sistema; monte el medidor de micrones en el sistema (p. ej., en el extremo opuesto) para confirmar que todo el sistema está evacuado."},
  {"id":249,"q":"Un 'whip' flexible (sealtight) entre el desconectador y el condensador se usa para:","opts":["Ventilar gas","Drenar el condensado","Permitir la vibración/movimiento mientras protege el cableado","Conducir refrigerante"],"re":"El whip flexible protege los conductores del circuito ramal en la unidad mientras permite la vibración y el ligero movimiento del equipo exterior."},
  {"id":250,"q":"El condensado de un horno (furnace) condensante de alta eficiencia es ligeramente ácido, por lo que a menudo se requiere un ___:","opts":["Filtro más grande","Línea de gas más grande","Neutralizador de condensado","Kit de arranque rápido"],"re":"El condensado de un horno (furnace) condensante es ácido (pH bajo); un kit neutralizador protege los drenajes metálicos y cumple con los requisitos locales de descarga."},
  {"id":251,"q":"Un interruptor de flotador de seguridad de condensado se conecta:","opts":["En paralelo con el voltaje de línea","A los devanados del compresor","Solo a la válvula de gas","En serie con el circuito de control para apagar la unidad ante un nivel alto de agua"],"re":"El interruptor de flotador abre el circuito de control de 24 V cuando la bandeja/línea se acumula, deteniendo el sistema antes de que el agua se desborde y cause daños."},
  {"id":252,"q":"Las válvulas de servicio (king/queen) de un condensador se 'asientan hacia atrás' (back-seated) para:","opts":["Aislar los puertos de manómetro mientras se deja el sistema abierto al flujo","Hacer el vaciado (pump down) del sistema","Ventilar refrigerante","Agregar aceite"],"re":"El asentamiento hacia atrás abre la trayectoria de flujo del sistema y cierra el puerto de servicio; el asentamiento hacia adelante (front-seating) aísla el condensador (se usa en el pump-down)."},
  {"id":253,"q":"El 'vaciado' (pump down) de un sistema almacena el refrigerante en el:","opts":["Evaporador","Aceite del compresor","Línea de succión","Condensador/receptor (cerrando la válvula de líquido y haciéndolo funcionar hasta baja succión)"],"re":"Cerrar la válvula de la línea de líquido (king) y hacer funcionar el compresor atrae el refrigerante hacia el condensador/receptor, aislando el lado de baja para el servicio."},
  {"id":254,"q":"Un filtro secador de línea de líquido debe instalarse:","opts":["En cualquier dirección","Solo en la línea de succión","Al revés","Con su flecha apuntando en la dirección del flujo de refrigerante (hacia el dispositivo dosificador)"],"re":"La flecha de flujo del secador debe apuntar hacia el evaporador/dispositivo dosificador; una instalación invertida perjudica el filtrado y el secado."},
  {"id":255,"q":"La humedad en un sistema de refrigeración es dañina porque puede:","opts":["Congelarse en el dispositivo dosificador y formar ácidos con el aceite","Reducir la presión de cabeza","Aumentar el subenfriamiento","Mejorar el enfriamiento"],"re":"La humedad puede congelarse en el dispositivo dosificador (restricción intermitente) y reaccionar con el aceite POE/refrigerante para formar ácidos que corroen y causan quemadura (burnout)."},
  {"id":256,"q":"Los gases no condensables (como el aire) en un sistema causan:","opts":["Presión de cabeza más alta de lo normal para la temperatura ambiente/de condensación","Mejor eficiencia","Bajo sobrecalentamiento","Baja presión de cabeza"],"re":"El aire no condensa, por lo que ocupa volumen del condensador y eleva la presión de cabeza por encima de lo que produciría la temperatura ambiente por sí sola."},
  {"id":257,"q":"Las burbujas en la mirilla de la línea de líquido (gas de revaporización/flash gas) usualmente indican:","opts":["Bajo subenfriamiento — carga insuficiente o una restricción","Sobrecarga","Alto flujo de aire","Un filtro limpio"],"re":"El flash gas significa que el líquido no está completamente subenfriado; las causas comunes son la carga insuficiente o una restricción en la línea de líquido (p. ej., secador obstruido)."},
  {"id":258,"q":"Una TXV atascada cerrada (o con la carga del bulbo perdida) produce:","opts":["Ningún cambio","Alto sobrecalentamiento, baja succión, baja capacidad","Síntomas de sobrecarga","Bajo sobrecalentamiento, alta succión"],"re":"Una TXV cerrada/que subalimenta deja hambriento al evaporador: el sobrecalentamiento sube, la presión de succión baja y la capacidad disminuye."},
  {"id":259,"q":"Una TXV atascada abierta (sobrealimentando) produce:","opts":["Baja succión","Bajo sobrecalentamiento, alta succión y riesgo de retorno de líquido (floodback)","Alto sobrecalentamiento","Ningún síntoma"],"re":"Una válvula que sobrealimenta inunda el evaporador: el sobrecalentamiento cae hacia cero, la succión sube y el líquido puede regresar al compresor (riesgo de slugging)."},
  {"id":260,"q":"El retorno de refrigerante líquido al compresor (floodback/slugging) es peligroso porque el líquido:","opts":["Mejora la lubricación","Reduce los amperes","No se comprime y puede romper válvulas/cojinetes","Se comprime fácilmente"],"re":"El líquido es esencialmente incompresible; el slugging golpea las válvulas y arrastra el aceite de los cojinetes, causando falla mecánica."},
  {"id":261,"q":"En un compresor monofásico, la lectura de resistencia más alta normalmente está entre:","opts":["Las terminales de Arranque (Start) y Marcha (Run)","La terminal y tierra","Común (Common) y Marcha (Run)","Común (Common) y Arranque (Start)"],"re":"C-R es la más baja, C-S es más alta y S-R es la suma (la más alta). La continuidad a la carcasa/tierra indica un compresor a tierra (con falla)."},
  {"id":262,"q":"Un devanado de compresor que lee resistencia infinita (OL) indica:","opts":["Un devanado en buen estado","Un devanado a tierra","Un devanado abierto (o una sobrecarga interna abierta)","Un devanado en cortocircuito"],"re":"La resistencia infinita significa que el circuito está roto — un devanado abierto o una sobrecarga térmica interna abierta (puede reiniciarse al enfriarse)."},
  {"id":263,"q":"Un motor trifásico que pierde una fase ('single-phasing') normalmente:","opts":["Se acelera","Funciona más frío","Se sobrecalienta, zumba y se dispara por sobrecarga","Mejora la eficiencia"],"re":"Con una fase perdida, el motor no puede desarrollar el torque normal; la corriente sube en los devanados restantes y se sobrecalienta/dispara. Revise fusibles, contactos y suministro."},
  {"id":264,"q":"Un compresor con válvulas desgastadas/con fugas normalmente muestra:","opts":["Baja succión, alta presión de cabeza","Desempeño normal","Capacidad reducida con alta succión y baja presión de descarga","Alto subenfriamiento"],"re":"La fuga interna de las válvulas permite que el gas recircule, por lo que el compresor no puede generar la descarga normal ni bajar la succión — la capacidad cae a pesar de estar funcionando."},
  {"id":265,"q":"Antes de condenar un motor de soplador ECM, el técnico debe revisar primero:","opts":["La presión de gas","La trampa de condensado","La carga de refrigerante","La alimentación, la señal de control/PWM y las conexiones/programación"],"re":"A menudo se culpa erróneamente a los módulos ECM; verifique primero la alimentación de línea/bajo voltaje, la señal de demanda del termostato/tablero, el arnés del motor y la programación correcta."},
  {"id":266,"q":"Un horno (furnace) de gas cuyo interruptor de presión no cierra después de que arranca el inductor:","opts":["Se sobrecalienta","Enciende normalmente","Enfría la casa","No logra encender (sin prueba de tiro)"],"re":"El interruptor de presión debe comprobar el tiro del inductor antes del encendido; si no cierra (inductor débil, chimenea/condensado bloqueado, manguera agrietada), la secuencia se detiene de forma segura."},
  {"id":267,"q":"El encendido retardado que causa un pequeño 'soplido' (puff) o salida de llama (rollout) en los quemadores se debe a menudo a:","opts":["Demasiado flujo de aire","Alto SEER","Quemadores sucios, baja presión de gas o una fuente de encendido débil","Sobrecarga"],"re":"Cuando el gas se acumula antes de encender, se enciende con un soplido; las causas incluyen quemadores sucios/obstruidos, baja presión de manifold o un encendedor/trayectoria de llama débil."},
  {"id":268,"q":"La ausencia de 24 V en la válvula de gas durante una demanda de calefacción (con una válvula en buen estado) apunta a un problema:","opts":["En el condensador","Aguas arriba en el circuito de control (tablero, límite, sensor de llama, transformador)","En el circuito de refrigerante","En el ducto"],"re":"Si la bobina de la válvula está en buen estado pero no recibe 24 V durante una demanda, rastree aguas arriba — límite/rollout abierto, tablero con falla, sin prueba de llama, o problema de transformador/fusible."},
  {"id":269,"q":"En enfriamiento, una baja presión de succión junto con una alta presión de cabeza muy probablemente indica:","opts":["Baja carga","Solo filtro sucio","Sobrecarga","Una restricción en la línea de líquido o el dispositivo dosificador"],"re":"Una restricción acumula el refrigerante (alta presión de cabeza) mientras deja hambriento al evaporador (baja succión); busque un secador obstruido o un dispositivo dosificador atascado."},
  {"id":270,"q":"En enfriamiento, una alta presión de succión junto con una alta presión de cabeza sugiere:","opts":["Bajo flujo de aire en el evaporador","Una TXV cerrada","Carga insuficiente o restricción","Sobrecarga, un condensador sucio/bloqueado o carga excesiva"],"re":"Ambas presiones altas apuntan a demasiado refrigerante, un mal rechazo de calor del condensador (bobina sucia/ventilador con falla) o una carga muy alta."},
  {"id":271,"q":"En enfriamiento, una alta presión de succión con una baja presión de cabeza con mayor frecuencia indica:","opts":["Sobrecarga","Un compresor ineficiente (válvulas desgastadas)","Condensador sucio","Una restricción"],"re":"Cuando el compresor no puede bombear eficazmente, la succión se mantiene alta y la presión de cabeza baja — la firma clásica de un compresor ineficiente/de válvulas desgastadas."},
  {"id":272,"q":"Una válvula reversible que zumba pero no cambia puede deberse a:","opts":["Un filtro limpio","Baja carga de refrigerante (diferencial de presión insuficiente) o un solenoide con falla","Un termostato nuevo","Alto flujo de aire"],"re":"La válvula necesita una diferencia de presión adecuada para cambiar; una carga baja o una bobina de solenoide con falla/corredera atascada puede dejarla zumbando sin cambiar de modo."},
  {"id":273,"q":"Una bomba de calor con poca carga en modo calefacción normalmente muestra:","opts":["Ningún síntoma","Solo alta presión de cabeza","Alta succión, alta capacidad","Baja presión de succión, capacidad de calefacción reducida y posible formación de hielo en la bobina exterior"],"re":"La carga insuficiente en calefacción deja hambrienta a la bobina exterior (evaporador): baja succión, salida de calor débil y escarcha/hielo anormal."},
  {"id":274,"q":"Un fusible de control (bajo voltaje) de 24 V que se quema repetidamente con mayor frecuencia indica:","opts":["Un cortocircuito a tierra en el termostato/cableado de control","Alta presión de cabeza","Un filtro sucio","Una fuga de refrigerante"],"re":"Un cable de bajo voltaje a tierra/en cortocircuito (p. ej., un cable de termostato rozado) toma corriente excesiva y quema el fusible de control; inspeccione y aísle el cableado."},
  {"id":275,"q":"Una bobina de condensador sucia en enfriamiento normalmente causa:","opts":["Alta presión de cabeza, alta temperatura de descarga y mayor consumo de amperes","Mejor eficiencia","Baja presión de cabeza","Solo baja succión"],"re":"El flujo de aire restringido del condensador reduce el rechazo de calor, elevando la presión de cabeza, la temperatura de descarga y la corriente — con un enfriamiento deficiente y posibles disparos por alta presión."},
  {"id":276,"q":"Después de descongelar una bobina de evaporador congelada, el técnico debe:","opts":["Encontrar y corregir la causa (bajo flujo de aire o baja carga) antes de volver a poner en servicio","Reemplazar el compresor","Recargar de inmediato","Agregar aceite"],"re":"Descongelar solo restablece el flujo temporalmente; a menos que se corrija la restricción de flujo de aire o la carga insuficiente, la bobina se volverá a congelar."},
  {"id":277,"q":"El chasquido del contactor (entrada/salida rápida) comúnmente es causado por:","opts":["Alto SEER","Sobrecarga","Bajo voltaje de control o un transformador débil/conexión floja","Condensador sucio"],"re":"Si la bobina no puede mantenerse (bajo 24 V, transformador débil, conexión floja/de alta resistencia), el contactor chasquea; corrija el voltaje/conexión de control."},
  {"id":278,"q":"Una prueba de fuga de presión estática (con nitrógeno seco) confirma la hermeticidad al:","opts":["Presurizar y observar una caída de presión en el tiempo (corregida por temperatura)","Hacer vacío","Agregar refrigerante","Medir el sobrecalentamiento"],"re":"Después de presurizar con nitrógeno, una presión mantenida (considerando el cambio de temperatura) indica que no hay fuga; una caída revela una para localizarla con jabón/detector."},
  {"id":279,"q":"Cal/OSHA (Título 8) requiere que todo empleador establezca por escrito un:","opts":["Plan de marketing","Programa de Prevención de Lesiones y Enfermedades (IIPP)","Reporte de SEER","Solo un registro de refrigerante"],"re":"Los empleadores de California deben tener un IIPP por escrito que cubra la identificación de peligros, capacitación, inspecciones y corrección de condiciones inseguras."},
  {"id":280,"q":"El estándar de Comunicación de Peligros (GHS) requiere que los productos químicos peligrosos en un sitio de trabajo tengan:","opts":["Ningún etiquetado","Una patente","Etiquetas adecuadas y Hojas de Datos de Seguridad (SDS) accesibles","Solo una etiqueta de precio"],"re":"HazCom/GHS requiere etiquetas estandarizadas y SDS para que los trabajadores conozcan los peligros, el manejo seguro y los primeros auxilios de los químicos con los que puedan tener contacto."},
  {"id":281,"q":"Según las reglas de la EPA, el refrigerante recuperado que será reutilizado por un propietario diferente generalmente debe ser:","opts":["Ventilado","Reclamado a estándares de pureza (o reciclado en sitio para el mismo propietario)","Quemado","Mezclado con aceite"],"re":"El refrigerante que cambia de propietario debe ser reclamado a la pureza AHRI-700 por un reclamador certificado; el reciclaje en sitio se limita al equipo del mismo propietario."},
  {"id":282,"q":"El oxígeno nunca debe usarse para presurizar un sistema de refrigeración porque:","opts":["Puede reaccionar explosivamente con el aceite del compresor","Es demasiado pesado","Es demasiado caro","Congela las líneas"],"re":"El oxígeno bajo presión puede combustionar violentamente con los aceites de hidrocarburos; solo se usa nitrógeno seco para las pruebas de presión/fugas."},
  {"id":283,"q":"Un aparato con un intercambiador de calor agrietado conocido debe ser:","opts":["Dejado tal como está","Operado a mayor presión de gas","Apagado y etiquetado con rojo (red-tagged) hasta su reparación/reemplazo","Operado con más flujo de aire"],"re":"Un intercambiador de calor agrietado puede filtrar CO al aire de suministro; el aparato debe apagarse (red-tagged) hasta que el intercambiador de calor se repare o reemplace."},
  {"id":284,"q":"Una alarma de CO y una prueba de combustión protegen a los ocupantes porque el envenenamiento por monóxido de carbono causa primero:","opts":["Sarpullido en la piel","Mejor respiración","Ruido fuerte","Dolor de cabeza, náuseas y mareos (a menudo confundidos con gripe)"],"re":"Los primeros síntomas del CO son dolor de cabeza, náuseas, mareos y fatiga; como el CO es inodoro, las alarmas y la prueba de combustión son salvaguardas esenciales."},
  {"id":285,"q":"El aislamiento de tubería o ducto en un edificio construido antes de aproximadamente 1980 puede contener asbesto, por lo que el técnico debe:","opts":["Cortarlo libremente","Aspirarlo con una aspiradora de taller","Quemarlo","No perturbarlo y usar un contratista de remediación certificado si se requiere su remoción"],"re":"Perturbar el asbesto libera fibras peligrosas; los materiales sospechosos en edificios antiguos deben dejarse intactos y ser manejados solo por profesionales de remediación certificados."},
  {"id":286,"q":"Después de una salpicadura química en los ojos, una estación de lavado de ojos de emergencia debe enjuagar los ojos durante al menos aproximadamente:","opts":["1 minuto","15 minutos","No se necesita enjuague","10 segundos"],"re":"La práctica estándar es enjuagar los ojos/piel afectados durante ~15 minutos y buscar atención médica; consulte la SDS del químico para detalles específicos."},
  {"id":287,"q":"El método 'PASS' para usar un extintor de incendios portátil significa:","opts":["Push, Add, Stop, Spray (Empujar, Agregar, Detener, Rociar)","Pull, Aim, Squeeze, Sweep (Jalar, Apuntar, Apretar, Barrer)","Press, Alarm, Shut, Step (Presionar, Alarmar, Cerrar, Pisar)","Pump, Adjust, Set, Slide (Bombear, Ajustar, Fijar, Deslizar)"],"re":"PASS = Pull (jalar el pasador), Aim (apuntar a la base del fuego), Squeeze (apretar la manija), Sweep (barrer de lado a lado) — solo en un fuego pequeño y contenido con una salida detrás de usted."},
  {"id":288,"q":"Realizar trabajo en caliente (soldadura con bronce/corte) cerca de combustibles requiere:","opts":["Ninguna precaución","Más refrigerante","Mayor voltaje","Una vigilancia de incendios y un extintor presente, con los combustibles retirados/protegidos"],"re":"El trabajo en caliente requiere el área despejada o protegida, un extintor a la mano y una vigilancia de incendios durante y después del trabajo para detectar una ignición latente."},
  {"id":289,"q":"El bloqueo/etiquetado (lockout/tagout) se aplica a un soplador o equipo rotativo antes del servicio para:","opts":["Reducir la presión estática","Evitar un arranque inesperado que pudiera lesionar al técnico","Agregar refrigerante","Aumentar el flujo de aire"],"re":"El LOTO desenergiza y asegura el equipo para que no pueda arrancar inesperadamente (p. ej., ante una demanda del termostato) mientras las manos están cerca de las partes móviles."},
  {"id":290,"q":"Las guardas de bandas y poleas en los manejadores de aire se requieren para:","opts":["Evitar el enredo y las lesiones por contacto con las partes móviles","Contener refrigerante","Reducir el voltaje","Mejorar el flujo de aire"],"re":"El resguardo de máquinas mantiene las manos, la ropa y las herramientas fuera de las bandas/poleas rotativas; nunca opere el equipo con las guardas retiradas."},
  {"id":291,"q":"Al probar la atmósfera de un espacio confinado, el orden correcto para hacer las pruebas es:","opts":["Tóxicos, luego oxígeno, luego inflamables","Oxígeno primero, luego gases inflamables, luego tóxicos","El orden no importa","Inflamables primero, luego oxígeno"],"re":"Pruebe el oxígeno primero (para que las lecturas de inflamables/tóxicos sean válidas), luego los gases inflamables, luego los gases tóxicos — antes de entrar y de forma continua según se requiera."},
  {"id":292,"q":"En la entrada a un espacio confinado que requiere permiso, la función del vigilante (attendant) es:","opts":["Hacer funcionar el compresor","Entrar y trabajar al lado","Permanecer afuera, monitorear las condiciones y mantener la comunicación con quien entra","Probar el refrigerante"],"re":"El vigilante permanece afuera, está atento a los peligros, mantiene la comunicación e inicia los procedimientos de rescate — sin entrar nunca a intentar un rescate por su cuenta."},
  {"id":293,"q":"Los cables de extensión usados para herramientas eléctricas en un sitio de trabajo deben:","opts":["Estar calificados para la carga e inspeccionados por daños; con protección GFCI en exteriores/áreas húmedas","Pasarse por el agua","Conectarse en cadena para alargarse","Empalmarse con cinta"],"re":"Use cables sin daños, debidamente calificados, evite la conexión en cadena y proporcione protección GFCI en lugares húmedos/exteriores para evitar choques e incendios."},
  {"id":294,"q":"Para el trabajo eléctrico energizado que no se puede evitar, la NFPA 70E requiere:","opts":["Ningún equipo especial","Mantener los límites de arco eléctrico y usar EPP con clasificación de arco","Solo guantes de algodón","Trabajar más rápido"],"re":"Cuando desenergizar no es factible, la 70E requiere una evaluación de riesgo, límites de aproximación/arco eléctrico y EPP con clasificación de arco acorde a la energía incidente."},
  {"id":295,"q":"Respirar una alta concentración de vapor de refrigerante en un área cerrada es peligroso porque puede causar:","opts":["Mareos, privación de oxígeno e incluso sensibilización cardíaca","Mejor enfriamiento","Un olor agradable","Mayor estado de alerta"],"re":"Las altas concentraciones de refrigerante desplazan el oxígeno y pueden sensibilizar el corazón a la arritmia; salga del área, ventile y nunca trabaje en una fuga sin ventilación."},
  {"id":296,"q":"Antes de desarmar una unidad, los capacitores deben descargarse porque:","opts":["Pueden almacenar una carga eléctrica peligrosa después de quitar la energía","Contienen refrigerante","Siempre es seguro tocarlos","Contienen aceite"],"re":"Los capacitores de marcha/arranque retienen una carga que puede provocar un choque; descárguelos a través de una resistencia adecuada (no con un cortocircuito directo) antes de manipular las terminales."},
  {"id":297,"q":"Un respirador usado para un peligro de polvo o vapor debe:","opts":["Estar hecho solo de tela","Ser opcional en todos los casos","Estar seleccionado para el peligro específico y con prueba de ajuste adecuada","Ser cualquier mascarilla"],"re":"La protección respiratoria debe coincidir con el contaminante (p. ej., N95 vs cartucho), y los respiradores de ajuste hermético requieren prueba de ajuste y un programa por escrito."},
  {"id":298,"q":"Trabajar desde un elevador aéreo o andamio requiere:","opts":["Solo un trabajador sin verificaciones","Retirar las barandillas","Ninguna capacitación","Protección contra caídas y operación capacitada/autorizada"],"re":"Los elevadores aéreos y andamios requieren operadores capacitados, inspecciones, protección contra caídas (p. ej., arnés en un elevador de pluma) y cumplimiento de los límites de capacidad."},
  {"id":299,"q":"Para soplar residuos de una línea o componente, un técnico debe usar:","opts":["Oxígeno puro","Refrigerante del sistema ventilado a la atmósfera","Acetileno comprimido","Nitrógeno seco (nunca refrigerante ni oxígeno)"],"re":"Use nitrógeno seco regulado para purgar/soplar líneas; ventilar refrigerante es ilegal y el oxígeno es peligrosamente reactivo con los aceites."},
  {"id":300,"q":"Si un control de seguridad (límite, interruptor de presión, rollout) sigue disparándose, el técnico debe:","opts":["Puentearlo y continuar","Retirar el control","Aumentar la presión de gas","Encontrar y corregir la causa subyacente, nunca puentear la seguridad"],"re":"Los disparos repetidos señalan un peligro real (sobrecalentamiento, chimenea bloqueada, alta presión); diagnostique y corrija la causa — puentear una seguridad puede causar incendio, CO o daño al equipo."},
  {"id":301,"q":"La transferencia de calor por contacto directo entre las moleculas de un solido se llama:","opts":["Infiltracion","Radiacion","Conduccion","Conveccion"],"re":"La conduccion es el calor que se mueve a traves de un material por contacto molecular; la conveccion mueve el calor por el movimiento de un fluido; la radiacion transfiere el calor como ondas electromagneticas sin necesidad de un medio."},
  {"id":302,"q":"La formula de calor total (entalpia) para una carga de aire acondicionado utiliza la constante:","opts":["1.08","0.68","4.5","3.41"],"re":"Calor total (BTU/h) = 4.5 x CFM x cambio de entalpia (delta-h, BTU/lb). 1.08 es sensible, 0.68 es latente, 3.41 convierte watts a BTU/h."},
  {"id":303,"q":"La formula de carga de calor latente utiliza la constante 0.68 multiplicada por los CFM y el cambio en:","opts":["Voltaje","Granos de humedad (relacion de humedad)","Temperatura de bulbo seco","Velocidad"],"re":"Calor latente (BTU/h) = 0.68 x CFM x cambio en granos de humedad por libra de aire. Toma en cuenta la eliminacion de humedad (latente), no el cambio de temperatura."},
  {"id":304,"q":"El factor U de un ensamblaje de edificio se relaciona con su valor R mediante:","opts":["U = R + 1","U = R","U = 1 / R","U = R al cuadrado"],"re":"El factor U es el reciproco del valor R total (U = 1/R). Un valor R mas alto significa un factor U mas bajo, lo que significa menor transferencia de calor a traves del ensamblaje."},
  {"id":305,"q":"El Coeficiente de Ganancia de Calor Solar (SHGC) de una ventana describe:","opts":["La fraccion de radiacion solar que admite como calor","Solo su color","Su peso","Su espesor"],"re":"El SHGC es la fraccion de energia solar incidente que se transmite como calor; un SHGC mas bajo reduce la carga de enfriamiento del vidrio expuesto al sol."},
  {"id":306,"q":"Para convertir una carga electrica de iluminacion en watts a ganancia de calor en BTU/h, multiplique los watts por:","opts":["1.08","4.5","3.41","0.293"],"re":"1 watt = 3.41 BTU/h. Las cargas de iluminacion y de tomacorrientes agregan calor sensible al calculo de enfriamiento con esta conversion."},
  {"id":307,"q":"En un calculo de carga, cada ocupante normalmente se cuenta como aporte de:","opts":["Solo calor latente","Nada de calor","Solo calor sensible","Calor sensible y latente a la vez"],"re":"Las personas agregan calor sensible (calor corporal) y calor latente (respiracion/transpiracion); las tablas del Manual J dan valores por persona segun el nivel de actividad."},
  {"id":308,"q":"Los cambios de aire por hora (ACH) son una forma de expresar:","opts":["La velocidad del compresor","La tasa de infiltracion/ventilacion de un espacio","El calibre del ducto","El flujo de refrigerante"],"re":"ACH = cuantas veces se reemplaza el volumen de aire de un espacio por hora; se usa para estimar las cargas de infiltracion y ventilacion."},
  {"id":309,"q":"En un sistema de ductos, la presion total es igual a la presion estatica mas:","opts":["La presion atmosferica","La presion del gas","La presion de velocidad","La presion del refrigerante"],"re":"Presion total = presion estatica + presion de velocidad. La estatica actua en todas las direcciones; la presion de velocidad se relaciona con el movimiento del aire (y siempre es positiva en la direccion del flujo)."},
  {"id":310,"q":"Una alta relacion de aspecto en un ducto (ducto rectangular muy ancho y plano) por lo general:","opts":["Elimina la necesidad de sellado","No tiene efecto","Aumenta la perdida por friccion y el material/costo para la misma area","Reduce la friccion"],"re":"Para una misma area de seccion transversal, una alta relacion de aspecto aumenta el area superficial y la friccion, elevando la presion estatica y el costo de la lamina; los ductos casi cuadrados son mas eficientes."},
  {"id":311,"q":"El Manual T (ACCA) trata sobre la seleccion y ubicacion de:","opts":["Dispositivos de distribucion de aire (registros, rejillas, difusores)","Tuberia de gas","Compresores","Refrigerante"],"re":"El Manual T cubre la distribucion de aire: la seleccion de registros/difusores de suministro y rejillas de retorno para lograr el alcance (throw), la dispersion (spread) y el ruido (NC) adecuados con el flujo de aire de diseno."},
  {"id":312,"q":"Una prueba de fuga de ductos reportada como 'CFM25' mide la fuga a una presion de referencia de:","opts":["25 micrones","25 pulgadas WC","25 Pascales","25 psig"],"re":"La fuga de ductos se mide con el sistema presurizado a 25 Pascales; CFM25 es el flujo de aire de fuga a esa referencia, usado para la verificacion de codigo/HERS."},
  {"id":313,"q":"Un sistema de ductos de plenum extendido se diferencia de un sistema radial en que:","opts":["No tiene tronco principal","Usa un tronco principal de tamano constante con derivaciones de ramales","No se puede usar en viviendas","No necesita registros"],"re":"Un plenum extendido usa un tronco principal de tamano constante que alimenta los ramales; un tronco de plenum reductor disminuye de tamano en pasos; los sistemas radiales llevan los ramales directamente desde el manejador de aire."},
  {"id":314,"q":"La longitud equivalente (EL) de un accesorio de ducto se usa en el diseno para:","opts":["Medir el refrigerante","Ajustar la presion del gas","Tomar en cuenta la friccion del accesorio como una longitud adicional de ducto recto","Dimensionar el breaker"],"re":"Cada codo, derivacion o bota agrega una resistencia igual a una longitud de ducto recto; la longitud efectiva total = longitud recta medida + suma de las longitudes equivalentes de los accesorios."},
  {"id":315,"q":"En California, un reemplazo residencial con permiso comunmente activa la verificacion HERS del Titulo 24 de:","opts":["La cuenta de TikTok","La marca del termostato","La carga de refrigerante, el flujo de aire y la fuga de ductos","El color de la pintura"],"re":"El Codigo de Energia de California (Titulo 24) a menudo requiere que un evaluador HERS independiente verifique la carga de refrigerante/flujo de aire del ventilador y la fuga de ductos en las alteraciones, segun la medida."},
  {"id":316,"q":"La 'diversidad' en un calculo de carga comercial toma en cuenta el hecho de que:","opts":["Todas las cargas llegan a su pico al mismo tiempo","Los ductos tienen fugas","El refrigerante varia","No todas las cargas (personas, luces, equipos) llegan a su pico simultaneamente"],"re":"La diversidad reduce el pico calculado porque las cargas de ocupacion, iluminacion y equipos rara vez alcanzan su maximo en el mismo momento, evitando el sobredimensionamiento."},
  {"id":317,"q":"Una regla empirica de 'pies cuadrados por tonelada' para dimensionar el aire acondicionado es:","opts":["Usada para dimensionar el gas","Una estimacion aproximada que a menudo sobredimensiona el equipo","Requerida por el codigo","Mas precisa que el Manual J"],"re":"Las reglas empiricas (por ejemplo, 500-600 pies cuadrados/tonelada) ignoran el aislamiento, las ventanas y la orientacion y por lo general sobredimensionan; un calculo del Manual J es el metodo correcto."},
  {"id":318,"q":"Para lograr un margen bruto del 40%, un trabajo con un costo de $600 debe cotizarse en:","opts":["$660","$840","$1000","$960"],"re":"El margen es la ganancia como porcentaje del precio: precio = costo / (1 - margen) = 600 / 0.60 = $1000. (Un sobreprecio del 40% sobre el costo solo seria $840.)"},
  {"id":319,"q":"El recargo laboral (labor burden) agregado al salario base de un trabajador incluye:","opts":["Impuestos sobre la nomina, compensacion al trabajador y prestaciones","Cuotas de permisos","Costo de materiales","Solo el salario por hora"],"re":"El recargo laboral es el costo adicional sobre los salarios - impuestos patronales sobre la nomina, compensacion al trabajador, seguros y prestaciones - y debe estar incluido en la tarifa de mano de obra estimada."},
  {"id":320,"q":"Un conducto de humos/chimenea para un aparato atmosferico se dimensiona principalmente segun la entrada del aparato (BTU/h) y:","opts":["La altura del venteo y la configuracion del conector","El tipo de refrigerante","El color del ducto","El calibre del cable"],"re":"Las tablas de ventilacion dimensionan el conducto de humos a partir de la entrada total, la altura del venteo, la longitud lateral y el numero de conectores para que el aparato ventee con seguridad (segun las tablas de ventilacion/codigo)."},
  {"id":321,"q":"La 'temperatura de diseno' usada para el dimensionamiento debe provenir de:","opts":["Datos de diseno publicados de ASHRAE/Manual J para la ubicacion","Una suposicion","El ajuste del termostato","El dia mas caluroso/frio jamas registrado"],"re":"Use las temperaturas de diseno publicadas de ASHRAE al 1%/99% de la ubicacion (en el Manual J), no los extremos historicos, para evitar el sobredimensionamiento cronico."},
  {"id":322,"q":"El aire de ventilacion (exterior) requerido para un espacio comercial generalmente se basa en la ocupacion y:","opts":["El area de piso / categoria de uso segun el codigo (por ejemplo, ASHRAE 62.1)","La carga de refrigerante","El tamano del compresor","El color del ducto"],"re":"ASHRAE 62.1 establece las tasas de aire exterior a partir de las personas (cfm/persona) mas el area (cfm/pie cuadrado) por categoria de ocupacion para mantener la calidad del aire interior."},
  {"id":323,"q":"Los grados-dia de calefaccion (HDD) se usan para estimar:","opts":["El consumo de energia de calefaccion estacional","El tamano del ducto","La carga pico de enfriamiento","La carga de refrigerante"],"re":"Los grados-dia suman cuanto caen las temperaturas promedio diarias por debajo de una base (por ejemplo, 65F); los HDD estiman el consumo de energia/combustible de calefaccion estacional, no el dimensionamiento pico."},
  {"id":324,"q":"Cuando se especifican dos etapas de enfriamiento, la seleccion del equipo debe asegurar que la primera etapa:","opts":["Maneje las condiciones de carga parcial de manera eficiente para un mejor confort/control de humedad","Cubra toda la carga pico","Funcione solo en invierno","Este sobredimensionada"],"re":"El equipo de dos etapas (o variable) funciona a baja capacidad la mayor parte del tiempo, mejorando el tiempo de funcionamiento, la deshumidificacion y el confort; la capacidad total se reserva para los extremos de diseno."},
  {"id":325,"q":"Un diseno de ductos con tronco reductor (plenum reductor) mantiene la velocidad del aire mas constante al:","opts":["Agregar refrigerante","Mantener el tronco de un solo tamano","Disminuir el tamano del tronco en pasos despues de las derivaciones de ramales","Eliminar todos los ramales"],"re":"A medida que los ramales extraen aire, un tronco reductor disminuye de tamano en pasos para mantener la velocidad y la presion estatica balanceada a lo largo del recorrido."},
  {"id":326,"q":"Para un line set largo, la linea de liquido se dimensiona mas pequena que la linea de succion principalmente para:","opts":["Solo ahorrar dinero","Reducir el subenfriamiento","Mantener la velocidad del refrigerante y minimizar la carga en la linea de liquido","Aumentar el ruido"],"re":"El refrigerante liquido es denso, por lo que una linea de liquido mas pequena mantiene una velocidad adecuada y limita la carga adicional; la linea de succion (vapor) es mas grande para limitar la caida de presion."},
  {"id":327,"q":"Cuando el line set excede la longitud de la carga de fabrica, el tecnico debe:","opts":["Agregar nitrogeno","Agregar refrigerante segun el ajuste por pie del fabricante","Ignorarlo","Quitar refrigerante"],"re":"Los fabricantes precargan para una longitud de linea determinada; mas alla de esa longitud, agregue refrigerante segun la cantidad especificada por cada pie adicional de linea de liquido."},
  {"id":328,"q":"La carga por peso (usando una bascula) es el metodo mas preciso cuando:","opts":["Se hace una revision rapida","Se completa la carga por una fuga","Se adivina","Se instala un sistema con una carga total conocida o un mini-split"],"re":"La carga por peso hasta el total de la placa de datos (ajustada por la longitud de la linea) es la mas precisa en sistemas evacuados e instalaciones sin ductos donde se conoce la carga total."},
  {"id":329,"q":"Retirar los nucleos de las valvulas Schrader durante la evacuacion:","opts":["Agrega humedad","Retrasa la evacuacion","Nunca esta permitido","Acelera la evacuacion al eliminar una restriccion de flujo"],"re":"Los nucleos Schrader restringen la conductancia; usar una herramienta para retirar nucleos acelera enormemente la evacuacion profunda. Reinstale los nucleos antes de cargar."},
  {"id":330,"q":"El aceite de la bomba de vacio debe cambiarse:","opts":["Solo cuando tiene fugas","Nunca","Con regularidad, porque la humedad/contaminantes lo degradan y reducen la profundidad del vacio","Solo anualmente sin importar nada"],"re":"El aceite de bomba contaminado no puede alcanzar un vacio profundo; cambielo con frecuencia (especialmente despues de sistemas humedos) para mantener la bomba jalando por debajo de 500 micrones."},
  {"id":331,"q":"Una presion tipica de prueba de fuga (estatica) para un sistema R-410A usando nitrogeno seco esta en el rango de aproximadamente:","opts":["2000 psig","0 psig","Varios cientos de psig segun la clasificacion de prueba del equipo","10-15 psig"],"re":"Pruebe la presion con nitrogeno seco hasta la presion de prueba especificada por el fabricante (a menudo unos pocos cientos de psig para equipos R-410A); nunca exceda las clasificaciones de los componentes, y nunca use oxigeno."},
  {"id":332,"q":"Soldar con laton (brazing) cobre a un componente de acero o laton (metales disimiles) requiere:","opts":["Nunca usar fundente","Agua simple","Una aleacion de plata (BAg) con el fundente adecuado","Solo soldadura blanda"],"re":"Las uniones de cobre a acero/laton necesitan fundente y un material de aporte con plata (BAg); el BCuP autofundente solo es para cobre a cobre."},
  {"id":333,"q":"Las almohadillas de aislamiento de vibracion se colocan debajo de un condensador exterior para:","opts":["Aumentar el flujo de aire","Agregar refrigerante","Reducir el ruido/vibracion transmitidos y proteger la losa/conexiones","Elevar el SEER"],"re":"Las almohadillas de aislamiento amortiguan la vibracion del compresor, reduciendo el ruido y disminuyendo la fatiga en las conexiones de las lineas y la superficie de montaje."},
  {"id":334,"q":"Una charola de drenaje auxiliar (secundaria) debajo de un manejador de aire en el atico se requiere para:","opts":["Mejorar el flujo de aire","Sostener la unidad","Contener refrigerante","Capturar el desborde de condensado y proteger el techo de abajo"],"re":"El equipo que esta sobre un espacio acabado necesita una charola secundaria (con su propio drenaje o interruptor de flotador) para capturar el desborde si el drenaje primario se obstruye."},
  {"id":335,"q":"Un termostato debe ubicarse:","opts":["Sobre una fuente de calor","En una pared interior alejada de corrientes de aire, registros de suministro y luz solar","En una pared exterior bajo luz solar directa","Dentro de un closet"],"re":"Monte el termostato a unos 5 pies de altura en una pared interior en una ubicacion representativa, alejado de corrientes de aire, aire de suministro, sol y fuentes de calor, para una deteccion precisa."},
  {"id":336,"q":"Un termostato moderno Wi-Fi/inteligente generalmente requiere un cable 'C' para:","opts":["Proporcionar el comun continuo de 24 V para la alimentacion","Solicitar calefaccion","Abrir la valvula de gas","Hacer funcionar el compresor"],"re":"Los termostatos inteligentes consumen energia de forma continua; el cable C (comun) completa el circuito de 24 V para que el termostato funcione sin 'robo de energia' (power stealing) que puede causar fallas."},
  {"id":337,"q":"En un termostato de bomba de calor, la terminal 'E' controla:","opts":["El ventilador del evaporador","El calor de emergencia (auxiliar)","El economizador","El escape"],"re":"La E energiza el calor de emergencia (normalmente resistencias electricas) directamente, omitiendo el compresor; se usa si la bomba de calor falla o en modo de calor de emergencia."},
  {"id":338,"q":"Se necesita un espacio libre de servicio adecuado alrededor de un condensador exterior para:","opts":["Reducir el calibre del cable","Permitir el flujo de aire a traves del serpentin y espacio para dar servicio a la unidad","Contener refrigerante","Aumentar la clasificacion SEER"],"re":"Los fabricantes especifican espacios libres minimos para que el condensador reciba flujo de aire adecuado (evitando alta presion de descarga) y la unidad pueda recibir servicio de manera segura."},
  {"id":339,"q":"Las tomas de velocidad del soplador a menudo se ajustan de manera diferente para calefaccion y enfriamiento porque:","opts":["El refrigerante es diferente","El termostato lo requiere","El voltaje cambia","El enfriamiento necesita mayor flujo de aire por tonelada y la calefaccion necesita una elevacion de temperatura adecuada"],"re":"El enfriamiento normalmente usa ~400 CFM/tonelada; el flujo de aire de calefaccion se ajusta para mantener la elevacion de temperatura del horno dentro del rango nominal, por lo que las tomas suelen ser diferentes."},
  {"id":340,"q":"Convertir un horno de gas natural a LP (propano) requiere:","opts":["Ningun cambio","Agregar refrigerante","Cambiar los orificios del quemador y ajustar la presion del gas segun el kit","Reemplazar el soplador"],"re":"El LP tiene mayor valor calorifico y presion, por lo que se requiere un kit de conversion con orificios/inyectores mas pequenos y un ajuste de la presion del multiple; nunca haga funcionar un horno con un tipo de gas incorrecto."},
  {"id":341,"q":"Las aberturas de aire de combustion hacia el exterior para un horno en un espacio confinado se dimensionan segun:","opts":["El color del ducto","La carga de refrigerante","La entrada total en BTU/h y el metodo (directo/indirecto) segun el codigo","El SEER"],"re":"El codigo dimensiona las aberturas/ductos de aire de combustion a partir de la entrada total del aparato y de si el aire proviene del interior, del exterior o mediante ductos, asegurando una combustion completa."},
  {"id":342,"q":"Al hacer un abocardado (flare) en un mini-split, usar una llave de torque con el valor especificado evita:","opts":["Un SEER alto","Bajo voltaje","Un apriete insuficiente o excesivo que cause fugas o abocardados agrietados","Exceso de flujo de aire"],"re":"Las tuercas de abocardado de los mini-split tienen valores de torque especificados; muy flojas tienen fugas, muy apretadas agrietan el abocardado. Una llave de torque asegura una union confiable y sin fugas."},
  {"id":343,"q":"El aislamiento de celda cerrada para lineas de refrigerante debe:","opts":["Retirarse en verano","Reemplazarse solo con cinta","Sellarse en las uniones/extremos para evitar la condensacion debajo del aislamiento","Dejarse con las uniones abiertas"],"re":"Las uniones sin sellar dejan que el aire humedo llegue a la linea fria, causando condensacion oculta, goteo y corrosion; pegue/selle todas las uniones y extremos."},
  {"id":344,"q":"Comunmente se requiere un tomacorriente de servicio de 125 V cerca del equipo HVAC de azotea/atico para:","opts":["Cargar refrigerante","Alimentar el compresor","Reemplazar el desconectador","Proporcionar energia de conveniencia para las herramientas de servicio"],"re":"El codigo electrico requiere un tomacorriente de servicio dentro de una distancia determinada del equipo para que los tecnicos puedan alimentar herramientas y luces para el mantenimiento."},
  {"id":345,"q":"Al arrancar un sistema de enfriamiento, un split de temperatura interior normal (bulbo seco de retorno vs suministro) es de aproximadamente:","opts":["Cero","16-22 F","40-50 F","2-5 F"],"re":"Un sistema correctamente cargado con el flujo de aire adecuado normalmente muestra una caida de ~16-22 F a traves del evaporador (varia con el bulbo humedo interior); un valor muy pequeno o muy grande indica problemas de flujo de aire/carga."},
  {"id":346,"q":"Se usa una bomba de condensado cuando:","opts":["El sistema es solo de calefaccion","No hay condensado","El equipo esta por debajo del drenaje y el condensado debe elevarse","El drenaje puede tener pendiente por gravedad"],"re":"Cuando el drenaje por gravedad es imposible (sotano/bajo nivel), una bomba de condensado eleva el agua hasta un drenaje; normalmente tiene un interruptor de seguridad para detener el sistema si falla."},
  {"id":347,"q":"Un 'whip' (conducto flexible hermetico a los liquidos) en el condensador se usa para que:","opts":["La unidad reciba mas refrigerante","El SEER aumente","La vibracion no se transmita al conducto rigido y las conexiones flexionen de forma segura","La linea de gas sea mas corta"],"re":"Un whip flexible corto y hermetico a los liquidos absorbe la vibracion del compresor y permite una conexion flexible y resistente a la intemperie entre el desconectador y la unidad."},
  {"id":348,"q":"Soportar los line sets de refrigerante a intervalos adecuados evita:","opts":["Un SEER alto","Exceso de subenfriamiento","Bajo voltaje","Pandeo, esfuerzo en las uniones y dano por roce/vibracion"],"re":"Las lineas sin soporte se pandean y vibran, esforzando las uniones soldadas y desgastando el aislamiento por roce; asegurelas a intervalos regulares y donde penetren las paredes."},
  {"id":349,"q":"Antes de energizar un sistema recien instalado, el instalador debe verificar que el voltaje de linea este:","opts":["Siempre en 480 V","En cualquier valor","Dentro del rango de voltaje nominal de la unidad en la placa de datos","Por debajo de 24 V"],"re":"Operar fuera del rango de voltaje nominal (por ejemplo, bajo voltaje) causa sobrecalentamiento y falla de componentes; verifique que el voltaje de suministro coincida con la placa de datos antes del arranque."},
  {"id":350,"q":"Al instalar ducto flexible, el forro interior debe:","opts":["Llenarse con refrigerante","Cortarse mas corto de lo necesario","Dejarse suelto y doblado","Estirarse tenso y conectarse/sellarse al collar, con el aislamiento/forro asegurado"],"re":"Jale el nucleo interior tenso sobre el collar, asegurelo con una abrazadera/correa, sellelo, luego jale el aislamiento y el forro de vapor por encima y suncha­los, evitando la compresion y las fugas."},
  {"id":351,"q":"La valvula reversora (reversing valve) de una bomba de calor se energiza mediante:","opts":["Una bobina solenoide de 24 V","La alimentacion de voltaje de linea del compresor","Solo la presion del refrigerante","La valvula de gas"],"re":"El piloto de la valvula reversora se desplaza mediante una bobina solenoide de 24 V; la valvula principal se mueve por el diferencial de presion del refrigerante una vez que cambian los puertos del piloto."},
  {"id":352,"q":"Despues de soldar con laton un nuevo filtro deshidratador, debe instalarse con la flecha:","opts":["No importa","Apuntando en contra del flujo","De lado","Apuntando en la direccion del flujo del refrigerante"],"re":"La flecha del deshidratador debe apuntar en la direccion del flujo (normalmente de la linea de liquido hacia el dispositivo de medicion) para que filtre y seque correctamente."},
  {"id":353,"q":"Cuando no estan involucrados dos serpentines interiores que comparten una unidad exterior de bomba de calor, una linea de succion correctamente dimensionada en un montante alto puede usar un montante doble para:","opts":["Agregar refrigerante","Aumentar el ruido","Mantener el retorno de aceite tanto a capacidad total como reducida","Bajar el SEER"],"re":"En sistemas modulantes con montantes altos, un montante de succion doble (grande + pequeno) mantiene la velocidad lo suficientemente alta para el retorno de aceite a carga parcial, limitando a la vez la caida de presion a plena carga."},
  {"id":354,"q":"Documentar las lecturas de arranque (presiones, temperaturas, sobrecalentamiento/subenfriamiento, presion estatica, amperaje) es importante porque:","opts":["Es ilegal","Es una perdida de tiempo","Verifica el funcionamiento correcto y proporciona una referencia base para el servicio futuro","Anula la garantia"],"re":"Un registro de puesta en marcha comprueba que el sistema se configuro correctamente y da una referencia para diagnosticar problemas futuros y para la documentacion de garantia/HERS."},
  {"id":355,"q":"Un sistema de enfriamiento con un split de temperatura muy pequeno (por ejemplo, 8 F) y presiones normales lo mas probable es que tenga:","opts":["Una valvula reversora atascada","Flujo de aire excesivo o una condicion de carga de humedad","Un intercambiador de calor agrietado","Carga baja"],"re":"Demasiado flujo de aire (o una carga latente muy alta) reduce el split de bulbo seco; revise la velocidad del soplador y las condiciones antes de asumir un problema de refrigerante."},
  {"id":356,"q":"Un motor del ventilador del condensador que falla (se detiene) mientras el compresor funciona causara:","opts":["Una presion de descarga que sube rapidamente y un disparo por alta presion","Mas subenfriamiento","Menor amperaje","Baja presion de descarga"],"re":"Sin flujo de aire en el condensador, el calor no puede rechazarse, por lo que la presion de descarga sube rapidamente y el interruptor de alta presion se dispara (o el compresor se sobrecalienta). Revise el motor del ventilador y su capacitor."},
  {"id":357,"q":"Un solo capacitor de marcha que sirve tanto al compresor como al ventilador del condensador es un capacitor de 'marcha dual'; sus tres terminales estan etiquetadas como:","opts":["C (comun), HERM, FAN","L1, L2, L3","R, S, T","Y, G, W"],"re":"Un capacitor de marcha dual tiene una terminal comun (C) mas las terminales HERM (compresor) y FAN (ventilador); una seccion debil hace que ese motor batalle o se sobrecaliente."},
  {"id":358,"q":"Un soplador ECM que no funciona pero tiene el voltaje de linea correcto y una llamada valida del termostato debe revisarse en cuanto a:","opts":["La senal de control de bajo voltaje y el conector del modulo antes de condenar el motor","La presion del gas","El nivel de refrigerante","El color del ducto"],"re":"Los motores ECM necesitan una senal de control adecuada en el modulo; verifique el comando de 24 V/PWM y las conexiones; una senal faltante imita un motor fallado."},
  {"id":359,"q":"Un interruptor de derrame de flama (flame-rollout) de un horno que se ha disparado normalmente indica:","opts":["Demasiado flujo de aire","Solo un filtro sucio","Refrigerante alto","Un intercambiador de calor o conducto de humos bloqueado que hace que la flama se derrame fuera de la camara de quemadores"],"re":"El derrame se dispara cuando las flamas salen de los quemadores (pasos del intercambiador de calor bloqueados, ventilacion restringida o mala combustion de aire); encuentre y corrija la causa, no solo reinicie."},
  {"id":360,"q":"Una tarjeta de descongelamiento (defrost) atascada de modo que la bomba de calor permanece en descongelamiento demasiado tiempo causara:","opts":["Menor presion de descarga","Ningun efecto","Aire frio en calefaccion y energia desperdiciada al seguir reversando a enfriamiento","Mayor capacidad de calefaccion"],"re":"Un sensor/tarjeta de descongelamiento fallado puede sobre-descongelar, reversando repetidamente a enfriamiento y haciendo funcionar el calor auxiliar, reduciendo la eficiencia y el confort."},
  {"id":361,"q":"Despues de la quemadura de un compresor (burnout), el sistema debe limpiarse, normalmente instalando un:","opts":["Nuevo termostato","Filtro deshidratador para remocion de acido en la linea de succion (y de liquido) y siguiendo el procedimiento de quemadura","Ducto mas grande","Condensador mas grande"],"re":"Una quemadura deja acido y contaminantes; instale deshidratadores de limpieza de acido de succion y de liquido, monitoreelos/reemplacelos, y pruebe la presencia de acido hasta que el sistema este limpio."},
  {"id":362,"q":"Un contactor cuyos contactos se han soldado cerrados causara:","opts":["Solo un fusible quemado","Refrigerante bajo","Que la unidad siga funcionando incluso cuando el termostato esta satisfecho","Que la unidad nunca arranque"],"re":"Los contactos soldados mantienen cerrado el circuito de alto voltaje, por lo que el compresor/condensador funciona continuamente sin importar la llamada de control; reemplace el contactor."},
  {"id":363,"q":"La formacion de escarcha en la linea de succion hasta el compresor normalmente indica:","opts":["Retorno de liquido (bajo sobrecalentamiento) regresando al compresor","Un filtro sucio","Sobrecalentamiento","Alta presion de descarga"],"re":"La escarcha de succion hasta el compresor indica un sobrecalentamiento muy bajo/retorno de liquido; las causas incluyen sobrecarga, una TXV que inunda, o baja carga/flujo de aire; corrija antes de que el compresor se dane."},
  {"id":364,"q":"En un compresor trifasico, un desequilibrio de voltaje significativo entre fases (mas de ~2%) puede causar:","opts":["Exceso de corriente y sobrecalentamiento del motor","Mejor eficiencia","Menor presion de descarga","Mas subenfriamiento"],"re":"El desequilibrio de voltaje produce un desequilibrio de corriente mucho mayor y calentamiento del motor; investigue las conexiones de suministro/la compania electrica, ya que un desequilibrio prolongado acorta la vida del motor."},
  {"id":365,"q":"Un megohmetro (probador de aislamiento) se usa en un motor de compresor para:","opts":["Medir el refrigerante","Detectar la ruptura del aislamiento del devanado a tierra (megado del motor)","Revisar el sobrecalentamiento","Ajustar la presion del gas"],"re":"Un megger aplica alto voltaje de CC para leer la resistencia de aislamiento del devanado a tierra en megaohmios; un valor bajo/en descenso advierte de una falla inminente del motor."},
  {"id":366,"q":"El soplador funciona pero el horno de gas no produce calor. Lo primero que hay que revisar incluye:","opts":["El suministro de gas, la secuencia de encendido y la comprobacion de flama","El subenfriamiento","El color del ducto","La carga de refrigerante"],"re":"La falta de calor con el soplador funcionando apunta al lado del gas/encendido: valvula de gas, encendedor/piloto, sensor de flama, limites, y la secuencia de la tarjeta de control, no al circuito de refrigerante."},
  {"id":367,"q":"Un capacitor que prueba muy por debajo de sus microfaradios nominales causara que un motor:","opts":["Arranque con dificultad, funcione caliente y consuma alto amperaje (o no arranque)","Aumente el SEER","Baje la presion de descarga","Funcione mas frio"],"re":"Un capacitor debil reduce el torque del motor y el desfase, por lo que el motor funciona caliente y con sobreamperaje; reemplacelo con el valor exacto de uF nominal y el voltaje igual o mayor."},
  {"id":368,"q":"Un limite alto (high-limit) que se dispara repetidamente en un horno, con un filtro limpio y los registros abiertos, puede indicar:","opts":["Un motor del soplador/capacitor que esta fallando o un ducto cerrado/bloqueado que reduce el flujo de aire","Una valvula reversora atascada","Bajo subenfriamiento","Sobrecarga"],"re":"Si los filtros y registros estan bien, el bajo flujo de aire puede provenir de un soplador debil (motor/capacitor), una banda patinando o un ducto bloqueado, todo lo cual sobrecalienta el intercambiador de calor y dispara el limite."},
  {"id":369,"q":"Para distinguir una carga baja de refrigerante de un dispositivo de medicion restringido, el tecnico compara:","opts":["El sobrecalentamiento, el subenfriamiento y las presiones en conjunto contra los valores esperados","Solo el voltaje","El calibre del ducto","La marca del termostato"],"re":"La carga baja muestra alto sobrecalentamiento Y bajo subenfriamiento; una restriccion en la linea de liquido a menudo muestra alto subenfriamiento aguas arriba con baja presion del evaporador; leer el conjunto completo los distingue."},
  {"id":370,"q":"Un compresor ruidoso que golpetea al arrancar y muestra escarcha en la succion puede estar experimentando:","opts":["Un SEER alto","Golpeteo de liquido (slugging) por migracion de refrigerante o sobrecarga","Solo bajo voltaje","Funcionamiento normal"],"re":"El golpeteo con escarcha en la succion sugiere liquido entrando al compresor (migracion durante el ciclo de apagado o sobrecarga); un calentador de carter y la carga correcta ayudan a evitar el slugging."},
  {"id":371,"q":"Una revision de mantenimiento encuentra un acercamiento (approach) de mas de 10 F en un condensador limpio en un dia templado; el siguiente paso es:","opts":["Agregar refrigerante a ciegas","Cambiar el termostato","Verificar la carga (subenfriamiento) y el flujo de aire del condensador antes de cualquier correccion","Reemplazar el compresor"],"re":"Diagnostique con mediciones: confirme el subenfriamiento, el flujo de aire y la temperatura ambiente antes de ajustar la carga; nunca agregue refrigerante sin verificar que realmente este baja."},
  {"id":372,"q":"Un filtro de aire sucio que se deja sin cambiar con el tiempo causa de manera mas directa:","opts":["Mayor costo de refrigerante","Mas subenfriamiento","Reduccion del flujo de aire, menor capacidad, y posible congelamiento del serpentin o disparos del limite","Mayor voltaje"],"re":"Un filtro obstruido restringe el flujo de aire, reduciendo la capacidad y la eficiencia; en enfriamiento puede congelar el serpentin, en calefaccion puede disparar el limite; los cambios rutinarios de filtro lo evitan."},
  {"id":373,"q":"Cuando el termostato solicita enfriamiento pero nada funciona, una primera revision logica es:","opts":["El sensor de flama","El subenfriamiento del refrigerante","La fuga de ductos","24 V en la bobina del contactor y el voltaje de linea/desconectador adecuado"],"re":"Rastree el circuito: confirme la energia/desconectador, luego la senal de control de 24 V al contactor; la ausencia de voltaje de control apunta aguas arriba (termostato, transformador, seguridades), no al lado del refrigerante."},
  {"id":374,"q":"Una bomba de calor que da calor debil con baja presion de succion y un serpentin exterior escarchado que no se despeja sugiere:","opts":["Un intercambiador de calor agrietado","Un problema de descongelamiento y/o carga baja en calefaccion","Sobrecarga","Demasiado flujo de aire"],"re":"En calefaccion el serpentin exterior es el evaporador; si el descongelamiento falla o la carga es baja, se acumula hielo y la capacidad de calefaccion cae; revise el control de descongelamiento y la carga."},
  {"id":375,"q":"Durante el mantenimiento, apretar los lugs/terminales electricos es importante porque las conexiones flojas causan:","opts":["Mayor SEER","Menor amperaje","Calor, caida de voltaje y conexiones quemadas/falla de componentes","Mas refrigerante"],"re":"Las conexiones flojas agregan resistencia, generando calor y caida de voltaje que quema las terminales y dana los contactores/cableado; revise y apriete durante el servicio."},
  {"id":376,"q":"Un fusible de control de 24 V que se quema en el instante en que se restablece la energia indica:","opts":["Un ducto en mal estado","Un corto en el cableado de bajo voltaje o un componente en corto (por ejemplo, la bobina del contactor)","Una condicion de refrigerante bajo","Un filtro sucio"],"re":"Un fusible de control que se quema de inmediato significa un corto franco en el circuito de 24 V: cable del termostato desgastado, bobina en corto o cable pellizcado; encuentrelo y corrijalo antes de volver a colocar el fusible."},
  {"id":377,"q":"El mantenimiento anual de un horno de gas debe incluir la limpieza del sensor de flama y:","opts":["Deshabilitar el interruptor de derrame de flama","Quitar el interruptor de limite","Agregar refrigerante","Inspeccionar el intercambiador de calor y verificar la combustion/ventilacion segura"],"re":"El mantenimiento incluye la limpieza del sensor de flama, la inspeccion del intercambiador de calor, la revision de la combustion/ventilacion y la confirmacion de que todas las seguridades funcionan; nunca deshabilite un control de seguridad."},
  {"id":378,"q":"Comparar el amperaje de marcha medido del compresor con la RLA de la placa de datos ayuda a determinar si el compresor esta:","opts":["Del color correcto","Una bomba de calor","Sobrecargado, subdimensionado para las condiciones, u operando normalmente","Sin refrigerante por si solo"],"re":"El amperaje de marcha cercano a la RLA en condiciones de diseno es normal; muy por encima de la RLA sugiere alta presion de descarga/sobrecarga/problemas mecanicos, muy por debajo puede indicar carga baja o descarga (unloading); interpretelo junto con las presiones."},
  {"id":379,"q":"Los cilindros de refrigerante transportados en un vehiculo deben:","opts":["Acostarse de lado cerca del motor","Asegurarse en posicion vertical, con la valvula protegida, en un area ventilada (no en la cabina de pasajeros)","Sueltos en la cabina de pasajeros","Calentarse para generar presion"],"re":"Asegure los cilindros en posicion vertical con las tapas de valvula puestas, en un area de carga ventilada lejos de los ocupantes y del calor, para evitar fugas, rodamientos y peligros de asfixia."},
  {"id":380,"q":"En un espacio confinado que requiere permiso, un nivel de oxigeno seguro generalmente es:","opts":["19.5% a 23.5%","Por encima del 30%","Exactamente 50%","Por debajo del 15%"],"re":"El oxigeno normal/seguro es 19.5-23.5%; por debajo del 19.5% es deficiente en oxigeno (riesgo de asfixia) y por encima del 23.5% es enriquecido en oxigeno (riesgo de incendio). Pruebe antes de entrar."},
  {"id":381,"q":"Los termostatos viejos que contienen un bulbo de mercurio deben:","opts":["Desecharse como residuo universal/peligroso (recuperacion de mercurio)","Tirarse a la basura comun","Quemarse","Enterrarse en el sitio"],"re":"El mercurio es toxico; los termostatos con interruptor de mercurio son residuos universales y deben reciclarse mediante programas aprobados, nunca en vertederos ni incinerados."},
  {"id":382,"q":"Los balastros o capacitores fluorescentes viejos pueden contener PCB, lo que requiere:","opts":["Manejo y eliminacion como residuo peligroso","Eliminacion en la basura comun","Ninguna precaucion","Quemarse en el sitio"],"re":"Los balastros/capacitores que contienen PCB son residuos peligrosos; manejelos para evitar fugas y desechelos a traves de los canales adecuados de residuos peligrosos."},
  {"id":383,"q":"La primera accion cuando alguien esta recibiendo una descarga y no puede soltar un circuito energizado es:","opts":["Esperar y observar","Desenergizar el circuito (cortar la energia) antes de tocarlo","Echarle agua","Jalarlo con las manos descubiertas"],"re":"Nunca toque a una persona en contacto con corriente viva; corte primero la energia/desconectador (o use un medio no conductor), luego pida ayuda y brinde auxilio."},
  {"id":384,"q":"Los primeros auxilios por inhalar una alta concentracion de vapor de refrigerante son:","opts":["Hacer que siga trabajando","Llevar a la persona al aire fresco de inmediato y buscar ayuda medica","Aplicar calor","Darle cafeina a la persona"],"re":"El vapor de refrigerante desplaza el oxigeno y puede causar mareos/asfixia; lleve a la persona al aire fresco de inmediato, vigile la respiracion y obtenga atencion medica segun la SDS."},
  {"id":385,"q":"Un respirador seleccionado para un polvo o vapor especifico debe:","opts":["Ser cualquier mascarilla disponible","Estar acorde al peligro, tener prueba de ajuste y usarse dentro de un programa de proteccion respiratoria","Ser una mascarilla quirurgica","Ser siempre opcional"],"re":"La eleccion del respirador (por ejemplo, N95/P100 para particulas, cartuchos para vapores) debe coincidir con el peligro, tener prueba de ajuste y seguir los requisitos de proteccion respiratoria de Cal/OSHA."},
  {"id":386,"q":"El golpe de calor se diferencia del agotamiento por calor en que el golpe de calor:","opts":["Solo causa sed","No necesita ninguna accion","Es una emergencia medica (temperatura corporal alta, confusion) que requiere enfriamiento inmediato y 911","Es menor"],"re":"El agotamiento por calor (sudoracion intensa, debilidad) es serio; el golpe de calor (piel caliente y seca o confusion, temperatura muy alta) es mortal; enfrie rapidamente y llame al 911 de inmediato."},
  {"id":387,"q":"Bajo la norma de enfermedad por calor de Cal/OSHA, los trabajadores nuevos o que regresan en condiciones de alto calor deben:","opts":["Enviarse solos a la azotea","Negarseles agua","Aclimatarse gradualmente y observarse de cerca","Trabajar a ritmo completo de inmediato"],"re":"La aclimatacion (desarrollar gradualmente la tolerancia al calor durante varios dias) y la observacion cercana de los trabajadores nuevos/que regresan reducen el riesgo de enfermedad por calor durante las olas de calor."},
  {"id":388,"q":"Una escalera de extension usada en el trabajo debe tener una clasificacion de carga (duty rating) que:","opts":["Cumpla o exceda el peso combinado del trabajador mas las herramientas/materiales","No importa","Sea la mas barata disponible","Sea siempre Tipo III"],"re":"Elija una clasificacion de carga de escalera (por ejemplo, Tipo IA = 300 lb) igual o superior a la carga total; sobrecargar una escalera arriesga fallas estructurales y caidas."},
  {"id":389,"q":"Antes de tocar un circuito que cree que esta desenergizado, la practica mas segura es:","opts":["Probar antes de tocar: verificar voltaje cero con un medidor comprobado en una fuente viva conocida","Tocarlo rapidamente","Usar solo guantes","Asumir que esta apagado"],"re":"'Probar antes de tocar' (vivo-muerto-vivo): confirme que su medidor funciona en una fuente viva conocida, verifique que el circuito lea cero, luego vuelva a confirmar el medidor; esto detecta errores de LOTO."},
  {"id":390,"q":"Los extintores portatiles de incendios en un sitio de trabajo deben:","opts":["Ser usados solo por los gerentes","Dejarse vacios","Estar inspeccionados/mantenidos y cargados, con la clase correcta para el peligro","Pintarse de cualquier color"],"re":"Los extintores deben estar accesibles, inspeccionados, totalmente cargados y de la clase correcta (ABC para trabajo general de HVAC cerca de equipos electricos) para ser eficaces."},
  {"id":391,"q":"La proteccion auditiva debe usarse cuando:","opts":["Solo en interiores","Los niveles de ruido son lo suficientemente altos como para requerirla (por ejemplo, cerca de equipos ruidosos/herramientas electricas)","Solo de noche","Nunca en trabajos de HVAC"],"re":"El ruido alto sostenido dana la audicion; use tapones/orejeras cuando trabaje cerca de sopladores, compresores o herramientas electricas ruidosas, segun los limites de exposicion al ruido."},
  {"id":392,"q":"Un cilindro de gas comprimido (refrigerante o nitrogeno) en uso o almacenamiento debe:","opts":["Dejarse en los pasillos","Acostarse de lado sin asegurar","Usarse como rodillo","Asegurarse en posicion vertical (encadenado/sunchado) para que no pueda caerse"],"re":"Los cilindros deben asegurarse en posicion vertical para que no puedan volcarse; un cilindro que cae puede cortar la valvula y convertirse en un proyectil peligroso."},
  {"id":393,"q":"Al cargar o recuperar, un cilindro de recuperacion nunca debe llenarse en exceso porque:","opts":["Agrega humedad","Reduce la eficiencia","Cambia el color","La presion hidrostatica por la expansion del liquido puede romperlo"],"re":"Llenar mas alla del 80% no deja espacio para la expansion del liquido; a medida que sube la temperatura, la presion hidrostatica puede reventar el cilindro; use una bascula y nunca lo llene en exceso."},
  {"id":394,"q":"Antes de realizar trabajo en caliente (brazing) en un edificio ocupado, un tecnico debe:","opts":["Deshabilitar las alarmas de humo permanentemente","Despejar/proteger los combustibles, tener un extintor y una vigilancia de incendios listos","Usar mas fundente","Omitir notificar a alguien"],"re":"El trabajo en caliente requiere retirar o proteger los combustibles, un extintor cargado a la mano, y una vigilancia de incendios durante y despues del trabajo para detectar una ignicion latente."},
  {"id":395,"q":"Debe usarse proteccion ocular clasificada para impacto y para el resplandor del brazing porque:","opts":["Se ve profesional","Las salpicaduras de fundente, el metal caliente y la luz intensa pueden lesionar los ojos desprotegidos","Es solo para los gerentes","Aumenta el SEER"],"re":"El brazing produce resplandor y salpicaduras; los lentes clasificados para impacto/con sombra protegen contra quemaduras, particulas voladoras y luz danina durante la fabricacion."},
  {"id":396,"q":"El Programa escrito de Prevencion de Lesiones y Enfermedades (IIPP) de Cal/OSHA debe incluir:","opts":["Un plan de marketing","Procedimientos de identificacion de peligros, correccion, capacitacion y comunicacion","Precios de refrigerante","Solo un logotipo"],"re":"Todo empleador de California debe mantener un IIPP que identifique y corrija peligros, capacite a los empleados, y documente la comunicacion y la responsabilidad de seguridad."},
  {"id":397,"q":"Una escalera colocada para acceder a una azotea debe extenderse por encima del borde del techo aproximadamente:","opts":["Aproximadamente 3 pies (36 in) para un agarre seguro","0 pulgadas","Debe estar por debajo del borde","10 pies"],"re":"Extienda la escalera ~3 pies por encima del descanso/borde del techo y asegure la parte superior para que el trabajador tenga un agarre estable al subir y bajar."},
  {"id":398,"q":"Al entrar en un atico que puede exceder temperaturas seguras en verano, el tecnico debe:","opts":["Limitar la exposicion, hidratarse, ventilar y vigilar los sintomas de enfermedad por calor","Trabajar el mayor tiempo posible","Usar ropa pesada","Omitir las pausas para tomar agua"],"re":"Los aticos pueden alcanzar un calor peligroso; limite el tiempo, tome pausas para agua/descanso, ventile si es posible, y deten­gase ante los primeros signos de enfermedad por calor."},
  {"id":399,"q":"El refrigerante recuperado y el aceite usado del compresor deben:","opts":["Mezclarse y quemarse","Verterse por un drenaje","Manejarse y desecharse adecuadamente (el aceite como residuo peligroso; el refrigerante recuperado/reciclado)","Ventilarse al exterior"],"re":"Nunca tire refrigerante ni aceite; recupere el refrigerante para su reutilizacion/reciclaje y maneje el aceite usado como residuo peligroso mediante eliminacion/reciclaje aprobados."},
  {"id":400,"q":"El enfoque general mas seguro cuando se encuentra cualquier condicion desconocida o peligrosa en un trabajo es:","opts":["Retirar los dispositivos de seguridad","Proceder rapidamente y confiar en la suerte","Ignorar la seguridad para ahorrar tiempo","Detenerse, evaluar el peligro, seguir la SDS/codigos, y usar el EPP y los procedimientos adecuados"],"re":"Un enfoque de detenerse y evaluar -leyendo la SDS, siguiendo el codigo, y usando el EPP/bloqueo correcto- previene lesiones; la produccion nunca justifica saltarse la seguridad."},
  {"id":401,"q":"Un tecnico utiliza una tabla de presion-temperatura (P-T) para:","opts":["Dimensionar ductos","Encontrar la temperatura de saturacion de un refrigerante a una presion medida","Calcular el calibre del cable","Ajustar la presion del gas"],"re":"Una tabla P-T indica la temperatura de saturacion (ebullicion/condensacion) de cada refrigerante a una presion dada, esencial para calcular el sobrecalentamiento y el subenfriamiento."},
  {"id":402,"q":"La presion absoluta (psia) es igual a la presion manometrica (psig) mas aproximadamente:","opts":["100","14.7","32","0"],"re":"psia = psig + 14.7 (presion atmosferica al nivel del mar). La presion absoluta se usa para trabajos de relacion de compresion y de vacio (micrones)."},
  {"id":403,"q":"La temperatura de saturacion de un refrigerante es la temperatura a la cual este:","opts":["Hierve/condensa (cambia de estado) a una presion dada","Alcanza la temperatura ambiente","Pierde todo el calor","Se congela por completo"],"re":"En la saturacion el refrigerante esta cambiando de estado (liquido<->vapor) a la presion correspondiente; el sobrecalentamiento y el subenfriamiento se miden respecto a esta temperatura."},
  {"id":404,"q":"El calor especifico es la cantidad de calor necesaria para elevar la temperatura de una libra de una sustancia en:","opts":["10 grados","1 grado F","Cualquier cantidad","100 grados"],"re":"El calor especifico es BTU por libra por grado F. El agua es la referencia con 1.0 BTU/lb/F; el aire es aproximadamente 0.24."},
  {"id":405,"q":"Durante un cambio de estado (por ejemplo, la ebullicion), el calor agregado a un refrigerante:","opts":["Cambia su estado a temperatura constante (calor latente)","Se pierde por completo","Reduce su presion","Eleva su temperatura rapidamente"],"re":"El calor latente cambia el estado sin un cambio de temperatura; el calor sensible cambia la temperatura. En el evaporador, la absorcion latente realiza el trabajo de enfriamiento."},
  {"id":406,"q":"El HSPF es una clasificacion que mide, en una bomba de calor, su:","opts":["Eficiencia de enfriamiento","Eficiencia estacional de calefaccion","Carga de refrigerante","Fuga de aire en los ductos"],"re":"El HSPF (Heating Seasonal Performance Factor) clasifica la eficiencia en modo calefaccion durante una temporada; el SEER/SEER2 clasifica el enfriamiento. Un HSPF mas alto significa calefaccion mas eficiente."},
  {"id":407,"q":"Las clasificaciones de eficiencia mas recientes SEER2/EER2 difieren del SEER/EER principalmente porque se prueban a:","opts":["Temperaturas exteriores mas frias","Sin flujo de aire","Una presion estatica externa mas alta (condiciones de ductos mas realistas)","Menor voltaje"],"re":"El SEER2/EER2 (vigente desde 2023) usa una presion estatica externa mas alta en las pruebas para reflejar mejor los sistemas de ductos realmente instalados, por lo que los numeros resultan un poco mas bajos que el antiguo SEER."},
  {"id":408,"q":"Un calefactor (furnace) de gas instalado a gran altitud normalmente debe reducirse en su capacidad (derate) en aproximadamente:","opts":["Cerca de 4% por cada 1000 ft sobre ~2000 ft de elevacion","Sin cambio","Al doble","50% siempre"],"re":"El aire mas delgado a la altitud reduce el aire de combustion; la mayoria de los fabricantes reducen la entrada (input) cerca de 4% por cada 1000 ft sobre 2000 ft (siga la placa de clasificacion/instrucciones del fabricante)."},
  {"id":409,"q":"El metodo de friccion igual (equal-friction) para el diseno de ductos los dimensiona para mantener constante un valor de:","opts":["Temperatura del aire","Presion del refrigerante","Perdida por friccion por cada 100 ft de ducto","Voltaje"],"re":"El diseno de friccion igual mantiene constante la tasa de friccion (por ejemplo, 0.1 in WC por cada 100 ft) en todo el sistema, dimensionando cada seccion a ese objetivo para el CFM requerido."},
  {"id":410,"q":"Se supone que el aire estandar usado en los calculos de HVAC tiene una densidad de aproximadamente:","opts":["14.7 lb/ft3","0.0 lb/ft3","0.075 lb/ft3","1.0 lb/ft3"],"re":"El aire estandar es ~0.075 lb/ft3 (70 F, nivel del mar, 50% RH). Las constantes 1.08 y 4.5 se basan en esto; la gran altitud/temperatura requiere correccion."},
  {"id":411,"q":"Un economizador del lado del aire (air-side economizer) ahorra energia al:","opts":["Usar aire exterior frio para enfriamiento gratuito cuando las condiciones lo permiten","Cerrar todas las compuertas","Encender la calefaccion","Agregar refrigerante"],"re":"Cuando el aire exterior es lo suficientemente frio/seco, un economizador introduce aire del exterior para enfriar el espacio en lugar de operar el compresor, reduciendo el consumo de energia."},
  {"id":412,"q":"Un ERV (ventilador de recuperacion de energia) se utiliza para:","opts":["Reemplazar el calefactor (furnace)","Aumentar la presion de descarga (head pressure)","Recuperar calor (y humedad) del aire de escape para preacondicionar el aire fresco entrante","Agregar refrigerante"],"re":"Un ERV transfiere calor y humedad entre el aire de escape y el de entrada, proporcionando ventilacion de aire fresco mientras reduce la carga de calefaccion/enfriamiento de esa ventilacion."},
  {"id":413,"q":"Se debe proporcionar aire de reposicion (make-up air) cuando un edificio tiene grandes ventiladores de escape con el fin de:","opts":["Aumentar el SEER","Reemplazar el aire extraido y prevenir la presion negativa/contratiro (backdrafting)","Reducir la presion del gas","Agregar refrigerante"],"re":"Sin aire de reposicion, los grandes ventiladores de escape despresurizan el edificio, lo que puede causar contratiro en los aparatos de combustion y atraer aire no acondicionado. Proporcione aire de reposicion balanceado."},
  {"id":414,"q":"Una compuerta de derivacion (bypass damper) en un sistema zonificado se utiliza para:","opts":["Aumentar la carga","Aliviar el exceso de presion de aire cuando solo unas pocas zonas estan activas","Agregar refrigerante","Cerrar la valvula de gas"],"re":"Cuando solo hay zonas pequenas abiertas, una compuerta de derivacion alivia el exceso de flujo de aire para evitar alta presion estatica y ruido, aunque un diseno de zonas adecuado limita su necesidad."},
  {"id":415,"q":"En una vivienda con retornos centrales, se proporciona un corte inferior de puerta (door undercut) o una rejilla de transferencia para que:","opts":["El gas pueda ventilarse","El aire pueda retornar desde las habitaciones cerradas de vuelta al retorno (balance de presion)","Fluya el refrigerante","El ducto se haga mas pequeno"],"re":"Las habitaciones con la puerta cerrada necesitan una trayectoria de retorno (corte inferior/rejilla de transferencia/jump duct); sin ella, el aire de suministro presuriza la habitacion y restringe el flujo de aire de retorno."},
  {"id":416,"q":"Para convertir la potencia electrica en kilovatios a BTU/h, multiplique los kW por aproximadamente:","opts":["12000","3412","100","746"],"re":"1 kW = 3412 BTU/h. Esto convierte los kW de calefaccion electrica o de equipos en salida de calor/carga (por ejemplo, un calentador de resistencia de 5 kW = ~17,060 BTU/h)."},
  {"id":417,"q":"Para la facturacion/dimensionamiento de gas natural, un therm equivale a aproximadamente:","opts":["3412 BTU","100,000 BTU","12,000 BTU","1000 BTU"],"re":"Un therm es 100,000 BTU de energia de gas. Conocer los therms y la lectura del medidor permite a un tecnico relacionar el uso de combustible con la entrada (input) del calefactor."},
  {"id":418,"q":"El EER y el COP se relacionan mediante la expresion:","opts":["EER = COP / 100","EER = COP","EER = COP x 3.412","EER = COP + 12"],"re":"EER (BTU/h por vatio) = COP x 3.412, ya que 1 vatio = 3.412 BTU/h. El COP es la relacion adimensional entre el calor desplazado y la energia consumida."},
  {"id":419,"q":"En el Title 24 de California, un CF1R (Certificado de Cumplimiento) generalmente se completa en la etapa de:","opts":["Venta de la vivienda","Inspeccion final unicamente","Diseno/solicitud del permiso","Demolicion"],"re":"El CF1R documenta que el diseno cumple con el Title 24; el CF2R es el certificado de instalacion del contratista; el CF3R es la verificacion del evaluador HERS, cada uno en su etapa."},
  {"id":420,"q":"El nivel de Criterio de Ruido (NC) importa al seleccionar registros/difusores porque:","opts":["Establece la carga de refrigerante","La alta velocidad del aire a traves de un registro genera ruido molesto","Cambia el voltaje","Dimensiona el interruptor (breaker)"],"re":"Los registros/difusores se seleccionan para que la velocidad frontal se mantenga por debajo del umbral de ruido del espacio (los dormitorios necesitan un NC mas bajo); un flujo de aire sobredimensionado provoca silbidos."},
  {"id":421,"q":"En un clima humedo, disenar para una mejor deshumidificacion a menudo significa seleccionar el flujo de aire hacia el extremo ___ del rango:","opts":["Maximo posible","Cero","Mas alto (450 CFM/ton)","Mas bajo (alrededor de 350 CFM/ton)"],"re":"Un menor flujo de aire por tonelada reduce la temperatura del serpentin y aumenta la eliminacion de humedad (capacidad latente), mejorando el confort en condiciones humedas."},
  {"id":422,"q":"Agregar una contingencia a una cotizacion tiene como fin:","opts":["Garantizar una perdida","Reemplazar el permiso","Cubrir condiciones imprevistas y riesgos para que el trabajo siga siendo rentable","Bajar el precio por debajo del costo"],"re":"Una reserva de contingencia amortigua las sorpresas (condiciones ocultas, cambios de precio); protege el margen sin depender de suposiciones durante el trabajo."},
  {"id":423,"q":"Segun el codigo de energia de California, los ductos en espacios no acondicionados generalmente deben aislarse al menos a aproximadamente:","opts":["R-8","R-30","Sin aislamiento","R-2"],"re":"El Title 24 normalmente requiere alrededor de R-8 de aislamiento de ductos en espacios no acondicionados (aticos) para limitar las perdidas por conduccion; verifique el valor de codigo vigente para la zona climatica."},
  {"id":424,"q":"Un calculo de 'carga en bloque' (block load) difiere de un calculo habitacion por habitacion en que:","opts":["Ignora el clima","Es solo para gas","Dimensiona cada registro","Dimensiona el equipo de todo el edificio pero no el flujo de aire de cada habitacion"],"re":"La carga en bloque da el tamano total del equipo; aun se necesita un calculo habitacion por habitacion (Manual J detallado) para dimensionar los ductos y distribuir el flujo de aire a cada habitacion."},
  {"id":425,"q":"El sobredimensionamiento del equipo de enfriamiento normalmente resulta en:","opts":["Ciclos cortos, mal control de humedad y menor confort/eficiencia","Tiempos de operacion mas largos","Mejor deshumidificacion","Menor ruido"],"re":"Un aire acondicionado sobredimensionado satisface el termostato rapidamente (ciclos cortos) antes de eliminar suficiente humedad, perjudicando el confort, la eficiencia y la vida del equipo, por eso importa el dimensionamiento Manual J/S."},
  {"id":426,"q":"Antes de abocinar (flaring) tuberia de cobre, el extremo debe desbarbarse/escariarse para que:","opts":["La pared sea mas delgada","El abocinado se forme de manera uniforme y selle sin una via de fuga","El soldado fuerte (brazing) sea mas rapido","El tubo sea mas corto"],"re":"Las rebabas provocan un abocinado desigual y vias de fuga; desbarbe ligeramente (sin remover mucha pared) para que el abocinado asiente uniformemente contra la conexion."},
  {"id":427,"q":"El abocardado por expansion (swaging) de dos piezas de tuberia de cobre le permite al tecnico:","opts":["Agregar refrigerante","Doblar sin una herramienta","Unirlas sin un acople separado (un extremo expandido sobre el otro)","Aumentar el SEER"],"re":"Una herramienta de expansion (swage) ensancha el extremo de un tubo para deslizarlo sobre el tubo correspondiente, formando una union soldada con soldadura fuerte sin comprar un acople."},
  {"id":428,"q":"Para doblar tuberia de cobre blando sin retorcerla, el tecnico debe usar:","opts":["Su pie","Pinzas","Un martillo","Un dobladora de tubos (de resorte o de palanca) respetando el radio minimo"],"re":"Una dobladora de tubos soporta la pared durante el doblez; los pliegues restringen el flujo y debilitan el tubo. Mantengase por encima del radio minimo de doblez."},
  {"id":429,"q":"Las conexiones de refrigerante de tipo prensado (press-type, por ejemplo RLS) son una alternativa al soldado fuerte (brazing) que:","opts":["Usan soldadura blanda","Requieren una llama abierta","Son solo para agua","Forman una union permanente con una herramienta de prensado y un O-ring, sin llama"],"re":"Las conexiones prensadas hacen uniones de refrigerante sin llama con una herramienta de prensado, utiles donde una antorcha es peligrosa; siga el listado y los requisitos de preparacion."},
  {"id":430,"q":"Una nueva conexion de tuberia de gas se verifica en busca de fugas usando:","opts":["Solucion de pompas de jabon o un detector electronico de gas","Refrigerante","Una llama abierta","Agua simple"],"re":"Nunca use una llama para encontrar fugas de gas. Aplique solucion de deteccion de fugas (jabon) o use un detector de gas combustible con la linea presurizada."},
  {"id":431,"q":"Despues de conectar una nueva linea de gas, se debe purgar el aire de la tuberia para:","opts":["Asegurar que el aparato reciba gas puro y encienda de forma confiable","Reducir el voltaje","Aumentar la presion estatica","Agregar refrigerante"],"re":"El aire atrapado causa problemas de ignicion y combustion insegura; purgue la linea (de forma segura, hacia el exterior) hasta que haya gas presente antes de encender el aparato."},
  {"id":432,"q":"La CSST (tuberia de gas de acero inoxidable corrugado) generalmente requiere:","opts":["Sin conexion a tierra","Refrigerante","Pintura","Conexion equipotencial (bonding) al sistema de puesta a tierra (proteccion contra rayos)"],"re":"El codigo requiere que la CSST este conectada equipotencialmente (bonded) para reducir el riesgo de que un arco inducido por un rayo perfore la tuberia delgada; siga las instrucciones de bonding del fabricante."},
  {"id":433,"q":"Un fusible de retardo de tiempo (de doble elemento) se usa a menudo en circuitos de motor porque:","opts":["Se dispara instantaneamente ante cualquier corriente","Tolera la breve corriente de arranque (inrush) del motor pero protege contra sobrecarga sostenida","Aumenta el voltaje","Agrega refrigerante"],"re":"Los motores consumen brevemente una alta corriente de arranque (inrush); un fusible de retardo de tiempo soporta ese pico mientras sigue protegiendo contra una sobrecorriente real y sostenida."},
  {"id":434,"q":"Al terminar un conductor de aluminio, el tecnico debe:","opts":["Aplicar compuesto antioxidante y aplicar el torque al valor especificado","Usarlo como el cobre sin preparacion","Soldarlo con soldadura blanda","Dejarlo suelto"],"re":"El aluminio se oxida y fluye (creep); use terminales listadas, pasta antioxidante donde se requiera y aplique el torque a la especificacion para evitar conexiones sueltas y sobrecalentadas."},
  {"id":435,"q":"Un receptaculo de 125 V instalado en exteriores o en una azotea para servicio debe estar:","opts":["Retirado en invierno","Sin proteccion","Protegido por GFCI y con una cubierta a prueba de intemperie (de uso/in-use)","Solo a 240 V"],"re":"Los receptaculos en exteriores/azoteas y otras ubicaciones humedas requieren proteccion GFCI y una cubierta a prueba de intemperie de uso (in-use) para proteccion contra descargas y resistencia a la intemperie."},
  {"id":436,"q":"Un transformador de control con multiples derivaciones (taps) primarias (por ejemplo, 208/240) se conecta:","opts":["Ignorando el voltaje","Conectando la derivacion (tap) que coincide con el voltaje de suministro real","Cortocircuitando todas las derivaciones","Usando cualquier derivacion"],"re":"Haga coincidir la derivacion primaria con el suministro medido (208 vs 240) para que el secundario entregue los 24 V adecuados; usar la derivacion equivocada da un voltaje de control alto/bajo y fallas."},
  {"id":437,"q":"El cableado de control de bajo voltaje Clase 2 generalmente debe estar:","opts":["Separado de los conductores de voltaje de linea a menos que este clasificado/dividido segun el codigo","Tendido en el mismo conducto que el voltaje de linea","Empalmado al voltaje de linea","Dejado energizado a tierra"],"re":"Mantenga el cableado Clase 2 (24 V) separado de los conductores de voltaje de linea (o use barreras/cable clasificado) para evitar la transferencia de voltaje peligroso e interferencias."},
  {"id":438,"q":"El condensado que drena a un sistema de plomeria normalmente debe descargar a traves de:","opts":["La linea de refrigerante","Una conexion directa rigida","Un desague indirecto con un espacio de aire (air gap)","La linea de gas"],"re":"Los codigos requieren que el condensado drene de forma indirecta con un espacio de aire (air gap) hacia un receptor adecuado, evitando el gas de alcantarilla/sifonaje inverso hacia el equipo."},
  {"id":439,"q":"Una base de techo (roof curb) bajo una unidad empaquetada de azotea (RTU) proporciona:","opts":["Voltaje adicional","Un soporte nivelado y a prueba de intemperie que tambien conecta los ductos de suministro/retorno","Mas SEER","Almacenamiento de refrigerante"],"re":"La base eleva y soporta la RTU, proporciona un sello contra la intemperie y alinea las aberturas de los ductos de suministro/retorno; hacer coincidir la base con la unidad es esencial en los cambios de equipo (changeouts)."},
  {"id":440,"q":"Donde un juego de lineas de refrigerante (line set) atraviesa una pared exterior, la penetracion debe estar:","opts":["Rellena con refrigerante","Ensanchada para el flujo de aire","Sellada (y entubada/protegida) para impedir el paso de aire, agua y plagas y evitar el roce","Dejada abierta"],"re":"Selle y proteja las penetraciones de pared con un manguito/ojal y sellador aprobado para detener la intrusion de aire/agua/plagas y evitar que la tuberia se desgaste contra el borde de la pared."},
  {"id":441,"q":"Al poner en marcha un mini-split sin ductos, el tecnico debe evacuar las lineas y el serpentin interior y luego:","opts":["Abrir las valvulas de servicio para liberar la carga de fabrica hacia el sistema","Dejar las valvulas cerradas","Agregar nitrogeno","Ventilar la carga"],"re":"La unidad exterior se envia precargada con las valvulas cerradas; solo despues de un vacio adecuado el tecnico abre las valvulas de servicio (vastago) para liberar la carga hacia las lineas/serpentin evacuados."},
  {"id":442,"q":"El cabezal interior de un mini-split de montaje en pared debe instalarse de modo que la linea de condensado:","opts":["Este sellada y cerrada","Se conecte a la linea de gas","Mantenga una pendiente descendente continua para drenar por gravedad","Vaya cuesta arriba"],"re":"El drenaje de condensado del cabezal interior debe tener una pendiente descendente continua; un hundimiento o un tramo cuesta arriba causa acumulacion de agua y fugas hacia la habitacion."},
  {"id":443,"q":"En un compresor scroll trifasico, verificar la rotacion de fase correcta en el arranque importa porque:","opts":["Cambia el color","La rotacion invertida hace que un scroll funcione al reves (ruidoso, sin bombear)","Reduce el voltaje","Agrega refrigerante"],"re":"Un scroll funciona en una sola direccion; si se conecta con la fase invertida es ruidoso, no bombea y puede danarse. Intercambie dos lineas (legs) para corregir la rotacion."},
  {"id":444,"q":"El subenfriamiento se calcula restando la temperatura medida de la linea de liquido de la:","opts":["Temperatura de condensacion saturada (a partir de la presion de liquido)","Temperatura de succion","Temperatura del aire exterior","Temperatura del aire de retorno"],"re":"Subenfriamiento = temperatura de condensacion saturada (convertida desde la presion de la linea de liquido mediante la tabla P-T) menos la temperatura real de la linea de liquido; confirma la carga en sistemas con TXV."},
  {"id":445,"q":"Despues de instalar una unidad con calentador de carter (crankcase heater), el calentador debe energizarse antes de arrancar el compresor durante aproximadamente:","opts":["Varias horas (a menudo 24 h) para evaporar el refrigerante del aceite","Un minuto","Nada de tiempo","Una semana"],"re":"Energizar el calentador de carter durante el periodo recomendado (a menudo ~24 h) expulsa el refrigerante liquido del aceite, evitando un arranque inundado y el golpe de liquido (slugging)."},
  {"id":446,"q":"El metodo de aumento de temperatura (temperature-rise) en el arranque del calefactor (furnace) se usa para:","opts":["Medir el refrigerante","Dimensionar el ducto","Establecer el tipo de gas","Verificar que el flujo de aire este dentro del rango de aumento clasificado en la placa de datos"],"re":"Mida las temperaturas del aire de retorno y de suministro; el aumento debe quedar dentro del rango de la placa. Demasiado alto = bajo flujo de aire; demasiado bajo = alto flujo de aire; ajuste la velocidad del soplador."},
  {"id":447,"q":"En un atico no acondicionado, los ductos de suministro deben aislarse al valor R del codigo principalmente para:","opts":["Reducir el ruido","Agregar refrigerante","Aumentar la presion estatica","Limitar la ganancia/perdida de calor por conduccion entre el aire y el atico caliente/frio"],"re":"Los aticos varian entre caliente y frio; aislar los ductos (por ejemplo, R-8 segun el Title 24) limita la energia perdida o ganada a traves de las paredes del ducto, protegiendo la capacidad y la eficiencia."},
  {"id":448,"q":"Las botas (boots) de suministro y los registros deben sellarse a la abertura del panel de yeso/piso para:","opts":["Aumentar el SEER","Evitar la fuga de aire hacia las cavidades de pared/piso (aire acondicionado perdido)","Agregar refrigerante","Reducir el voltaje"],"re":"Las botas sin sellar dejan escapar aire acondicionado hacia las cavidades, desperdiciando energia y reduciendo el flujo de aire de la habitacion; selle la conexion de la bota a la abertura con mastique/empaque."},
  {"id":449,"q":"Un calefactor (furnace) de ventilacion directa (combustion sellada) toma el aire de combustion del exterior a traves de:","opts":["Una tuberia de admision dedicada, expulsando a traves de un ventilador separado/concentrico","La linea de refrigerante","Solo aire de la habitacion","El ducto de retorno"],"re":"Las unidades de combustion sellada conducen el aire exterior directamente al quemador y ventilan los gases de combustion al exterior (a menudo una tuberia concentrica), aislando la combustion del aire interior."},
  {"id":450,"q":"Cuando un calefactor (furnace) de alta eficiencia reemplaza a uno mas antiguo que compartia una chimenea con un calentador de agua, el tecnico debe verificar la ventilacion del calentador de agua porque:","opts":["El calentador de agua 'huerfano' puede quedar sobredimensionado para la chimenea y tener contratiro (backdraft)","Necesita refrigerante","El tipo de gas cambio","Ahora tiene mas tiro"],"re":"Retirar el calefactor de una ventilacion compartida (comun) puede dejar al calentador de agua 'huerfano' en una chimenea sobredimensionada, con riesgo de mal tiro/contratiro; reevalue la ventilacion segun el codigo."},
  {"id":451,"q":"En una instalacion nueva, la trampa de condensado debe cebarse (llenarse con agua) para que:","opts":["El compresor arranque","La trampa selle de inmediato y no se aspire aire a traves del desague vacio","Suba el SEER","Encienda el gas"],"re":"Una trampa seca permite que el soplador aspire aire a traves del desague (o bloquee el drenaje); cebar la trampa establece el sello de agua para que el condensado fluya correctamente en el arranque."},
  {"id":452,"q":"En California, los equipos de HVAC y los calentadores de agua a menudo requieren amarre/anclaje sismico para:","opts":["Mejorar el flujo de aire","Elevar el voltaje","Evitar que la unidad se desplace o se vuelque durante un terremoto","Agregar refrigerante"],"re":"El anclaje sismico (amarrar los calentadores de agua, asegurar las unidades de azotea/atico) mantiene el equipo en su lugar durante un sismo, evitando danos a las lineas de gas/refrigerante y peligros."},
  {"id":453,"q":"En la instalacion, los bornes (lugs) y terminales electricos deben apretarse a:","opts":["Lo mas apretado posible","Ningun valor en particular","Solo apretado a mano","El valor de torque especificado por el fabricante"],"re":"Tanto el torque insuficiente como el excesivo causan problemas; use un destornillador/llave de torque al valor especificado para obtener conexiones de baja resistencia y confiables que no se aflojen ni se sobrecalienten."},
  {"id":454,"q":"Los interruptores (breakers) y desconectadores que sirven a los equipos de HVAC deben estar:","opts":["Puenteados","Claramente etiquetados para identificar el equipo al que sirven","Dejados sin etiqueta","Cubiertos con pintura"],"re":"Un etiquetado adecuado permite a los tecnicos y ocupantes identificar y desenergizar rapidamente el circuito correcto para servicio y emergencias, mejorando la seguridad."},
  {"id":455,"q":"Un compresor scroll trifasico que esta ruidoso y produce poco o ningun enfriamiento justo despues de un servicio puede estar:","opts":["Bajo de aceite","Conectado para rotacion inversa (dos fases intercambiadas)","Sobrecargado","Sin filtros"],"re":"La rotacion de fase invertida hace que un scroll gire al reves: ruidoso, sin bombeo y sin enfriamiento. Intercambiar dos fases de linea cualesquiera restablece la rotacion correcta."},
  {"id":456,"q":"Un visor (sight glass) indicador de humedad que se ha vuelto amarillo (en lugar de verde) indica:","opts":["Humedad en el sistema (reemplace el secador y evacue)","Carga correcta","Alto voltaje","Sobrecarga"],"re":"El indicador cambia de color con el contenido de humedad (verde = seco, amarillo = humedo). Una lectura humeda exige un nuevo filtro secador y una evacuacion adecuada."},
  {"id":457,"q":"Una temperatura de descarga del compresor anormalmente alta es causada comunmente por:","opts":["Solo bajo voltaje","Una alta relacion de compresion (baja succion/alta descarga), carga baja o alto sobrecalentamiento","Solo sobrecarga","Un filtro limpio"],"re":"La alta temperatura de descarga resulta de una alta relacion de compresion y un alto sobrecalentamiento del gas de retorno (a menudo por baja carga o restriccion); el calor excesivo descompone el aceite y dana las valvulas."},
  {"id":458,"q":"Una prueba de acidez del aceite que da positiva despues de una falla del compresor significa que el tecnico debe:","opts":["Solo recargar","Realizar una limpieza por quemadura (burnout) con secadores de acido hasta que el sistema de una prueba limpia","Ignorarlo","Agregar mas aceite"],"re":"El aceite acido indica contaminacion por una quemadura (burnout); instale secadores de eliminacion de acido en succion/liquido, opere, vuelva a probar y reemplace los secadores hasta que la prueba de acidez este limpia."},
  {"id":459,"q":"Un interruptor de presion (pressure switch) de un calefactor (furnace) de gas que no cierra despues de que arranca el inductor a menudo es causado por:","opts":["Demasiado flujo de aire","Alto refrigerante","Una ventilacion bloqueada o una manguera del interruptor de presion tapada con condensado","Un filtro limpio"],"re":"El interruptor comprueba el tiro del inductor; un conducto (flue) bloqueado, una manguera agrietada/tapada o condensado en el puerto lo mantiene abierto, deteniendo la ignicion por seguridad."},
  {"id":460,"q":"Una valvula reversora (reversing valve) con una fuga interna (bypass) causara:","opts":["Mala calefaccion/enfriamiento con las presiones de succion y descarga mas cercanas de lo normal","Bajo voltaje","Operacion perfecta","Un fusible quemado"],"re":"Una valvula reversora con fuga interna deja pasar gas de descarga caliente al lado de succion, igualando las presiones y reduciendo la capacidad aunque el solenoide funcione."},
  {"id":461,"q":"Un acumulador de linea de succion (suction-line accumulator) protege el compresor al:","opts":["Filtrar el aire","Atrapar el refrigerante liquido y dosificarlo de vuelta como vapor (evitando el golpe de liquido)","Agregar refrigerante","Elevar la presion de descarga (head pressure)"],"re":"El acumulador (comun en bombas de calor) retiene el liquido que retorna durante la calefaccion/descongelacion y lo realimenta lentamente para que el compresor no reciba golpe de liquido (slugging)."},
  {"id":462,"q":"Un filtro secador de doble flujo (bi-flow) o una valvula de retencion (check valve) instalada al reves en una bomba de calor:","opts":["Restringira el flujo en un modo, causando mal desempeno en calefaccion o enfriamiento","Agregara refrigerante","Mejorara la eficiencia","Reducira la temperatura de descarga"],"re":"Las bombas de calor invierten el flujo; un secador/valvula de retencion direccional instalado mal restringe un modo. Use un secador de doble flujo (bi-flow) o corrija la direccion de la flecha."},
  {"id":463,"q":"Una linea del ecualizador externo de un TXV tapada normalmente causara que la valvula:","opts":["Solo aumente el subenfriamiento","Agregue refrigerante","Controle deficientemente, generalmente restringiendo el evaporador (alto sobrecalentamiento)","Sobrealimente gravemente"],"re":"El ecualizador externo detecta la presion de salida del evaporador; si se tapa, el TXV lee mal y comunmente subalimenta, produciendo alto sobrecalentamiento y baja capacidad."},
  {"id":464,"q":"Una causa frecuentemente pasada por alto de bajo flujo de aire en una visita de mantenimiento es:","opts":["Una rueda del soplador sucia llena de residuos","Un serpentin limpio","Alto voltaje","Sobrecarga"],"re":"La suciedad carga las aspas de la rueda del soplador, reduciendo drasticamente el flujo de aire incluso con un filtro limpio; inspeccione y limpie la rueda como parte del diagnostico de flujo de aire."},
  {"id":465,"q":"En enfriamiento, un evaporador sucio (lado del aire) y un condensador sucio producen sintomas diferentes: un evaporador sucio reduce mas directamente:","opts":["El flujo de aire y la capacidad del evaporador (baja succion, posible formacion de hielo)","La presion de descarga (head pressure)","El voltaje","Solo el subenfriamiento"],"re":"Un evaporador sucio restringe el flujo de aire, bajando la presion de succion y arriesgando hielo; un condensador sucio eleva la presion de descarga. Leer ambas presiones localiza la falla."},
  {"id":466,"q":"En un sistema con bombeo de vaciado (pump-down), una valvula solenoide de linea de liquido que no logra cerrar causara:","opts":["Alto SEER","Bombeo de vaciado normal","Que el sistema no logre el bombeo de vaciado (el refrigerante sigue fluyendo al lado de baja)","Un fusible quemado"],"re":"El bombeo de vaciado depende de que el solenoide cierre para que el compresor evacue el lado de baja hacia el condensador/recibidor; una valvula atascada abierta anula el pump-down."},
  {"id":467,"q":"Un sensor de terminacion de descongelacion (defrost-termination) que falla puede causar que una bomba de calor:","opts":["Aumente el subenfriamiento","Detenga el compresor permanentemente","Nunca descongele o permanezca demasiado tiempo en descongelacion","Funcione con mayor eficiencia"],"re":"El sensor de terminacion finaliza la descongelacion a la temperatura correcta del serpentin; si falla, la unidad puede no eliminar el hielo o puede desperdiciar energia descongelando en exceso; revise el sensor/tarjeta."},
  {"id":468,"q":"Un kit de arranque forzado (hard-start) que usa un relevador de potencial (start relay) retira el capacitor de arranque del circuito segun:","opts":["La presion del refrigerante","Solo el tiempo","El voltaje de fuerza contraelectromotriz (back-EMF) a medida que el motor se acerca a la velocidad de operacion","La temperatura exterior"],"re":"Un relevador de potencial detecta la creciente back-EMF (voltaje del devanado de arranque) y abre para retirar el capacitor de arranque una vez que el motor alcanza su velocidad; un relevador defectuoso deja el capacitor dentro o fuera de forma incorrecta."},
  {"id":469,"q":"Un bulbo sensor de un TXV que esta suelto o mal aislado de la linea de succion tiende a hacer que la valvula:","opts":["Cierre por completo","Sobrealimente el evaporador (detecta aire caliente en lugar de la verdadera temperatura de la linea)","No tenga efecto","Restrinja el evaporador"],"re":"Un bulbo que lee el aire ambiente en lugar de la linea de succion mas fria detecta una falsa temperatura alta y sobrealimenta, bajando el sobrecalentamiento y arriesgando retorno de liquido (floodback); monte y aisle el bulbo correctamente."},
  {"id":470,"q":"Un capacitor debil del ventilador del condensador causara que el ventilador:","opts":["Solo reduzca el SEER","Funcione lento o se detenga y se sobrecaliente, elevando la presion de descarga (head pressure)","Agregue refrigerante","Gire mas rapido"],"re":"El motor del ventilador necesita su capacitor clasificado para el par (torque); un capacitor debil lo hace funcionar lento/caliente o no arrancar, reduciendo el flujo de aire del condensador y elevando la presion de descarga."},
  {"id":471,"q":"Un sonido de silbido o 'gorgoteo' en el TXV a menudo indica:","opts":["Carga correcta","Gas instantaneo (flash gas) en la valvula por baja carga o una restriccion en la linea de liquido","Sobrecarga","Alto voltaje"],"re":"El vapor (flash gas) que entra al TXV en lugar de liquido solido produce un ruido de silbido/gorgoteo y reduce la capacidad; revise si hay baja carga o una restriccion aguas arriba."},
  {"id":472,"q":"Un alto consumo de amperaje del compresor junto con alta presion de descarga (head pressure) lo mas probable es que apunte a:","opts":["Baja carga","Bajo voltaje","Un filtro sucio","Sobrecarga o un problema del condensador (serpentin sucio/ventilador averiado)"],"re":"La alta descarga hace que el compresor trabaje mas duro (alto amperaje); las causas incluyen sobrecarga, condensador sucio, ventilador del condensador averiado o no condensables; verifique antes de corregir."},
  {"id":473,"q":"Reducir el flujo de aire interior en enfriamiento (por ejemplo, un ducto cerrado) tendera a:","opts":["Elevar el voltaje","Bajar la presion de succion y la temperatura del evaporador, arriesgando la congelacion del serpentin","No tener efecto","Elevar la presion de succion"],"re":"Menos flujo de aire sobre el serpentin baja la presion/temperatura del evaporador; si no se corrige, congela el serpentin. Restablezca el flujo de aire antes de suponer una falla de refrigerante."},
  {"id":474,"q":"En termostatos antiguos, un ajuste del anticipador de calor (heat anticipator) demasiado bajo causa:","opts":["Ciclos del quemador mas largos y posible sobrepaso de la temperatura ajustada","Perdida de refrigerante","Mayor SEER","Sin ciclos"],"re":"El anticipador ajusta la duracion del ciclo; demasiado bajo alarga los ciclos y sobrepasa, demasiado alto provoca ciclos cortos. Los termostatos modernos usan ajustes electronicos de tasa de ciclo en su lugar."},
  {"id":475,"q":"Un compresor que funciona, luego se dispara y solo reinicia despues de enfriarse un rato, probablemente tiene:","opts":["Un ducto defectuoso","Un filtro limpio","Una proteccion de sobrecarga interna que abre por calor (a menudo por alto amperaje/temperatura)","Un termostato equivocado"],"re":"La proteccion de sobrecarga interna protege el motor abriendo cuando esta demasiado caliente y restableciendose al enfriarse; los disparos recurrentes senalan alta corriente/calor; investigue carga, flujo de aire, voltaje, capacitor."},
  {"id":476,"q":"Un capacitor de operacion (run capacitor) que esta visiblemente abultado o con fugas debe:","opts":["Reutilizarse","Limarse plano","Reemplazarse por uno con los mismos uF y una clasificacion de voltaje igual o superior","Rellenarse con aceite"],"re":"Un capacitor abultado/con fugas ha fallado; reemplacelo con la clasificacion exacta de microfaradios y la misma clasificacion de voltaje o superior, nunca una clasificacion de voltaje inferior."},
  {"id":477,"q":"Los contactos picados y de alta resistencia de un contactor pueden causar que un compresor reciba:","opts":["Bajo voltaje (caida de voltaje) y calor, lo que provoca arranques forzados o falla","Mas refrigerante","Mayor SEER","Aire mas limpio"],"re":"Los contactos desgastados agregan resistencia y caida de voltaje, privando al compresor de voltaje y generando calor; reemplace el contactor en lugar de limar los contactos."},
  {"id":478,"q":"La secuencia de diagnostico mas logica ante una falta de enfriamiento es verificar:","opts":["Solo el filtro","Solo el termostato","El refrigerante primero, siempre","La alimentacion/desconectador, luego los 24 V de control al contactor, despues el compresor y finalmente el circuito de refrigerante"],"re":"Recorra el circuito en orden: confirme la alimentacion de linea y el desconectador, luego la senal de control de 24 V, despues la operacion del contactor/compresor, y solo entonces evalue las presiones del refrigerante."},
  {"id":479,"q":"Al trabajar en un sistema cargado con un refrigerante A2L (ligeramente inflamable), el tecnico debe:","opts":["Usar cualquier llama abierta cerca","Eliminar las fuentes de ignicion, ventilar y usar herramientas/practicas clasificadas para refrigerante inflamable","Ventilarlo en interiores","Fumar mientras trabaja"],"re":"Los refrigerantes A2L pueden encenderse a alta concentracion; elimine las fuentes de ignicion, ventile el area, use un detector de fugas listado y siga los procedimientos de servicio A2L del equipo."},
  {"id":480,"q":"Para los refrigerantes A2L, la carga maxima permitida en un espacio se limita en funcion de:","opts":["El SEER","El color del ducto","El calibre del cable","El area del piso de la habitacion (para mantener cualquier fuga por debajo de la concentracion inflamable)"],"re":"Las normas (por ejemplo, UL 60335-2-40) limitan la carga segun el area de la habitacion para que una fuga total no pueda alcanzar una concentracion inflamable; cargas mayores requieren habitaciones mas grandes o mitigacion."},
  {"id":481,"q":"Detectar una fuga en un sistema de refrigerante inflamable (A2L) requiere:","opts":["Un detector de fugas listado/clasificado para refrigerantes inflamables","Solo su nariz","Rociar agua","Un cerillo encendido"],"re":"Use unicamente un detector de fugas aprobado para refrigerantes inflamables; una fuente de ignicion como una antorcha de haluro o una llama es peligrosa con los sistemas A2L."},
  {"id":482,"q":"Antes de conectarse a un cilindro de refrigerante, el tecnico debe confirmar el tipo de refrigerante mediante:","opts":["Su temperatura","La etiqueta y el codigo de color, para evitar mezclar refrigerantes incompatibles","El peso del cilindro","Agitandolo"],"re":"Los cilindros estan etiquetados y codificados por color; mezclar refrigerantes arruina la carga y el refrigerante recuperado. Verifique siempre la etiqueta antes de conectarse."},
  {"id":483,"q":"El acetileno usado para soldadura fuerte (brazing) nunca debe usarse por encima de una presion de trabajo de aproximadamente:","opts":["5 psig","250 psig","100 psig","15 psig"],"re":"El acetileno es inestable por encima de ~15 psig y puede descomponerse de forma explosiva; nunca ajuste el regulador mas alto. Use practicas de seguridad adecuadas de oxiacetileno."},
  {"id":484,"q":"Los arrestallamas (flashback arrestors) en un equipo de antorcha de oxicombustible se instalan para:","opts":["Evitar que una llama viaje de regreso hacia las mangueras/cilindros","Ahorrar gas","Aumentar el tamano de la llama","Agregar refrigerante"],"re":"Los arrestallamas/valvulas de retencion detienen una llama o el flujo inverso de gas para que no lleguen a las mangueras y cilindros, evitando una explosion peligrosa."},
  {"id":485,"q":"Los cilindros de acetileno deben almacenarse y usarse:","opts":["De costado","Horizontalmente bajo el sol","En posicion vertical (la acetona del interior lo requiere) y asegurados","Boca abajo"],"re":"El acetileno esta disuelto en acetona dentro del cilindro; almacenarlo/usarlo en posicion vertical evita que la acetona sea arrastrada hacia la manguera. Asegure los cilindros para que no se vuelquen."},
  {"id":486,"q":"Una antorcha de soldadura fuerte/oxicombustible debe encenderse usando:","opts":["Una vela encendida","Un encendedor de cigarrillos","Un chispero (encendedor de chispa), no cerillos ni un encendedor","Otra antorcha"],"re":"Use un chispero de friccion para mantener las manos alejadas de la llama que se enciende; los cerillos/encendedores ponen los dedos en la punta de la antorcha y arriesgan quemaduras."},
  {"id":487,"q":"Despues de completar trabajo en caliente (hot work) cerca de combustibles, una vigilancia contra incendios debe continuar durante al menos aproximadamente:","opts":["Nada de tiempo","5 segundos","30 minutos (para detectar una ignicion latente)","1 semana"],"re":"La combustion latente puede encenderse minutos despues de la soldadura fuerte/corte; mantenga una vigilancia contra incendios durante al menos 30 minutos (mas si las condiciones lo justifican) y tenga un extintor listo."},
  {"id":488,"q":"Al cargar escaleras o trabajar con equipos cerca de lineas electricas aereas (menos de 50 kV), mantenga una distancia minima de al menos:","opts":["2 pulgadas","1 pie","10 pies","No se necesita distancia"],"re":"OSHA requiere mantenerse al menos a 10 ft de las lineas aereas energizadas de hasta 50 kV (mas para voltajes mas altos); el contacto puede ser mortal; mire hacia arriba y planifique la ruta."},
  {"id":489,"q":"En una azotea u otra ubicacion humeda/exterior, las herramientas electricas deben conectarse a:","opts":["Un cable de extension sin tierra","Un circuito protegido por GFCI","Las terminales del desconectador","Cualquier tomacorriente"],"re":"La proteccion GFCI en ubicaciones humedas/exteriores corta la energia ante una falla a tierra en milisegundos, protegiendo al trabajador de la electrocucion."},
  {"id":490,"q":"El 'ABC' de un sistema personal de detencion de caidas (fall-arrest) significa Anclaje (Anchorage), Arnes de cuerpo (Body harness) y:","opts":["Bateria (Battery)","Conector (Connector) (cordon/cuerda de vida)","Compresor (Compressor)","Conducto (Conduit)"],"re":"Un sistema personal de detencion de caidas necesita un punto de Anclaje, un arnes de cuerpo completo (Body) y un Conector (cordon/SRL/cuerda de vida), los tres clasificados y usados correctamente."},
  {"id":491,"q":"Los agujeros abiertos en pisos o techos y los tragaluces en una obra deben estar:","opts":["Dejados abiertos","Protegidos con una cubierta o baranda para prevenir caidas","Marcados solo con pintura","Rellenos con refrigerante"],"re":"Los tragaluces y las aberturas de piso/techo son peligros de caida; protejalos con una cubierta asegurada y clasificada para carga o con barandas, y etiquete las cubiertas."},
  {"id":492,"q":"Alterar superficies pintadas en una vivienda construida antes de 1978 puede liberar plomo, por lo que el tecnico debe:","opts":["Quemar la pintura para retirarla","Ignorarlo","Lijarla en seco libremente","Seguir practicas de trabajo seguras con plomo (RRP) y contener el polvo"],"re":"La pintura anterior a 1978 puede contener plomo; use practicas de renovacion seguras con plomo (contencion, metodos humedos, limpieza) y la certificacion adecuada al alterarla."},
  {"id":493,"q":"Si una alarma de CO suena y los ocupantes tienen sintomas, la accion inmediata correcta es:","opts":["Silenciar la alarma","Abrir una ventana y seguir trabajando","Evacuar a los ocupantes al aire fresco, luego ventilar y encontrar la fuente","Hacer funcionar el calefactor (furnace) con mas fuerza"],"re":"El monoxido de carbono es mortal; lleve primero a todos al aire fresco, pida ayuda si hay sintomas, luego apague el aparato sospechoso y diagnostique la fuente."},
  {"id":494,"q":"Un multimetro digital usado para mediciones en la alimentacion del edificio debe tener una clasificacion CAT que:","opts":["Siempre sea CAT I","Sea la mas barata","No importa","Coincida o supere la categoria del circuito (por ejemplo, CAT III para distribucion)"],"re":"La clasificacion CAT (categoria de medicion) asegura que el medidor pueda manejar de forma segura las sobretensiones transitorias en ese circuito; usar un medidor subclasificado arriesga lesiones por arco electrico (arc-flash)."},
  {"id":495,"q":"Las baterias de iones de litio para herramientas electricas deben:","opts":["Cargarse sobre superficies inflamables","Perforarse para probarlas","Arrojarse al agua","Mantenerse alejadas de danos/calor y cargarse con el cargador correcto; los paquetes danados deben retirarse de servicio"],"re":"Los paquetes de iones de litio danados, sobrecalentados o cargados incorrectamente pueden liberar gases o incendiarse; use el cargador correcto, evite el calor/impacto y deseche los paquetes danados de forma segura."},
  {"id":496,"q":"En una etiqueta quimica GHS, el pictograma de la 'llama' indica que el producto es:","opts":["Pesado","Inflamable","Frio","Toxico"],"re":"Los pictogramas GHS transmiten los peligros de un vistazo: la llama significa inflamable, la calavera con huesos cruzados significa toxicidad aguda, la bomba explotando significa explosivo, etc."},
  {"id":497,"q":"Los primeros auxilios para una quemadura menor por metal caliente o una antorcha consisten en:","opts":["Frotarla con fundente (flux)","Enfriar la quemadura con agua corriente y cubrirla; no reventar las ampollas","Aplicar hielo directamente y reventar las ampollas","Ignorarla"],"re":"Enfrie una quemadura termica con agua corriente fria (no helada), cubrala sin apretar y evite reventar las ampollas; busque atencion medica para quemaduras graves."},
  {"id":498,"q":"El uso seguro de escaleras requiere mantener tres puntos de contacto y:","opts":["Mirar hacia la escalera al subir, sin estirarse en exceso","Subir con ambas manos ocupadas","Mirar en direccion contraria a la escalera","Pararse en el peldano superior"],"re":"Mantenga tres puntos de contacto, mire hacia la escalera, mantenga la hebilla del cinturon entre los rieles (sin estirarse en exceso) y nunca se pare en la tapa/peldano superior."},
  {"id":499,"q":"Las escaleras y los materiales transportados en un portaequipajes de vehiculo deben estar:","opts":["Apilados por encima de la altura legal","Debidamente asegurados/amarrados para que no puedan moverse ni caer durante el transporte","Dejados sin amarrar para acceso rapido","Colocados de forma suelta"],"re":"Las cargas sin asegurar pueden caerse y causar choques o lesiones; amarre las escaleras y los materiales y revise las correas antes de conducir."},
  {"id":500,"q":"Si un trabajo no puede completarse de forma segura con las herramientas, el PPE o las condiciones disponibles, la accion correcta es:","opts":["Retirar las protecciones de seguridad","Apresurarse a terminar de todos modos","Omitir el PPE","Detener el trabajo, atender el peligro y conseguir el equipo/ayuda adecuados antes de continuar"],"re":"La produccion nunca justifica un atajo inseguro; todo trabajador puede y debe detener el trabajo para corregir un peligro, obtener el PPE/equipo adecuado y seguir la SDS y los codigos."}
];
